/// Result of a completed `run` invocation. All artifacts are written before
/// this value is returned; `main` turns it into the process exit decision so a
/// failing gate can never truncate artifacts.
struct RunCompletion {
    gate_conclusion: String,
    fail_on_gate: bool,
    run_dir: PathBuf,
}

fn cmd_run(args: RunArgs) -> Result<RunCompletion> {
    let run_started = Instant::now();
    let mut args = normalize_run_args(args)?;
    let run_pass = resolved_run_pass(args.run_pass);
    let (config, diff, box_state, plan) =
        prepare_plan(&args.review, args.allow_heavy, &args.selectors)?;
    // D2 precedence (spec 0006): an explicit --provider-policy / env value
    // wins; `auto` defers to the repo's [providers].policy; with neither,
    // `auto` keeps its built-in minimax-primary semantics.
    args.provider_policy = resolved_provider_policy(&config, args.provider_policy);
    let profile = config.selected_profile()?;
    apply_runtime_profile_limits(&mut args, profile)?;
    let selected_model_lanes = selected_review_lanes_for_args(&plan, &args)?;
    print_plan(&plan, &box_state);
    write_plan_artifacts(
        &args.review.out,
        &config,
        &diff,
        &box_state,
        &plan,
        PlanArtifactSelectors {
            run_args: Some(&args),
            selectors: &args.selectors,
            effective_model_lanes: Some(&selected_model_lanes),
        },
    )?;

    let event_log = EventLog::open(&args.review.out.join("events.ndjson"))?;
    let mut run_loop_tracker = RunLoopTracker::new();
    event_log.append(
        "run_started",
        serde_json::json!({"base": args.review.base, "head": args.review.head, "profile": plan.profile_name, "dry_run": args.dry_run, "run_pass": run_pass.key()}),
    )?;

    let evidence_loop = start_run_loop(
        &event_log,
        &run_started,
        "evidence",
        "coordination",
        "sensors-and-packet",
    )?;
    if args.dry_run {
        write_dry_run_sensor_receipts(&args.review.root, &args.review.out, &plan, &event_log)?;
        event_log.append("run_dry", serde_json::json!({"reason": "--dry-run"}))?;
    } else {
        write_skipped_sensor_receipts(&args.review.root, &args.review.out, &plan, &event_log)?;
        run_sensors(
            &args.review.root,
            &args.review.out,
            &plan,
            profile,
            &event_log,
        )?;
    }
    let tool_gate_outcomes =
        write_tool_status_artifacts(&args.review.out, &config, profile, &plan)?;

    write_lane_packets(&args.review.out, &diff, &selected_model_lanes, &event_log)?;
    finish_run_loop(
        &event_log,
        &run_started,
        &mut run_loop_tracker,
        evidence_loop,
        "completed",
    )?;
    let preliminary_summary = render_summary(&args.review.out, &plan, &diff)?;
    fs::write(
        args.review.out.join("running-summary.md"),
        &preliminary_summary,
    )?;
    let gate_outcome = write_review_artifacts(
        &args.review.root,
        &args.review.out,
        &config,
        &diff,
        &box_state,
        &plan,
        &tool_gate_outcomes.outcomes,
        &preliminary_summary,
        &args,
        &event_log,
        &run_started,
        &mut run_loop_tracker,
        run_started.elapsed(),
    )?;
    let summary = render_summary(&args.review.out, &plan, &diff)?;
    fs::write(args.review.out.join("running-summary.md"), &summary)?;
    if config.review.github_summary && !args.no_github_summary {
        append_github_step_summary(&summary)?;
    }
    event_log.append(
        "run_finished",
        serde_json::json!({"run_dir": args.review.out}),
    )?;
    println!("wrote {}", args.review.out.display());
    println!("open {}/running-summary.md", args.review.out.display());
    Ok(RunCompletion {
        gate_conclusion: gate_outcome.conclusion,
        fail_on_gate: args.fail_on_gate.resolved(args.mode),
        run_dir: args.review.out,
    })
}

fn normalize_run_args(mut args: RunArgs) -> Result<RunArgs> {
    apply_depth_defaults(&mut args)?;
    validate_run_args(&args)?;
    Ok(args)
}

fn apply_depth_defaults(args: &mut RunArgs) -> Result<()> {
    if args.depth == ReviewDepth::Standard {
        return Ok(());
    }
    if args.lane_width != STANDARD_LANE_WIDTH
        || args.model_concurrency != STANDARD_MODEL_CONCURRENCY
        || args.max_model_calls != STANDARD_MAX_MODEL_CALLS
    {
        bail!(
            "--depth {} cannot be combined with --lane-width, --model-concurrency, or --max-model-calls overrides; use --depth standard for custom raw budgets",
            args.depth.key()
        );
    }
    args.lane_width = args.depth.lane_width();
    args.model_concurrency = args.depth.model_concurrency();
    args.max_model_calls = args.depth.max_model_calls();
    Ok(())
}

fn ensure_supported_mode(mode: RunMode) -> Result<()> {
    match mode {
        RunMode::ReviewByok | RunMode::IntelligentCi => Ok(()),
        RunMode::AgentInvestigate | RunMode::AgentPatch => bail!(
            "{} is reserved for optional leased workers and is not implemented in v0",
            mode.key()
        ),
    }
}

fn resolved_run_pass(run_pass: RunPass) -> RunPass {
    if run_pass != RunPass::Auto {
        return run_pass;
    }
    resolve_run_pass_from_event(
        std::env::var("GITHUB_EVENT_NAME").ok().as_deref(),
        github_event_action().as_deref(),
    )
}

fn resolve_run_pass_from_event(event_name: Option<&str>, event_action: Option<&str>) -> RunPass {
    match event_name {
        Some("pull_request" | "pull_request_target") => match event_action {
            Some("opened") => RunPass::Opened,
            Some("reopened") => RunPass::Reopened,
            Some("ready_for_review") => RunPass::ReadyForReview,
            Some("synchronize") => RunPass::Synchronize,
            _ => RunPass::PullRequestOther,
        },
        _ => RunPass::Manual,
    }
}

fn github_event_action() -> Option<String> {
    for name in ["UB_REVIEW_GITHUB_EVENT_ACTION", "GITHUB_EVENT_ACTION"] {
        if let Ok(value) = std::env::var(name) {
            let value = value.trim();
            if !value.is_empty() {
                return Some(value.to_owned());
            }
        }
    }
    github_event_action_from_path()
}

fn github_event_action_from_path() -> Option<String> {
    let path = std::env::var_os("GITHUB_EVENT_PATH")?;
    let text = fs::read_to_string(path).ok()?;
    let value: serde_json::Value = serde_json::from_str(&text).ok()?;
    value
        .get("action")
        .and_then(serde_json::Value::as_str)
        .map(str::to_owned)
}

fn validate_run_args(args: &RunArgs) -> Result<()> {
    ensure_supported_mode(args.mode)?;
    validate_selector_syntax(&args.selectors)?;
    if !matches!(args.lane_width, 6 | 10 | 20) {
        bail!("--lane-width must be one of 6, 10, or 20");
    }
    if args.model_timeout_sec == 0 {
        bail!("--model-timeout-sec must be greater than zero");
    }
    if args.model_concurrency == 0 {
        bail!("--model-concurrency must be greater than zero");
    }
    if args.review_body_max_bytes < 1_000 {
        bail!("--review-body-max-bytes must be at least 1000");
    }
    Ok(())
}

fn apply_runtime_profile_limits(args: &mut RunArgs, profile: &Profile) -> Result<()> {
    let llm_in_flight = profile.limits.llm_in_flight;
    if llm_in_flight == 0 {
        bail!(
            "runtime profile {} has llm_in_flight=0; model concurrency cannot be scheduled",
            profile.name
        );
    }
    args.model_concurrency = args.model_concurrency.min(llm_in_flight);
    Ok(())
}

fn cmd_summary(args: SummaryArgs) -> Result<()> {
    let plan: Plan = serde_json::from_slice(&fs::read(args.run_dir.join("plan.json"))?)?;
    let diff: DiffContext =
        serde_json::from_slice(&fs::read(args.run_dir.join("input/diff-context.json"))?)?;
    let summary = render_summary(&args.run_dir, &plan, &diff)?;
    fs::write(args.run_dir.join("running-summary.md"), summary)?;
    println!("wrote {}/running-summary.md", args.run_dir.display());
    Ok(())
}

fn cmd_post(args: PostArgs) -> Result<()> {
    fs::create_dir_all(&args.out)?;
    if !args.review_json.exists()
        && let Some(skip) = read_github_review_skip_receipt(&args.review_json)
    {
        fs::write(
            args.out.join("post-result.json"),
            serde_json::to_vec_pretty(&skip)?,
        )?;
        println!(
            "skipped GitHub review post; wrote {}/post-result.json",
            args.out.display()
        );
        run_issue_broker_step(&args);
        return Ok(());
    }
    let post_outcome = match post_github_review(&args) {
        Ok(value) => {
            fs::write(
                args.out.join("post-result.json"),
                serde_json::to_vec_pretty(&value)?,
            )?;
            println!("wrote {}/post-result.json", args.out.display());
            Ok(())
        }
        Err(err) => {
            let value = build_post_error_receipt(&args, &err);
            fs::write(
                args.out.join("post-error.json"),
                serde_json::to_vec_pretty(&value)?,
            )?;
            if args.fail_on_post_error {
                Err(err)
            } else {
                eprintln!(
                    "ub-review post failed; wrote {}/post-error.json",
                    args.out.display()
                );
                Ok(())
            }
        }
    };
    // The issue broker runs after the review submission attempt on every
    // path: it has its own receipts (issue_broker_results.json), the
    // fingerprint duplicate search makes it idempotent across passes, and
    // its failures never change the post exit code.
    run_issue_broker_step(&args);
    post_outcome
}

/// Execute the run-written broker plan, never fatally: read
/// review/issue_broker_plan.json next to the review payload, perform the
/// remote duplicate search and opens for `attempt` entries, and write
/// issue_broker_results artifacts. Absent plan means the broker was not
/// opted in; any whole-step error is reported to stderr and swallowed
/// (broker outcomes never affect the gate or the post exit code).
fn run_issue_broker_step(args: &PostArgs) {
    let plan_path = args
        .review_json
        .parent()
        .unwrap_or_else(|| Path::new("."))
        .join("issue_broker_plan.json");
    if !plan_path.exists() {
        return;
    }
    match execute_issue_broker(args, &plan_path) {
        Ok(results) => {
            if let Err(err) = write_issue_broker_results(&args.out, &results) {
                eprintln!("ub-review issue broker: failed to write results: {err:#}");
            } else {
                let opened = results.iter().filter(|r| r.action == "opened").count();
                let duplicates = results.iter().filter(|r| r.action == "duplicate").count();
                let failed = results
                    .iter()
                    .filter(|r| r.action == "failed_to_open")
                    .count();
                println!(
                    "issue broker: {opened} opened, {duplicates} duplicate, {failed} failed, \
                     {} skipped; wrote {}/issue_broker_results.json",
                    results.iter().filter(|r| r.action == "skipped").count(),
                    args.out.display()
                );
            }
        }
        Err(err) => {
            eprintln!("ub-review issue broker failed (tolerated): {err:#}");
        }
    }
}

/// Execute every plan entry. Skips mirror through as `skipped`; attempts run
/// the fingerprint duplicate search first and only open when the search
/// comes back empty. Per-entry failures become `failed_to_open` results, so
/// one bad target repo cannot abort the rest of the plan.
fn execute_issue_broker(args: &PostArgs, plan_path: &Path) -> Result<Vec<IssueBrokerResult>> {
    let plan: Vec<IssueBrokerPlanEntry> = serde_json::from_slice(
        &fs::read(plan_path).with_context(|| format!("read {}", plan_path.display()))?,
    )
    .with_context(|| format!("parse {}", plan_path.display()))?;
    let token = args
        .github_token
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let api_url = args.github_api_url.trim_end_matches('/');
    let mut results = Vec::new();
    for (index, entry) in plan.iter().enumerate() {
        let result = if entry.decision != "attempt" {
            IssueBrokerResult {
                schema: ISSUE_BROKER_RESULT_SCHEMA.to_owned(),
                candidate_id: entry.candidate_id.clone(),
                target_repo: entry.target_repo.clone(),
                action: "skipped".to_owned(),
                reason: entry.reason.clone(),
                url: None,
                error: None,
            }
        } else if let Some(token) = token {
            execute_issue_broker_attempt(args, api_url, token, entry, index)
        } else {
            IssueBrokerResult {
                schema: ISSUE_BROKER_RESULT_SCHEMA.to_owned(),
                candidate_id: entry.candidate_id.clone(),
                target_repo: entry.target_repo.clone(),
                action: "failed_to_open".to_owned(),
                reason: "broker attempt planned but no GitHub token was available at post time"
                    .to_owned(),
                url: None,
                error: Some("github token unavailable".to_owned()),
            }
        };
        results.push(result);
    }
    Ok(results)
}

/// One open attempt: fingerprint duplicate search, then create. Every
/// outcome is a result row, never an error.
fn execute_issue_broker_attempt(
    args: &PostArgs,
    api_url: &str,
    token: &str,
    entry: &IssueBrokerPlanEntry,
    index: usize,
) -> IssueBrokerResult {
    let mut result = IssueBrokerResult {
        schema: ISSUE_BROKER_RESULT_SCHEMA.to_owned(),
        candidate_id: entry.candidate_id.clone(),
        target_repo: entry.target_repo.clone(),
        action: "failed_to_open".to_owned(),
        reason: String::new(),
        url: None,
        error: None,
    };
    let marker = issue_broker_fingerprint_marker(&entry.fingerprint);
    let query = format!("repo:{} in:body \"{marker}\"", entry.target_repo);
    let search_url = format!(
        "{api_url}/search/issues?per_page=1&q={}",
        percent_encode_query(&query)
    );
    match run_github_api_get(Path::new("."), &search_url, token) {
        Ok(value) => {
            let total = value
                .get("total_count")
                .and_then(serde_json::Value::as_u64)
                .unwrap_or(0);
            if total > 0 {
                let existing_url = value
                    .get("items")
                    .and_then(|items| items.get(0))
                    .and_then(|item| item.get("html_url"))
                    .and_then(serde_json::Value::as_str)
                    .unwrap_or_default()
                    .to_owned();
                result.action = "duplicate".to_owned();
                result.reason = format!(
                    "fingerprint duplicate search found {total} existing issue(s) in {}",
                    entry.target_repo
                );
                result.url = Some(existing_url);
                return result;
            }
        }
        Err(err) => {
            result.reason =
                "fingerprint duplicate search failed; refusing to open without it".to_owned();
            result.error = Some(format!("{err:#}"));
            return result;
        }
    }
    let payload = serde_json::json!({
        "title": entry.title,
        "body": entry.body,
        "labels": entry.labels,
    });
    let payload_path = args
        .out
        .join(format!("issue-broker-payload-{index:03}.json"));
    if let Err(err) = serde_json::to_vec_pretty(&payload)
        .map_err(anyhow::Error::from)
        .and_then(|bytes| fs::write(&payload_path, bytes).map_err(anyhow::Error::from))
    {
        result.reason = "failed to write the issue create payload receipt".to_owned();
        result.error = Some(format!("{err:#}"));
        return result;
    }
    let create_url = format!("{api_url}/repos/{}/issues", entry.target_repo);
    match run_curl_json_post(
        Path::new("."),
        &create_url,
        &format!("Authorization: Bearer {token}"),
        &payload_path,
        &[
            "Accept: application/vnd.github+json",
            "Content-Type: application/json",
            "X-GitHub-Api-Version: 2022-11-28",
        ],
        60,
    ) {
        Ok(output) if output.status.success() => {
            let response: serde_json::Value =
                serde_json::from_slice(&output.stdout).unwrap_or(serde_json::Value::Null);
            let url = response
                .get("html_url")
                .and_then(serde_json::Value::as_str)
                .unwrap_or_default()
                .to_owned();
            result.action = "opened".to_owned();
            result.reason = "no fingerprint duplicate found; issue opened".to_owned();
            result.url = Some(url);
            result
        }
        Ok(output) => {
            result.reason = "GitHub issue create returned a failure status".to_owned();
            result.error = Some(format!(
                "http status {:?}: {}",
                output.http_status,
                String::from_utf8_lossy(&output.stderr)
            ));
            result
        }
        Err(err) => {
            result.reason = "GitHub issue create request failed".to_owned();
            result.error = Some(format!("{err:#}"));
            result
        }
    }
}

/// Minimal percent-encoding for a GitHub search query string: keeps
/// unreserved characters, encodes everything else byte-wise.
fn percent_encode_query(value: &str) -> String {
    let mut encoded = String::with_capacity(value.len() * 3);
    for byte in value.bytes() {
        match byte {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'.' | b'_' | b'~' => {
                encoded.push(byte as char);
            }
            _ => {
                encoded.push_str(&format!("%{byte:02X}"));
            }
        }
    }
    encoded
}

/// Persist broker results (review/issue_broker_results.json next to the
/// other review artifacts under out, plus the NDJSON twin at the out root).
fn write_issue_broker_results(out: &Path, results: &[IssueBrokerResult]) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("issue_broker_results.json"),
        serde_json::to_vec_pretty(results)?,
    )?;
    let mut lines = String::new();
    for result in results {
        lines.push_str(&serde_json::to_string(result)?);
        lines.push('\n');
    }
    fs::write(out.join("issue_broker_results.ndjson"), lines)?;
    Ok(())
}

fn read_github_review_skip_receipt(review_json: &Path) -> Option<serde_json::Value> {
    let skip_path = github_review_skip_path(review_json);
    let text = fs::read_to_string(skip_path).ok()?;
    serde_json::from_str(&text).ok()
}

fn build_post_error_receipt(args: &PostArgs, err: &anyhow::Error) -> PostErrorReceipt {
    let review_metadata = read_github_review_metadata(args);
    let repo_valid = args.repo.as_deref().is_some_and(is_valid_repo_slug);
    let pull_number = args.pull_number.or_else(detect_pull_number_from_event);
    let token_present = args
        .github_token
        .as_ref()
        .is_some_and(|value| !value.trim().is_empty());
    let review_json_valid = review_metadata
        .as_ref()
        .is_some_and(|metadata| metadata.valid);
    let http_status = http_status_from_error(err);
    let (error_kind, failure_stage) = classify_post_error(
        args,
        err,
        repo_valid,
        pull_number,
        review_json_valid,
        http_status,
    );
    let would_post = token_present && repo_valid && pull_number.is_some() && review_json_valid;
    let payload_written = failure_stage == "network_post"
        && args.out.join("github-review-post-payload.json").exists();
    PostErrorReceipt {
        schema_version: 1,
        status: "failed".to_owned(),
        error_kind,
        failure_stage,
        reason: format!("{err:#}"),
        review_json: args.review_json.display().to_string(),
        review_json_exists: args.review_json.exists(),
        review_json_valid,
        review_event: review_metadata.as_ref().map(|review| review.event.clone()),
        review_body_bytes: review_metadata.as_ref().map(|review| review.body_bytes),
        review_comment_count: review_metadata.as_ref().map(|review| review.comments),
        diff_patch: review_metadata
            .as_ref()
            .map(|review| review.diff_patch.display().to_string())
            .unwrap_or_else(|| post_diff_patch_path(args).display().to_string()),
        diff_patch_exists: review_metadata
            .as_ref()
            .is_some_and(|review| review.diff_patch_exists),
        diff_patch_valid: review_metadata
            .as_ref()
            .is_some_and(|review| review.diff_patch_valid),
        diff_line_count: review_metadata
            .as_ref()
            .and_then(|review| review.diff_line_count),
        off_diff_comment_count: review_metadata
            .as_ref()
            .and_then(|review| review.off_diff_comment_count),
        repo: args.repo.clone(),
        repo_valid,
        pull_number,
        comments: review_metadata.as_ref().map(|review| review.comments),
        http_status,
        token_present,
        payload_written,
        would_post,
        failure_tolerated: !args.fail_on_post_error,
        fail_on_post_error: args.fail_on_post_error,
    }
}

fn classify_post_error(
    args: &PostArgs,
    err: &anyhow::Error,
    repo_valid: bool,
    pull_number: Option<u64>,
    review_json_valid: bool,
    http_status: Option<u16>,
) -> (String, String) {
    let token_present = args
        .github_token
        .as_ref()
        .is_some_and(|value| !value.trim().is_empty());
    if !token_present {
        return ("missing_token".to_owned(), "preflight".to_owned());
    }
    if !repo_valid {
        return ("invalid_repo".to_owned(), "preflight".to_owned());
    }
    if pull_number.is_none() {
        return ("missing_pull_number".to_owned(), "preflight".to_owned());
    }
    if !review_json_valid {
        return (
            "invalid_review_payload".to_owned(),
            "payload_validation".to_owned(),
        );
    }
    if http_status.is_some() {
        return ("post_http_error".to_owned(), "network_post".to_owned());
    }
    let text = model_error_chain_text(err).to_ascii_lowercase();
    if text.contains("curl") || text.contains("github review post failed") {
        return ("post_failed".to_owned(), "network_post".to_owned());
    }
    ("failed".to_owned(), "unknown".to_owned())
}

struct GitHubReviewMetadata {
    valid: bool,
    comments: usize,
    event: String,
    body_bytes: usize,
    diff_patch: PathBuf,
    diff_patch_exists: bool,
    diff_patch_valid: bool,
    diff_line_count: Option<usize>,
    off_diff_comment_count: Option<usize>,
}

fn read_github_review_metadata(args: &PostArgs) -> Option<GitHubReviewMetadata> {
    let review: GitHubReview = serde_json::from_slice(&fs::read(&args.review_json).ok()?).ok()?;
    let diff_patch = post_diff_patch_path(args);
    let diff_metadata = review_diff_metadata(&diff_patch, &review);
    let diff_valid = review.comments.is_empty()
        || diff_metadata
            .as_ref()
            .is_some_and(|metadata| metadata.off_diff_comment_count == 0);
    // Mirror validate_github_review_payload_for_post: the receipt's `valid`
    // marker must reflect the policy the payload was prepared under, not the
    // hardcoded default.
    let review_body_policy = post_review_body_policy(args);
    let valid = validate_github_review_payload_with_policy_waiver(
        &review,
        &review_body_policy,
        summary_only_body_waives_post_validation(&review_body_policy),
    )
    .is_ok()
        && diff_valid;
    Some(GitHubReviewMetadata {
        valid,
        comments: review.comments.len(),
        event: review.event,
        body_bytes: review.body.len(),
        diff_patch,
        diff_patch_exists: diff_metadata.is_some(),
        diff_patch_valid: diff_metadata.is_some(),
        diff_line_count: diff_metadata
            .as_ref()
            .map(|metadata| metadata.diff_line_count),
        off_diff_comment_count: diff_metadata.map(|metadata| metadata.off_diff_comment_count),
    })
}

struct ReviewDiffMetadata {
    diff_line_count: usize,
    off_diff_comment_count: usize,
}

fn review_diff_metadata(diff_patch: &Path, review: &GitHubReview) -> Option<ReviewDiffMetadata> {
    let patch = fs::read_to_string(diff_patch).ok()?;
    let right_lines = right_side_diff_lines(&patch);
    Some(ReviewDiffMetadata {
        diff_line_count: right_lines.len(),
        off_diff_comment_count: off_diff_comment_count(review, &right_lines),
    })
}

fn off_diff_comment_count(review: &GitHubReview, right_lines: &BTreeSet<(String, u32)>) -> usize {
    review
        .comments
        .iter()
        .filter(|comment| {
            let path = normalize_repo_path(&comment.path);
            !right_lines.contains(&(path, comment.line))
        })
        .count()
}

fn prepare_plan(
    args: &ReviewArgs,
    allow_heavy: bool,
    selectors: &SelectorArgs,
) -> Result<(Config, DiffContext, BoxState, Plan)> {
    validate_selector_syntax(selectors)?;
    let config = Config::load_or_default(
        &args.config,
        runtime_profile_override(args.profile.as_ref(), args.runtime_profile.as_ref()),
    )?;
    let profile = config.selected_profile()?;
    let box_state = BoxState::detect()?;
    let diff = DiffContext::from_git(&args.root, &args.base, &args.head)?;
    let mut plan = build_plan(&config, profile, &box_state, &diff, &args.root, allow_heavy);
    apply_plan_selectors(&mut plan, selectors)?;
    Ok((config, diff, box_state, plan))
}

fn write_plan_artifacts(
    out: &Path,
    config: &Config,
    diff: &DiffContext,
    box_state: &BoxState,
    plan: &Plan,
    selectors: PlanArtifactSelectors<'_>,
) -> Result<()> {
    fs::create_dir_all(out.join("input"))?;
    let profile = config.selected_profile()?;
    fs::write(out.join("plan.json"), serde_json::to_vec_pretty(plan)?)?;
    fs::write(
        out.join("effective-config.json"),
        serde_json::to_vec_pretty(config)?,
    )?;
    fs::write(
        out.join("resolved-profile.json"),
        serde_json::to_vec_pretty(&resolved_profile_artifact(config, profile))?,
    )?;
    fs::write(
        out.join("resolved-plan.json"),
        serde_json::to_vec_pretty(&resolved_plan_artifact(
            config,
            profile,
            diff,
            plan,
            selectors.run_args,
            selectors.selectors,
            selectors.effective_model_lanes,
        ))?,
    )?;
    write_resolved_tools_artifacts(out, config, profile, plan)?;
    fs::write(
        out.join("box-state.json"),
        serde_json::to_vec_pretty(box_state)?,
    )?;
    fs::write(
        out.join("input/diff-context.json"),
        serde_json::to_vec_pretty(diff)?,
    )?;
    fs::write(
        out.join("input/changed-files.txt"),
        diff.changed_files.join("\n"),
    )?;
    fs::write(out.join("input/diff.patch"), &diff.patch)?;
    fs::write(out.join("input/pr.md"), render_pr_packet(diff))?;
    fs::write(out.join("input/claims.md"), render_claim_prompt(diff))?;
    Ok(())
}

struct PlanArtifactSelectors<'a> {
    run_args: Option<&'a RunArgs>,
    selectors: &'a SelectorArgs,
    effective_model_lanes: Option<&'a [LanePlan]>,
}

fn resolved_profile_artifact(config: &Config, profile: &Profile) -> serde_json::Value {
    serde_json::json!({
        "schema": RESOLVED_PROFILE_SCHEMA,
        "selected_profile": &profile.name,
        "selected_review_profile": &config.review_profile,
        "selected_runtime_profile": &profile.name,
        "repo": &config.repo,
        "review": &config.review,
        "review_body": &config.review_body,
        "gate": &config.gate,
        "proof": &config.proof,
        "review_profile": {
            "name": &config.review_profile,
            "repo_kind": &config.repo.kind,
            "default_lanes_enabled": config.review.enable_default_lanes,
            "posting_engine": &config.review.posting_engine,
        },
        "profile": profile,
        "tools": &config.tools,
    })
}

/// One entry from a bucket in `repair-queue.json` (schema_version `"0.1"`).
///
/// Validated against real `unsafe-review 0.3.4` output. The repair queue
/// classifies each card into one of several buckets (`repairable_by_guard`,
/// `requires_witness_receipt`, `requires_human_review`, …) with per-entry
/// fields for routing and missing-evidence description.
///
/// **Honest capability assessment**: the repair queue provides guidance — it
/// names the missing evidence and classifies the repair class — but does NOT
/// supply a concrete replacement text that could power a one-click GitHub
/// suggestion block. Fields like `operation` (the unsafe expression as-is),
/// `missing_evidence` (why it lacks a guard), and `do_not_do` (negative
/// constraints) are present; a `replacement` / `new_text` / `suggestion_text`
/// field is absent. Suggestion blocks therefore cannot be emitted from this
/// source without fabricating edits. See the narrow follow-up issue:
/// "repair-queue should emit applicable edits for suggestion blocks".
#[derive(Clone, Debug, Deserialize)]
struct RepairQueueEntry {
    card_id: String,
    /// Bucket reason explains why this entry landed in its bucket.
    #[serde(default)]
    bucket_reason: Option<String>,
    /// The unsafe operation text (read-only context; not a replacement).
    #[serde(default)]
    operation: Option<String>,
    /// Missing evidence items (prose guidance; not a diff suggestion).
    #[serde(default)]
    missing_evidence: Vec<String>,
}

/// Top-level shape of `repair-queue.json` (schema_version `"0.1"`).
///
/// Only the `buckets` map is consumed here; all other top-level fields are
/// silently tolerated so forward-compatible additions do not break ingestion.
#[derive(Debug, Deserialize)]
struct RepairQueueFile {
    /// All bucket names map to lists of `RepairQueueEntry`. Known keys:
    /// `repairable_by_guard`, `repairable_by_safety_docs`, `repairable_by_test`,
    /// `requires_witness_receipt`, `requires_human_review`, `do_not_auto_repair`.
    #[serde(default)]
    buckets: std::collections::BTreeMap<String, Vec<RepairQueueEntry>>,
}

/// Read `repair-queue.json` from the unsafe-review output directory.
///
/// Returns a map from `card_id` to the first `RepairQueueEntry` for that id
/// (entries may appear in multiple buckets; we keep the first bucket hit per
/// card so callers get exactly one context record per card). Returns an empty
/// map when the file is absent, unreadable, or unparseable — always degrades
/// gracefully.
fn read_repair_queue(
    sensor_dir: &Path,
    artifacts: &UnsafeReviewGate,
) -> std::collections::BTreeMap<String, RepairQueueEntry> {
    let out_dir = sensor_dir.join(UNSAFE_REVIEW_OUTPUT_SUBDIR);
    let rq_path = artifacts
        .artifacts
        .get("repair_queue")
        .map(|rel| out_dir.join(rel))
        .unwrap_or_else(|| out_dir.join("repair-queue.json"));
    let text = match fs::read_to_string(&rq_path) {
        Ok(t) => t,
        Err(_) => return std::collections::BTreeMap::new(),
    };
    let rq: RepairQueueFile = match serde_json::from_str(&text) {
        Ok(r) => r,
        Err(_) => return std::collections::BTreeMap::new(),
    };
    let mut by_card: std::collections::BTreeMap<String, RepairQueueEntry> =
        std::collections::BTreeMap::new();
    for entries in rq.buckets.into_values() {
        for entry in entries {
            by_card.entry(entry.card_id.clone()).or_insert(entry);
        }
    }
    by_card
}

/// Build `GitHubReviewComment` entries from unsafe-review `comment-plan.json`
/// candidates for inline posting on the PR diff.
///
/// # Selection rules
/// - Only candidates with `changed_line: true` are eligible; anchoring to an
///   unchanged line would be rejected by the GitHub review API.
/// - Capped at `min(comment_plan.len(), max_inline_budget)` (the comment plan
///   is already bounded to ≤3 by unsafe-review itself).
/// - Deduplication against `existing_paths_lines` prevents double-posting if a
///   model lane already proposed a comment on the same `(path, line)` pair.
///
/// # Suggestion blocks
/// Each comment body names the `coverage_gap`, the next reviewer action
/// (`confirmation_state`), and the per-entry `trust_boundary`. A GitHub
/// `suggestion` block is emitted ONLY when unsafe-review's repair-queue
/// provides a concrete applicable code edit for the site. As of
/// `repair-queue/0.1`, the queue provides bucket classification and guidance
/// (missing evidence, do-not-do constraints) but NO replacement text — so
/// suggestion blocks are NOT emitted from this source. The field remains ready
/// on `GitHubReviewComment` for a future repair-queue version that adds
/// `replacement` / `applicable_edit` output. This is an honest capability gap
/// reported upstream as a narrow follow-up issue.
fn build_unsafe_review_inline_comments(
    sensor_dir: &Path,
    existing_paths_lines: &std::collections::BTreeSet<(String, u32)>,
    max_inline_budget: usize,
) -> Vec<GitHubReviewComment> {
    let artifacts = match read_unsafe_review_artifacts(sensor_dir) {
        Some(a) => a,
        None => return Vec::new(),
    };
    let repair_queue = read_repair_queue(sensor_dir, &artifacts.gate);
    let trust = artifacts
        .gate
        .trust_boundary
        .as_deref()
        .unwrap_or("advisory");
    let mut comments: Vec<GitHubReviewComment> = Vec::new();
    for entry in &artifacts.comment_plan {
        if comments.len() >= max_inline_budget {
            break;
        }
        // Only anchor to changed lines — GitHub review API requires it.
        if entry.changed_line != Some(true) {
            continue;
        }
        let (Some(path), Some(line)) = (entry.path.as_deref(), entry.line) else {
            continue;
        };
        // Dedup: skip if a model lane already claimed this (path, line).
        let norm_path = normalize_repo_path(path);
        if existing_paths_lines.contains(&(norm_path.clone(), line)) {
            continue;
        }
        let gap = entry
            .coverage_gap
            .as_deref()
            .unwrap_or("unsafe coverage gap");
        let action = entry
            .confirmation_state
            .as_deref()
            .unwrap_or("reviewer confirmation required");
        let card_label = entry
            .card_id
            .as_deref()
            .map(|id| format!(" (`{id}`)"))
            .unwrap_or_default();
        // Optional: if the repair queue has an entry for this card, surface the
        // bucket reason, operation, and missing evidence as additional context
        // (guidance only, not a suggestion block).
        let rq_context = entry
            .card_id
            .as_deref()
            .and_then(|id| repair_queue.get(id))
            .map(|rq_entry| {
                let bucket = rq_entry
                    .bucket_reason
                    .as_deref()
                    .unwrap_or("see repair-queue.json");
                let operation_line = rq_entry
                    .operation
                    .as_deref()
                    .map(|op| format!("\n\n**Operation**: `{op}`"))
                    .unwrap_or_default();
                let evidence_lines = rq_entry
                    .missing_evidence
                    .iter()
                    .map(|e| format!("  - {e}"))
                    .collect::<Vec<_>>()
                    .join("\n");
                if evidence_lines.is_empty() {
                    format!("\n\n**Repair class**: {bucket}{operation_line}")
                } else {
                    format!(
                        "\n\n**Repair class**: {bucket}{operation_line}\n\n**Missing evidence**:\n{evidence_lines}"
                    )
                }
            })
            .unwrap_or_default();
        let body = format!(
            "[unsafe-review]{card_label} **{gap}**\n\n\
             **Next action**: {action}\n\n\
             **Trust boundary** (advisory): {trust}{rq_context}\n\n\
             _Suggestion sourced from unsafe-review advisory output. \
             Apply only after reviewer verification. \
             Inline comments are advisory — they do not change the merge decision._"
        );
        // No suggestion block: repair-queue/0.1 provides guidance (missing
        // evidence, bucket classification, do-not-do constraints) but no
        // concrete replacement text. suggestion = None until a future
        // repair-queue version adds an applicable edit field.
        comments.push(GitHubReviewComment {
            path: norm_path,
            line,
            side: "RIGHT".to_owned(),
            body,
            suggestion: None,
        });
    }
    comments
}

fn resolved_plan_artifact(
    config: &Config,
    profile: &Profile,
    diff: &DiffContext,
    plan: &Plan,
    run_args: Option<&RunArgs>,
    selectors: &SelectorArgs,
    effective_model_lanes: Option<&[LanePlan]>,
) -> serde_json::Value {
    let run_pass = run_args
        .map(|args| resolved_run_pass(args.run_pass).key())
        .unwrap_or("plan-default");
    let language_mix = classify_language_mix(&diff.changed_files);
    serde_json::json!({
        "schema": RESOLVED_PLAN_SCHEMA,
        "base": &plan.base,
        "head": &plan.head,
        "run_pass": run_pass,
        "diff_class": diff.diff_class.key(),
        "language_mix": &language_mix,
        "proof_policy": resolved_proof_policy_artifact(config, diff, &language_mix),
        "review_profile": &config.review_profile,
        "profile_name": &plan.profile_name,
        "runtime_profile": &profile.name,
        "budgets": &profile.budgets,
        "trusted_repo": &profile.trusted_repo,
        "guards": &profile.guards,
        "limits": &profile.limits,
        "posting": &config.review,
        "review_body": &config.review_body,
        "gate": &config.gate,
        "selectors": resolved_selector_artifact(run_args, selectors, effective_model_lanes),
        "sensors": &plan.sensors,
        "lanes": &plan.lanes,
        "notes": &plan.notes,
    })
}

fn resolved_selector_artifact(
    run_args: Option<&RunArgs>,
    selectors: &SelectorArgs,
    effective_model_lanes: Option<&[LanePlan]>,
) -> serde_json::Value {
    let lane_include = selector_values_or_empty(&selectors.lanes);
    let lane_exclude = selector_values_or_empty(&selectors.except_lanes);
    let tool_include = selector_values_or_empty(&selectors.tools);
    let tool_exclude = selector_values_or_empty(&selectors.except_tools);
    let effective_lanes = effective_model_lanes
        .map(|lanes| lanes.iter().map(|lane| lane.id.clone()).collect::<Vec<_>>())
        .unwrap_or_default();
    if let Some(args) = run_args {
        serde_json::json!({
            "run_pass": resolved_run_pass(args.run_pass).key(),
            "depth": args.depth.key(),
            "lane_width": args.lane_width,
            "model_concurrency": args.model_concurrency,
            "max_model_calls": args.max_model_calls,
            "max_inline_comments": args.max_inline_comments,
            "lanes": lane_include,
            "except_lanes": lane_exclude,
            "tools": tool_include,
            "except_tools": tool_exclude,
            "effective_model_lanes": effective_lanes,
        })
    } else {
        serde_json::json!({
            "run_pass": "plan-default",
            "depth": ReviewDepth::Standard.key(),
            "lane_width": STANDARD_LANE_WIDTH,
            "model_concurrency": STANDARD_MODEL_CONCURRENCY,
            "max_model_calls": STANDARD_MAX_MODEL_CALLS,
            "max_inline_comments": 8,
            "lanes": lane_include,
            "except_lanes": lane_exclude,
            "tools": tool_include,
            "except_tools": tool_exclude,
            "effective_model_lanes": effective_lanes,
            "source": "plan-default",
        })
    }
}

fn validate_selector_syntax(selectors: &SelectorArgs) -> Result<()> {
    parse_selector_set(&selectors.lanes, "--lanes")?;
    parse_selector_set(&selectors.except_lanes, "--except-lanes")?;
    parse_selector_set(&selectors.tools, "--tools")?;
    parse_selector_set(&selectors.except_tools, "--except-tools")?;
    Ok(())
}

fn selector_values_or_empty(value: &str) -> Vec<String> {
    let mut values = value
        .split(',')
        .map(str::trim)
        .filter(|item| !item.is_empty())
        .map(ToOwned::to_owned)
        .collect::<Vec<_>>();
    values.sort();
    values.dedup();
    values
}

fn parse_selector_set(value: &str, flag: &str) -> Result<BTreeSet<String>> {
    let mut selected = BTreeSet::new();
    for item in value
        .split(',')
        .map(str::trim)
        .filter(|item| !item.is_empty())
    {
        if !is_selector_id(item) {
            bail!("{flag} contains invalid selector id `{item}`");
        }
        selected.insert(item.to_owned());
    }
    Ok(selected)
}

fn is_selector_id(value: &str) -> bool {
    value
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.'))
}

fn apply_plan_selectors(plan: &mut Plan, selectors: &SelectorArgs) -> Result<()> {
    let tool_include = parse_selector_set(&selectors.tools, "--tools")?;
    let tool_exclude = parse_selector_set(&selectors.except_tools, "--except-tools")?;
    if !tool_include.is_empty() || !tool_exclude.is_empty() {
        plan.sensors = filter_sensor_plans(
            std::mem::take(&mut plan.sensors),
            &tool_include,
            &tool_exclude,
        )?;
        plan.notes.push(format!(
            "tool selectors applied: tools=[{}] except-tools=[{}]",
            tool_include
                .iter()
                .map(String::as_str)
                .collect::<Vec<_>>()
                .join(","),
            tool_exclude
                .iter()
                .map(String::as_str)
                .collect::<Vec<_>>()
                .join(",")
        ));
    }
    let lane_include = parse_selector_set(&selectors.lanes, "--lanes")?;
    let lane_exclude = parse_selector_set(&selectors.except_lanes, "--except-lanes")?;
    if !lane_include.is_empty() || !lane_exclude.is_empty() {
        plan.notes.push(format!(
            "lane selectors will filter model assignments: lanes=[{}] except-lanes=[{}]",
            lane_include
                .iter()
                .map(String::as_str)
                .collect::<Vec<_>>()
                .join(","),
            lane_exclude
                .iter()
                .map(String::as_str)
                .collect::<Vec<_>>()
                .join(",")
        ));
    }
    Ok(())
}

fn filter_sensor_plans(
    sensors: Vec<SensorPlan>,
    include: &BTreeSet<String>,
    exclude: &BTreeSet<String>,
) -> Result<Vec<SensorPlan>> {
    validate_known_selectors(
        "tool",
        sensors.iter().map(|sensor| sensor.id.as_str()),
        include,
    )?;
    validate_known_selectors(
        "tool",
        sensors.iter().map(|sensor| sensor.id.as_str()),
        exclude,
    )?;
    Ok(sensors
        .into_iter()
        .filter(|sensor| include.is_empty() || include.contains(&sensor.id))
        .filter(|sensor| !exclude.contains(&sensor.id))
        .collect())
}

fn filter_lane_plans(
    lanes: Vec<LanePlan>,
    include: &BTreeSet<String>,
    exclude: &BTreeSet<String>,
) -> Result<Vec<LanePlan>> {
    validate_known_selectors("lane", lanes.iter().map(|lane| lane.id.as_str()), include)?;
    validate_known_selectors("lane", lanes.iter().map(|lane| lane.id.as_str()), exclude)?;
    Ok(lanes
        .into_iter()
        .filter(|lane| include.is_empty() || include.contains(&lane.id))
        .filter(|lane| !exclude.contains(&lane.id))
        .collect())
}

fn validate_known_selectors<'a>(
    kind: &str,
    available: impl Iterator<Item = &'a str>,
    selected: &BTreeSet<String>,
) -> Result<()> {
    if selected.is_empty() {
        return Ok(());
    }
    let available = available.collect::<BTreeSet<_>>();
    let unknown = selected
        .iter()
        .filter(|item| !available.contains(item.as_str()))
        .cloned()
        .collect::<Vec<_>>();
    if !unknown.is_empty() {
        bail!(
            "unknown {kind} selector(s): {}; available: {}",
            unknown.join(","),
            available.into_iter().collect::<Vec<_>>().join(",")
        );
    }
    Ok(())
}

fn print_plan(plan: &Plan, box_state: &BoxState) {
    println!("Profile: {}", plan.profile_name);
    println!("Diff class: {}", plan.diff_class.key());
    println!("Box: {}", box_state.summary_line());
    println!("Sensors:");
    for sensor in &plan.sensors {
        let marker = if sensor.run { "run" } else { "skip" };
        println!("  {:<5} {:<16} {}", marker, sensor.id, sensor.reason);
    }
    println!("Lanes:");
    for lane in &plan.lanes {
        println!("  {:<13} {}", lane.id, lane.model_display);
    }
}

impl DiffContext {
    fn from_git(root: &Path, base: &str, head: &str) -> Result<Self> {
        let range = format!("{base}...{head}");
        let changed_files = git_lines(root, &["diff", "--name-only", &range])
            .or_else(|_| git_lines(root, &["diff", "--name-only", base, head]))
            .with_context(|| format!("git diff --name-only {range}"))?;
        let patch = git_text(root, &["diff", "--patch", &range])
            .or_else(|_| git_text(root, &["diff", "--patch", base, head]))
            .unwrap_or_else(|_| String::new());
        let flags = classify_diff(&changed_files, &patch);
        let diff_class = classify_diff_class(&changed_files, &flags);
        Ok(Self {
            base: base.to_owned(),
            head: head.to_owned(),
            changed_files,
            patch,
            flags,
            diff_class,
        })
    }
}

fn git_lines(root: &Path, args: &[&str]) -> Result<Vec<String>> {
    Ok(git_text(root, args)?
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .map(ToOwned::to_owned)
        .collect())
}

fn git_text(root: &Path, args: &[&str]) -> Result<String> {
    let output = ProcessCommand::new("git")
        .arg("-C")
        .arg(root)
        .args(args)
        .output()
        .with_context(|| "run git")?;
    if !output.status.success() {
        bail!(
            "git {:?} failed: {}",
            args,
            String::from_utf8_lossy(&output.stderr)
        );
    }
    Ok(String::from_utf8_lossy(&output.stdout).to_string())
}

fn git_text_owned(root: &Path, args: &[String]) -> Result<String> {
    let output = ProcessCommand::new("git")
        .arg("-C")
        .arg(root)
        .args(args)
        .output()
        .with_context(|| "run git")?;
    if !output.status.success() {
        bail!(
            "git {:?} failed: {}",
            args,
            String::from_utf8_lossy(&output.stderr)
        );
    }
    Ok(String::from_utf8_lossy(&output.stdout).to_string())
}

fn classify_diff(files: &[String], patch: &str) -> DiffFlags {
    let mut flags = DiffFlags {
        docs_only: !files.is_empty(),
        ..DiffFlags::default()
    };
    for path in files {
        let lower = path.to_ascii_lowercase();
        flags.docs_only &= is_doc_path(&lower);
        flags.source_changed |= is_source_path(&lower);
        flags.rust_changed |= lower.ends_with(".rs");
        flags.rust_tests_changed |=
            lower.ends_with(".rs") && (lower.contains("test") || lower.contains("tests/"));
        flags.workflow_changed |= lower.starts_with(".github/workflows/")
            || lower.ends_with("action.yml")
            || lower.ends_with("action.yaml");
        flags.dependency_changed |= is_dependency_path(&lower);
        flags.shell_changed |= lower.ends_with(".sh") || lower.starts_with("scripts/");
        flags.cpp_changed |= is_cpp_path(&lower);
        flags.unsafe_or_native_risk |= is_native_risk_path(&lower);
    }
    if patch_tokens_can_promote_native_risk(files, &flags)
        && patch_contains_native_risk_token(patch)
    {
        flags.unsafe_or_native_risk = true;
    }
    flags
}

fn classify_language_mix(files: &[String]) -> LanguageMix {
    let mut language_counts = BTreeMap::<&'static str, usize>::new();
    let mut surfaces = BTreeSet::<&'static str>::new();

    for path in files {
        let lower = path.to_ascii_lowercase();
        if let Some(language) = language_for_path(&lower) {
            *language_counts.entry(language).or_default() += 1;
        }
        for surface in surfaces_for_path(&lower) {
            surfaces.insert(surface);
        }
    }

    let languages = language_counts
        .keys()
        .map(|language| (*language).to_owned())
        .collect::<Vec<_>>();
    let primary_language = language_counts
        .iter()
        .fold(
            None::<(&'static str, usize)>,
            |best, (language, count)| match best {
                Some((best_language, best_count))
                    if best_count > *count
                        || (best_count == *count && best_language <= *language) =>
                {
                    Some((best_language, best_count))
                }
                _ => Some((*language, *count)),
            },
        )
        .map(|(language, _count)| language.to_owned());

    LanguageMix {
        mixed_language: languages.len() > 1,
        languages,
        primary_language,
        surfaces: surfaces.into_iter().map(str::to_owned).collect::<Vec<_>>(),
    }
}

fn classify_diff_class(files: &[String], flags: &DiffFlags) -> DiffClass {
    if files.is_empty() {
        return DiffClass::ArtifactOnlySmoke;
    }
    if flags.docs_only {
        return DiffClass::DocsOnly;
    }
    if files.iter().all(|path| is_workflow_tooling_path(path)) {
        return DiffClass::WorkflowTooling;
    }
    if files.iter().all(|path| is_test_or_fixture_path(path)) {
        return DiffClass::TestsOnly;
    }
    if flags.unsafe_or_native_risk {
        return DiffClass::SourceUb;
    }
    DiffClass::SourceGeneral
}

fn is_source_path(path: &str) -> bool {
    [
        ".rs", ".zig", ".cpp", ".cc", ".c", ".h", ".hpp", ".ts", ".tsx", ".js", ".jsx", ".go",
        ".py",
    ]
    .iter()
    .any(|suffix| path.ends_with(suffix))
}

fn language_for_path(path: &str) -> Option<&'static str> {
    if path.ends_with(".rs") {
        Some("rust")
    } else if path.ends_with(".ts") || path.ends_with(".tsx") {
        Some("typescript")
    } else if path.ends_with(".js")
        || path.ends_with(".jsx")
        || path.ends_with(".mjs")
        || path.ends_with(".cjs")
    {
        Some("javascript")
    } else if is_cpp_path(path) {
        Some("c-cpp")
    } else if path.ends_with(".zig") {
        Some("zig")
    } else if path.ends_with(".go") {
        Some("go")
    } else if path.ends_with(".py") {
        Some("python")
    } else if path.ends_with(".sh") {
        Some("shell")
    } else if path.ends_with(".yml") || path.ends_with(".yaml") {
        Some("yaml")
    } else if path.ends_with(".toml") {
        Some("toml")
    } else if path.ends_with(".json") {
        Some("json")
    } else if path.ends_with(".md") {
        Some("markdown")
    } else {
        None
    }
}

fn surfaces_for_path(path: &str) -> Vec<&'static str> {
    let mut surfaces = Vec::new();
    if is_doc_path(path) {
        surfaces.push("docs");
    }
    if is_dependency_path(path) {
        surfaces.push("dependencies");
    }
    if path.starts_with(".github/workflows/") {
        surfaces.push("workflow");
    }
    if path.starts_with(".github/actions/")
        || path.ends_with("action.yml")
        || path.ends_with("action.yaml")
    {
        surfaces.push("action");
    }
    if path.contains("/fixtures/") || path.starts_with("fixtures/") {
        surfaces.push("fixtures");
    }
    if path.contains("/test/")
        || path.contains("/tests/")
        || path.starts_with("test/")
        || path.starts_with("tests/")
        || path.ends_with(".test.ts")
        || path.ends_with(".test.js")
        || path.ends_with("_test.rs")
    {
        surfaces.push("tests");
    }
    if path.ends_with(".sh") || path.starts_with("scripts/") {
        surfaces.push("scripts");
    }
    if path.starts_with("configs/") {
        surfaces.push("config");
    }
    if is_source_path(path) && !surfaces.contains(&"tests") {
        surfaces.push("source");
    }
    if surfaces.is_empty() {
        surfaces.push("other");
    }
    surfaces
}

fn is_doc_path(path: &str) -> bool {
    path.ends_with(".md") || path.starts_with("docs/")
}

fn is_cpp_path(path: &str) -> bool {
    [".c", ".cc", ".cpp", ".cxx", ".h", ".hpp"]
        .iter()
        .any(|suffix| path.ends_with(suffix))
}

fn is_zig_path(path: &str) -> bool {
    path.ends_with(".zig")
}

fn is_native_risk_path(path: &str) -> bool {
    path.contains("ffi")
        || path.contains("jsc")
        || path.contains("arraybuffer")
        || path.contains("typedarray")
        || path.contains("worker")
        || path.contains("crypto")
        || path.contains("zstd")
        || path.contains("src/runtime/")
        || path.contains("src/bun.js/bindings/")
}

fn patch_tokens_can_promote_native_risk(files: &[String], flags: &DiffFlags) -> bool {
    flags.rust_changed
        || flags.cpp_changed
        || files.iter().any(|path| {
            let lower = path.to_ascii_lowercase();
            is_zig_path(&lower) || is_native_risk_path(&lower)
        })
}

fn patch_contains_native_risk_token(patch: &str) -> bool {
    let lower_patch = patch.to_ascii_lowercase();
    [
        "unsafe",
        "extern",
        "from_raw_parts",
        "as_ptr",
        "as_mut_ptr",
        "maybeuninit",
        "nonnull",
        "arraybuffer",
        "typedarray",
        "detach",
        "resize",
        "transfer",
        "protect",
        "unprotect",
        "worker",
        "ffi",
        "jsc",
        "stringorbuffer",
        "sharedarraybuffer",
    ]
    .iter()
    .any(|token| lower_patch.contains(token))
}

fn is_dependency_path(path: &str) -> bool {
    matches!(
        path,
        "cargo.lock"
            | "cargo.toml"
            | "package.json"
            | "bun.lock"
            | "bun.lockb"
            | "pnpm-lock.yaml"
            | "yarn.lock"
            | "package-lock.json"
    ) || path.ends_with("/cargo.toml")
        || path.ends_with("/cargo.lock")
}

fn is_workflow_tooling_path(path: &str) -> bool {
    let lower = path.to_ascii_lowercase();
    lower.starts_with(".github/workflows/")
        || lower.starts_with(".github/actions/")
        || lower.ends_with("action.yml")
        || lower.ends_with("action.yaml")
        || lower.starts_with("scripts/")
        || lower.starts_with("configs/")
        || matches!(
            lower.as_str(),
            "justfile"
                | "makefile"
                | "dockerfile"
                | ".github/dependabot.yml"
                | ".github/dependabot.yaml"
        )
}

fn is_github_workflow_file(path: &str) -> bool {
    let lower = path.to_ascii_lowercase();
    lower.starts_with(".github/workflows/") && (lower.ends_with(".yml") || lower.ends_with(".yaml"))
}

fn is_test_or_fixture_path(path: &str) -> bool {
    let lower = path.to_ascii_lowercase();
    lower.contains("/test/")
        || lower.contains("/tests/")
        || lower.starts_with("test/")
        || lower.starts_with("tests/")
        || lower.contains("/fixtures/")
        || lower.starts_with("fixtures/")
        || lower.ends_with(".snap")
        || lower.ends_with(".test.ts")
        || lower.ends_with(".test.js")
        || lower.ends_with("_test.rs")
}

fn build_plan(
    config: &Config,
    profile: &Profile,
    box_state: &BoxState,
    diff: &DiffContext,
    root: &Path,
    allow_heavy: bool,
) -> Plan {
    let mut notes = Vec::new();
    let guard_ok = guard_ok(profile, box_state, &mut notes);
    let mut sensors = config
        .tools
        .values()
        .map(|tool| plan_tool(tool, profile, diff, root, guard_ok, allow_heavy))
        .collect::<Vec<_>>();
    sensors.sort_by_key(|sensor| sensor_order(&sensor.id));
    if diff.flags.docs_only {
        notes.push(
            "docs-only diff detected; workflow paths-ignore should normally skip this run"
                .to_owned(),
        );
    }
    if !allow_heavy {
        notes.push("heavy witnesses are disabled unless --allow-heavy is passed".to_owned());
    }
    if matches!(
        profile.name.as_str(),
        "gh-runner" | "gh-runner-standard" | "gh-runner-full"
    ) {
        notes.push(format!(
            "{} profile: trusted repos get opened and ready_for_review evidence passes, 30m target, 60m hard timeout",
            profile.name
        ));
    }
    let repo_lanes = repo_lane_plans(&config.lanes, diff, &mut notes);
    Plan {
        base: diff.base.clone(),
        head: diff.head.clone(),
        profile_name: profile.name.clone(),
        diff_class: diff.diff_class,
        changed_files: diff.changed_files.clone(),
        sensors,
        lanes: if config.review.enable_default_lanes {
            default_lanes_for_diff_class(diff.diff_class)
        } else {
            Vec::new()
        },
        repo_lanes,
        docs_only: diff.flags.docs_only,
        notes,
    }
}

/// Default sensor packet for repo lanes that do not declare `receives`.
const REPO_LANE_DEFAULT_RECEIVES: &[&str] = &["tokmd", "ripr", "ast-grep"];

/// Convert `[[lanes]]` from repo config into planned lanes for this run.
/// Entries missing `id` or `focus` are skipped with a plan note - they shape
/// review output, not the gate verdict, so the loud-but-non-fatal surface is
/// the plan notes (visible in resolved-plan.json). A lane whose
/// `diff_classes` do not match this diff is silently inapplicable. Lane
/// doctrine lives in docs/specs/UB-REVIEW-SPEC-0011-lane-doctrine.md.
fn repo_lane_plans(
    repo_lanes: &[RepoLane],
    diff: &DiffContext,
    notes: &mut Vec<String>,
) -> Vec<LanePlan> {
    let mut lanes: Vec<LanePlan> = Vec::new();
    for repo_lane in repo_lanes {
        if repo_lane.id.trim().is_empty() || repo_lane.focus.trim().is_empty() {
            notes.push(format!(
                "repo lane skipped: id and focus are required (id=`{}`)",
                repo_lane.id
            ));
            continue;
        }
        let diff_classes = if repo_lane.diff_classes.is_empty() {
            &["all".to_owned()][..]
        } else {
            &repo_lane.diff_classes[..]
        };
        if !proof_policy_diff_class_matches(diff_classes, diff.diff_class.key()) {
            continue;
        }
        let receives = if repo_lane.receives.is_empty() {
            REPO_LANE_DEFAULT_RECEIVES
                .iter()
                .map(|value| (*value).to_owned())
                .collect()
        } else {
            repo_lane.receives.clone()
        };
        let plan_lane = if repo_lane.model.trim().is_empty() {
            let receives_refs = receives.iter().map(String::as_str).collect::<Vec<_>>();
            model_lane(
                &repo_lane.id,
                &repo_lane.role,
                &receives_refs,
                &repo_lane.focus,
            )
        } else {
            LanePlan {
                id: repo_lane.id.clone(),
                role: repo_lane.role.clone(),
                model: repo_lane.model.clone(),
                model_display: repo_lane.model.clone(),
                receives,
                focus: repo_lane.focus.clone(),
            }
        };
        notes.push(format!(
            "repo lane `{}` registered for execution",
            plan_lane.id
        ));
        if let Some(existing) = lanes.iter_mut().find(|lane| lane.id == plan_lane.id) {
            *existing = plan_lane;
        } else {
            lanes.push(plan_lane);
        }
    }
    lanes
}

/// Merge repo lanes into a selected execution lane set: a repo lane replaces
/// a same-id builtin, otherwise appends. Applied after lane-width selection
/// so repo lanes execute at every width and diff class - the first wiring
/// pass only reached the plan artifact (PR #344's run proved the gap: plan
/// notes recorded the lanes, the executed set did not contain them).
fn merge_repo_lanes_into(lanes: &mut Vec<LanePlan>, repo_lanes: &[LanePlan]) {
    for repo_lane in repo_lanes {
        if let Some(existing) = lanes.iter_mut().find(|lane| lane.id == repo_lane.id) {
            *existing = repo_lane.clone();
        } else {
            lanes.push(repo_lane.clone());
        }
    }
}

fn plan_tool(
    tool: &ToolPolicy,
    profile: &Profile,
    diff: &DiffContext,
    root: &Path,
    guard_ok: bool,
    allow_heavy: bool,
) -> SensorPlan {
    let required = tool_required_for_diff(tool, diff);
    if !tool.enabled {
        return skipped(tool, "disabled by config", required);
    }
    if tool.requires_lease && !allow_heavy {
        return skipped(
            tool,
            "heavy/manual witness requires --allow-heavy",
            required,
        );
    }
    if matches!(tool.class, ToolClass::Test) && profile.limits.tests == 0 {
        return skipped(tool, "profile disables test leases", required);
    }
    if matches!(tool.class, ToolClass::Build) && profile.limits.builds == 0 {
        return skipped(tool, "profile disables build leases", required);
    }
    if !guard_ok && !matches!(tool.class, ToolClass::Packet) {
        return skipped(
            tool,
            "box guard failed; only packet generation is allowed",
            required,
        );
    }
    match trigger_match(tool.default, &diff.flags) {
        Some(reason) => {
            if tool.id == "cargo-allow" && !cargo_allow_policy_config_exists(root) {
                return skipped(tool, "cargo-allow policy config not found", required);
            }
            SensorPlan {
                id: tool.id.clone(),
                command: tool.command.clone(),
                run: true,
                reason,
                required,
                timeout_sec: tool.timeout_sec.min(profile.budgets.default_timeout_sec),
                artifact_budget_mb: tool.artifact_budget_mb,
                class: tool.class,
                weight: tool.weight,
                requires_lease: tool.requires_lease,
                gate: tool.gate.clone(),
            }
        }
        None => skipped(tool, "trigger did not match this diff", false),
    }
}

fn tool_required_for_diff(tool: &ToolPolicy, diff: &DiffContext) -> bool {
    tool.required && trigger_match(tool.default, &diff.flags).is_some()
}

/// Repo-native cargo-allow ledger that wins over cargo-allow's default
/// config discovery (`policy/allow.toml`, `.cargo/allow.toml`, `allow.toml`).
const CARGO_ALLOW_NATIVE_LEDGER: &str = "policy/cargo-allow.toml";

fn cargo_allow_policy_config_exists(root: &Path) -> bool {
    [
        CARGO_ALLOW_NATIVE_LEDGER,
        "policy/allow.toml",
        ".cargo/allow.toml",
        "allow.toml",
    ]
    .iter()
    .any(|path| root.join(path).is_file())
}

fn skipped(tool: &ToolPolicy, reason: &str, required: bool) -> SensorPlan {
    SensorPlan {
        id: tool.id.clone(),
        command: tool.command.clone(),
        run: false,
        reason: reason.to_owned(),
        required,
        timeout_sec: tool.timeout_sec,
        artifact_budget_mb: tool.artifact_budget_mb,
        class: tool.class,
        weight: tool.weight,
        requires_lease: tool.requires_lease,
        gate: tool.gate.clone(),
    }
}

fn trigger_match(trigger: Trigger, flags: &DiffFlags) -> Option<String> {
    match trigger {
        Trigger::Always => Some("always-on base packet".to_owned()),
        Trigger::SourceChanged if flags.source_changed => Some("source file changed".to_owned()),
        Trigger::SourceExceptionChanged
            if flags.source_changed
                || flags.workflow_changed
                || flags.shell_changed
                || flags.dependency_changed =>
        {
            Some("source-tree exception surface changed".to_owned())
        }
        Trigger::RustBehaviorOrTestsChanged if flags.rust_changed || flags.rust_tests_changed => {
            Some("Rust behavior or tests changed".to_owned())
        }
        Trigger::UnsafeOrNativeRiskChanged if flags.unsafe_or_native_risk => {
            Some("unsafe/native-risk pattern detected".to_owned())
        }
        Trigger::WorkflowChanged if flags.workflow_changed => {
            Some("workflow/action file changed".to_owned())
        }
        Trigger::DependencyChanged if flags.dependency_changed => {
            Some("dependency manifest or lockfile changed".to_owned())
        }
        Trigger::ShellChanged if flags.shell_changed => {
            Some("shell/script file changed".to_owned())
        }
        Trigger::CppChanged if flags.cpp_changed => Some("C/C++ file changed".to_owned()),
        Trigger::Diff => Some("diff-scoped advisory scan".to_owned()),
        Trigger::Manual | Trigger::Never => None,
        _ => None,
    }
}

fn guard_ok(profile: &Profile, box_state: &BoxState, notes: &mut Vec<String>) -> bool {
    let mut ok = true;
    if let Some(mem) = box_state.free_mem_mb
        && mem < profile.guards.min_free_mem_mb
    {
        ok = false;
        notes.push(format!(
            "free memory {mem}MiB is below profile floor {}MiB",
            profile.guards.min_free_mem_mb
        ));
    }
    if let Some(disk) = box_state.free_disk_mb
        && disk < profile.guards.min_free_disk_mb
    {
        ok = false;
        notes.push(format!(
            "free disk {disk}MiB is below profile floor {}MiB",
            profile.guards.min_free_disk_mb
        ));
    }
    if let Some(load) = box_state.load_1m
        && load > profile.guards.max_load_1m
    {
        ok = false;
        notes.push(format!(
            "load average {load:.2} exceeds profile ceiling {:.2}",
            profile.guards.max_load_1m
        ));
    }
    ok
}

fn sensor_order(id: &str) -> u8 {
    match id {
        "tokmd" => 0,
        "cargo-allow" => 1,
        "ripr" => 2,
        "unsafe-review" => 3,
        "ast-grep" => 4,
        "semgrep" => 5,
        "actionlint" => 6,
        "zizmor" => 7,
        "gitleaks" => 8,
        "osv-scanner" => 9,
        "cargo-audit" => 10,
        "cargo-deny" => 11,
        "coverage" => 12,
        _ => 50,
    }
}

fn write_skipped_sensor_receipts(
    root: &Path,
    out: &Path,
    plan: &Plan,
    event_log: &EventLog,
) -> Result<()> {
    for sensor in plan.sensors.iter().filter(|sensor| !sensor.run) {
        let dir = out.join("sensors").join(&sensor.id);
        let argv = build_sensor_argv(root, &dir, sensor, plan);
        write_sensor_status(
            out,
            sensor,
            SensorStatusWrite {
                status: "skipped",
                argv: &argv,
                duration_ms: 0,
                reason: &sensor.reason,
                exit_code: None,
                timed_out: false,
            },
        )?;
        event_log.append(
            "sensor_skipped",
            serde_json::json!({"sensor": sensor.id, "reason": sensor.reason}),
        )?;
    }
    Ok(())
}

fn write_dry_run_sensor_receipts(
    root: &Path,
    out: &Path,
    plan: &Plan,
    event_log: &EventLog,
) -> Result<()> {
    for sensor in &plan.sensors {
        let dir = out.join("sensors").join(&sensor.id);
        let argv = build_sensor_argv(root, &dir, sensor, plan);
        let reason = if sensor.run {
            "dry-run; sensor not executed"
        } else {
            &sensor.reason
        };
        write_sensor_status(
            out,
            sensor,
            SensorStatusWrite {
                status: "skipped",
                argv: &argv,
                duration_ms: 0,
                reason,
                exit_code: None,
                timed_out: false,
            },
        )?;
        event_log.append(
            "sensor_skipped",
            serde_json::json!({"sensor": sensor.id, "reason": reason}),
        )?;
    }
    Ok(())
}

fn absolute_path(path: &Path) -> PathBuf {
    if path.is_absolute() {
        path.to_path_buf()
    } else {
        std::env::current_dir()
            .unwrap_or_else(|_| PathBuf::from("."))
            .join(path)
    }
}

fn changed_paths_for_tokmd_context(root: &Path, plan: &Plan) -> Vec<String> {
    git_lines(
        root,
        &[
            "diff",
            "--name-only",
            &format!("{}...{}", plan.base, plan.head),
        ],
    )
    .or_else(|_| git_lines(root, &["diff", "--name-only", &plan.base, &plan.head]))
    .unwrap_or_default()
    .into_iter()
    .filter(|path| root.join(path).is_file())
    .take(40)
    .collect()
}

fn commands_json(commands: &[SensorSubcommand]) -> serde_json::Value {
    serde_json::Value::Array(
        commands
            .iter()
            .map(|command| {
                serde_json::json!({
                    "label": command.label,
                    "command": display_command(&command.argv),
                    "stdout": command.stdout_path.display().to_string(),
                    "stderr": command.stderr_path.display().to_string(),
                })
            })
            .collect(),
    )
}

fn append_file(path: &Path, text: &str) -> Result<()> {
    use std::io::Write as _;

    let mut file = OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)
        .with_context(|| format!("open {}", path.display()))?;
    file.write_all(text.as_bytes())?;
    Ok(())
}

fn append_existing_file(target: &Path, source: &Path) -> Result<()> {
    if !source.exists() {
        return Ok(());
    }
    let text = fs::read_to_string(source).unwrap_or_else(|_| String::new());
    if text.is_empty() {
        return Ok(());
    }
    append_file(target, &text)
}

fn run_command_to_files(
    root: &Path,
    argv: &[String],
    env: &BTreeMap<String, String>,
    timeout_sec: u64,
    stdout_path: &Path,
    stderr_path: &Path,
) -> Result<CommandStatus> {
    let Some((program, args)) = argv.split_first() else {
        bail!("empty command");
    };
    let stdout =
        File::create(stdout_path).with_context(|| format!("create {}", stdout_path.display()))?;
    let stderr =
        File::create(stderr_path).with_context(|| format!("create {}", stderr_path.display()))?;
    let started = Instant::now();
    let mut child = ProcessCommand::new(program)
        .args(args)
        .envs(env)
        .current_dir(root)
        .stdout(Stdio::from(stdout))
        .stderr(Stdio::from(stderr))
        .spawn()
        .with_context(|| format!("spawn {program}"))?;
    let status = match child.wait_timeout(Duration::from_secs(timeout_sec))? {
        Some(status) => status,
        None => {
            let _ = child.kill();
            let _ = child.wait();
            return Ok(CommandStatus {
                exit_code: None,
                timed_out: true,
                success: false,
                reason: format!("timed out after {timeout_sec}s"),
                duration_ms: started.elapsed().as_millis(),
            });
        }
    };
    Ok(CommandStatus {
        exit_code: status.code(),
        timed_out: false,
        success: status.success(),
        reason: if status.success() {
            "completed".to_owned()
        } else {
            format!("exit code {:?}", status.code())
        },
        duration_ms: started.elapsed().as_millis(),
    })
}

fn parse_lcov_count(value: &str) -> u64 {
    value.trim().parse().unwrap_or_default()
}

fn write_lane_packets(
    out: &Path,
    diff: &DiffContext,
    lanes: &[LanePlan],
    event_log: &EventLog,
) -> Result<()> {
    let lane_dir = out.join("lanes");
    fs::create_dir_all(&lane_dir)?;
    for lane in lanes {
        let mut text = String::new();
        text.push_str(&format!("# Lane: `{}`\n\n", lane.id));
        text.push_str(&format!("Model: `{}`\n\n", lane.model_display));
        text.push_str(&format!("Role: {}\n\n", lane.role));
        text.push_str("## Focus\n\n");
        text.push_str(&lane.focus);
        text.push_str("\n\n## Shared diff\n\n");
        text.push_str(&format!(
            "Base: `{}`\n\nHead: `{}`\n\n",
            diff.base, diff.head
        ));
        text.push_str("Changed files:\n\n");
        for file in &diff.changed_files {
            text.push_str(&format!("- `{file}`\n"));
        }
        text.push_str("\n## Routed sensor evidence\n\n");
        for sensor_id in &lane.receives {
            let sensor_dir = out.join("sensors").join(sensor_id);
            let status_path = sensor_dir.join("ub-review-sensor-status.json");
            let status = read_sensor_receipt(&status_path)
                .map(|receipt| receipt.status)
                .unwrap_or_else(|| "receipt-absent".to_owned());
            text.push_str(&format!("- `{sensor_id}`: `{status}`\n"));
            if sensor_id == "unsafe-review" {
                text.push_str(&render_unsafe_review_lane_evidence(&sensor_dir, &status));
            }
        }
        text.push_str("\n## Review posture\n\n");
        text.push_str(review_posture_for_diff_class(diff.diff_class));
        text.push_str("\n\n## Required output shape\n\n");
        text.push_str(&format!(
            "Start inline comments for this lane with `[{}]`. If no blocking finding exists, write an audit trail: what you checked, strongest failed objection, and residual risk. Do not infer safety from missing sensor receipts.\n",
            lane.id
        ));
        fs::write(lane_dir.join(format!("{}.md", lane.id)), text)?;
        event_log.append("lane_packet_written", serde_json::json!({"lane": lane.id}))?;
    }
    Ok(())
}

/// Build the structured evidence block for an unsafe-review sensor entry in a
/// lane packet.
///
/// When `unsafe-review-gate.json` is present and its schema_version matches
/// `UNSAFE_REVIEW_GATE_SCHEMA`, returns a Markdown block with the movement
/// summary and comment-plan entries (capped at 3, matching unsafe-review's own
/// bounded output). When the file is absent, the sensor failed, or the schema
/// is unrecognised, returns a note explaining the degradation so model lanes
/// never infer safety from silence.
///
/// Trust boundary is always surfaced: unsafe-review output is advisory only.
/// The deterministic floor (required-sensor gap logic) still gates; this
/// structured block is supplementary review context.
fn render_unsafe_review_lane_evidence(sensor_dir: &Path, status: &str) -> String {
    if status != "ok" {
        // Sensor did not succeed: no artifacts to read; nothing to add beyond
        // the status line already written by the caller.
        return String::new();
    }
    match read_unsafe_review_artifacts(sensor_dir) {
        None => {
            // The gate file is absent or has an unrecognised schema_version.
            let gate_path = sensor_dir
                .join(UNSAFE_REVIEW_OUTPUT_SUBDIR)
                .join("unsafe-review-gate.json");
            let reason = if gate_path.exists() {
                "unsafe-review-gate.json present but schema_version not recognised; \
                 structured evidence unavailable (schema routing degraded)"
            } else {
                "unsafe-review-gate.json absent; structured evidence unavailable"
            };
            format!("  - unsafe-review structured evidence: {reason}\n")
        }
        Some(artifacts) => {
            let gate = &artifacts.gate;
            let trust = gate.trust_boundary.as_deref().unwrap_or("advisory");
            let summary = &gate.summary;
            let mut block = String::new();
            block.push_str(&format!(
                "  - unsafe-review movement (trust_boundary: `{trust}`, advisory only): \
                 new_gaps={}, worsened={}, resolved={}, inherited={}\n",
                summary.new_gaps,
                summary.worsened_gaps,
                summary.resolved_gaps,
                summary.inherited_gaps
            ));
            if artifacts.comment_plan.is_empty() {
                block.push_str(
                    "  - unsafe-review comment-plan: absent or empty \
                     (no comment candidates for this diff)\n",
                );
            } else {
                block.push_str(&format!(
                    "  - unsafe-review comment-plan ({} candidate(s), advisory):\n",
                    artifacts.comment_plan.len()
                ));
                for entry in &artifacts.comment_plan {
                    let path = entry.path.as_deref().unwrap_or("(unknown path)");
                    let line = entry
                        .line
                        .map(|l| l.to_string())
                        .unwrap_or_else(|| "?".to_owned());
                    let gap = entry
                        .coverage_gap
                        .as_deref()
                        .unwrap_or("(no gap description)");
                    block.push_str(&format!("    - `{path}:{line}` — {gap}\n"));
                }
            }
            block
        }
    }
}

fn render_pr_packet(diff: &DiffContext) -> String {
    let mut text = String::new();
    text.push_str("# PR evidence packet\n\n");
    text.push_str(&format!(
        "Base: `{}`\n\nHead: `{}`\n\n",
        diff.base, diff.head
    ));
    text.push_str("## Changed files\n\n");
    for file in &diff.changed_files {
        text.push_str(&format!("- `{file}`\n"));
    }
    text.push_str("\n## Diff flags\n\n");
    text.push_str(&format!(
        "```json\n{}\n```\n",
        serde_json::to_string_pretty(&diff.flags).unwrap_or_else(|_| "{}".to_owned())
    ));
    text
}

fn render_claim_prompt(diff: &DiffContext) -> String {
    let mut text = String::new();
    text.push_str("# PR claims extraction prompt\n\n");
    text.push_str("No PR body is available in no-token GH runner mode. Treat claims as absent unless supplied by a separate artifact.\n\n");
    text.push_str(
        "Reviewers should verify only claims grounded in the diff and available artifacts.\n\n",
    );
    text.push_str("Changed files:\n\n");
    for file in &diff.changed_files {
        text.push_str(&format!("- `{file}`\n"));
    }
    text
}

#[expect(
    clippy::too_many_arguments,
    reason = "tracked in policy/allow.toml#clippy-too-many-arguments-artifact-writers"
)]
fn write_review_artifacts(
    root: &Path,
    out: &Path,
    config: &Config,
    diff: &DiffContext,
    box_state: &BoxState,
    plan: &Plan,
    tool_gate_outcomes: &[ToolGateOutcomeEntry],
    running_summary: &str,
    args: &RunArgs,
    event_log: &EventLog,
    run_started: &Instant,
    run_loop_tracker: &mut RunLoopTracker,
    elapsed: Duration,
) -> Result<GateOutcome> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir)?;
    let pr_thread_context = collect_pr_thread_context(root, args)?;
    let profile = config.selected_profile()?;
    let mut proof_requests = Vec::new();
    append_configured_required_proof_requests(config, diff, args, &mut proof_requests);
    let shared_context = render_shared_context(
        root,
        out,
        config,
        diff,
        plan,
        running_summary,
        args,
        &pr_thread_context,
        profile,
        &proof_requests,
    )?;
    fs::write(review_dir.join("shared_context.md"), &shared_context)?;
    fs::write(
        review_dir.join("pr_thread_context.json"),
        serde_json::to_vec_pretty(&pr_thread_context)?,
    )?;
    let shared_context_id = sha256_hex(shared_context.as_bytes());
    let line_map = right_side_diff_lines(&diff.patch);
    let assignments = model_assignments(plan, args)?;
    let mut provider_preflights = build_provider_preflight_receipts(&assignments, args);
    if should_run_proof_planner_model_lane(args, diff) {
        ensure_provider_preflight_receipt(
            &mut provider_preflights,
            direct_minimax_spec(args),
            args,
        );
    }
    write_shared_context_cache_artifacts(
        out,
        &shared_context,
        &assignments,
        &provider_preflights,
        &[],
        &[],
        args,
    )?;
    let mut model_lanes = build_model_lane_receipts(&assignments, args);
    let missing_or_failed_sensor_evidence = collect_sensor_evidence_issues(out, plan);
    let mut missing_or_failed_model_evidence = model_lanes
        .iter()
        .filter(|receipt| is_model_receipt_evidence_issue(receipt))
        .map(model_issue_from_receipt)
        .collect::<Vec<_>>();
    let mut summary_only_findings = Vec::new();
    let mut inline_comments = Vec::new();
    let mut model_observations = Vec::new();
    let mut issue_candidates: Vec<IssueCandidate> = Vec::new();
    let mut model_calls_used = 0usize;
    let seeded_proof_requests = proof_requests.clone();

    let mut proof_result = ProofBrokerResult::default();
    if matches!(args.model_mode, ModelMode::Auto) {
        let initial_proof_loop = start_run_loop(
            event_log,
            run_started,
            "proof",
            "proof",
            "initial-diff-broker",
        )?;
        thread::scope(|scope| -> Result<()> {
            let proof_handle = scope.spawn(move || {
                run_seeded_proof_stream_v0(
                    root,
                    out,
                    diff,
                    profile,
                    args,
                    &seeded_proof_requests,
                    initial_proof_loop,
                    event_log,
                    run_started,
                )
            });

            let model_loop =
                start_run_loop(event_log, run_started, "model", "investigation", "primary")?;
            run_provider_preflights(
                root,
                &review_dir,
                &mut provider_preflights,
                &shared_context,
                args,
            )?;
            append_preflight_evidence_issues(
                &provider_preflights,
                &mut missing_or_failed_model_evidence,
            );
            model_calls_used = run_available_model_lanes(
                ModelRunContext {
                    root,
                    review_dir: &review_dir,
                    assignments: &assignments,
                    provider_preflights: &provider_preflights,
                    shared_context: &shared_context,
                    args,
                    line_map: &line_map,
                    key_present: env_value_present,
                },
                &mut model_lanes,
                &mut missing_or_failed_model_evidence,
                &mut inline_comments,
                &mut summary_only_findings,
                &mut model_observations,
                &mut proof_requests,
                &mut issue_candidates,
            )?;
            dedupe_inline_comments(&mut inline_comments, &mut summary_only_findings);
            model_calls_used += run_proof_planner_model_lane(
                ProofPlannerRunContext {
                    root,
                    review_dir: &review_dir,
                    provider_preflights: &provider_preflights,
                    shared_context: &shared_context,
                    args,
                    diff,
                    profile,
                    box_state,
                    pr_thread_context: &pr_thread_context,
                    model_calls_used,
                    line_map: &line_map,
                },
                &mut model_lanes,
                &mut missing_or_failed_model_evidence,
                &mut model_observations,
                &mut proof_requests,
            )?;
            model_calls_used += run_refuter_pass(
                RefuterRunContext {
                    root,
                    review_dir: &review_dir,
                    provider_preflights: &provider_preflights,
                    shared_context: &shared_context,
                    args,
                    model_calls_used,
                },
                &mut model_lanes,
                &mut missing_or_failed_model_evidence,
                &mut inline_comments,
                &mut summary_only_findings,
            )?;
            finish_run_loop(
                event_log,
                run_started,
                run_loop_tracker,
                model_loop,
                "completed",
            )?;

            let (seeded_result, proof_phases) = proof_handle
                .join()
                .map_err(|_| anyhow::anyhow!("seeded proof stream thread panicked"))??;
            for phase in proof_phases {
                run_loop_tracker.record(phase);
            }
            proof_result = seeded_result;
            Ok(())
        })?;
    } else {
        let model_loop =
            start_run_loop(event_log, run_started, "model", "investigation", "primary")?;
        finish_run_loop(
            event_log,
            run_started,
            run_loop_tracker,
            model_loop,
            "skipped_model_mode_off",
        )?;
        let initial_proof_loop = start_run_loop(
            event_log,
            run_started,
            "proof",
            "proof",
            "initial-diff-broker",
        )?;
        proof_result = run_initial_diff_proof_broker_v0(root, out, diff, profile, args)?;
        finish_run_loop(
            event_log,
            run_started,
            run_loop_tracker,
            initial_proof_loop,
            "completed",
        )?;
    }
    attach_request_metadata_to_focused_receipts(
        diff,
        &proof_requests,
        &mut proof_result.proof_receipts,
    );
    write_proof_planner_artifacts(
        out,
        diff,
        plan,
        profile,
        box_state,
        &pr_thread_context,
        &proof_requests,
    )?;
    if has_unreceipted_proof_request_tasks(&proof_requests, &proof_result.proof_receipts) {
        let request_proof_loop = start_run_loop(
            event_log,
            run_started,
            "proof",
            "proof",
            "model-request-broker",
        )?;
        let request_proof_result = run_request_proof_broker_v0(
            root,
            out,
            diff,
            profile,
            &proof_requests,
            &proof_result.proof_receipts,
            &proof_result.resource_leases,
            args,
        )?;
        proof_result
            .proof_receipts
            .extend(request_proof_result.proof_receipts);
        proof_result
            .resource_leases
            .extend(request_proof_result.resource_leases);
        finish_run_loop(
            event_log,
            run_started,
            run_loop_tracker,
            request_proof_loop,
            "completed",
        )?;
    }
    let proof_receipts = proof_result.proof_receipts;
    let resource_leases = proof_result.resource_leases;
    let compiler_loop = start_run_loop(
        event_log,
        run_started,
        "compiler",
        "coordination",
        "preliminary",
    )?;
    // Invariant (#314): candidates are built from the same inline-comment
    // and summary-finding values the final compile later filters through
    // `candidate_matches_inline_comment` / `candidate_matches_summary_finding`.
    // No dedupe, trim, or other normalization may run between this point and
    // that filter - the matchers compare exact fields, and a normalized
    // surface would fail the match OPEN, letting a refuted candidate post.
    // The verifier's negative self-test pins the closed loop from the other
    // side: a leaked refuted surface in final_compiler_input.json reds the
    // gate's verifier step.
    let candidates = build_candidate_records(&inline_comments, &summary_only_findings);
    write_candidate_artifacts(out, &candidates)?;
    let candidates = read_candidate_records(out)?;
    let (inline_comments, summary_only_findings) = read_candidate_review_surfaces(out)?;

    let run_pass = resolved_run_pass(args.run_pass);
    let preliminary_surface = compile_review_surface(ReviewCompilerInput {
        shared_context_id: &shared_context_id,
        review_body_policy: &config.review_body,
        run_pass,
        post_review_on: &config.gate.post_review_on,
        args,
        plan,
        diff,
        model_lanes: &model_lanes,
        missing_or_failed_sensor_evidence: &missing_or_failed_sensor_evidence,
        missing_or_failed_model_evidence: &missing_or_failed_model_evidence,
        inline_comments: &inline_comments,
        summary_only_findings: &summary_only_findings,
        observations: &model_observations,
        proof_receipts: &proof_receipts,
        final_follow_up_tasks: 0,
        suggested_issues: &[],
    })?;
    let mut review = ReviewArtifacts {
        shared_context_id,
        review_profile: config.review_profile.clone(),
        mode: args.mode.key().to_owned(),
        posting: args.posting.key().to_owned(),
        runtime_profile: profile.name.clone(),
        run_pass: run_pass.key().to_owned(),
        model_mode: args.model_mode.key().to_owned(),
        depth: args.depth.key().to_owned(),
        provider_policy: args.provider_policy.key().to_owned(),
        model_provider_policy: args.provider_policy.key().to_owned(),
        lane_width: args.lane_width,
        model_concurrency: args.model_concurrency,
        max_model_calls: args.max_model_calls,
        max_inline_comments: args.max_inline_comments,
        model_timeout_sec: args.model_timeout_sec,
        ledger_path: effective_ledger_path(config, args),
        ledger_max_bytes: args.ledger_max_bytes,
        pr_thread_context,
        terminal_state: preliminary_surface.terminal_state,
        provider_preflights,
        model_lanes,
        missing_or_failed_sensor_evidence,
        missing_or_failed_model_evidence,
        inline_comments,
        summary_only_findings,
        observations: model_observations,
        proof_requests,
        proof_receipts,
        resource_leases,
        body: preliminary_surface.artifact_body,
    };
    let observations = combined_observations(&review);
    let observation_summary = observation_summary_artifacts(&observations);
    let orchestrator_plan = build_orchestrator_plan(
        &candidates,
        &observation_summary.unique,
        &review.proof_receipts,
        &review.resource_leases,
    );
    write_observation_artifacts(out, &observations)?;
    write_orchestrator_artifacts(out, &orchestrator_plan, &review.proof_receipts)?;
    finish_run_loop(
        event_log,
        run_started,
        run_loop_tracker,
        compiler_loop,
        "completed",
    )?;
    let mut follow_up_results = Vec::new();
    let mut follow_up_outputs = Vec::new();
    let follow_up_model_loop = start_run_loop(
        event_log,
        run_started,
        "model",
        "investigation",
        "follow-up",
    )?;
    run_follow_up_model_pass(
        FollowUpRunContext {
            root,
            out,
            review_dir: &review_dir,
            provider_preflights: &review.provider_preflights,
            shared_context: &shared_context,
            args,
            model_calls_used,
            tasks: &orchestrator_plan.follow_up_tasks,
            line_map: &line_map,
        },
        &mut follow_up_results,
        &mut follow_up_outputs,
    )?;
    finish_run_loop(
        event_log,
        run_started,
        run_loop_tracker,
        follow_up_model_loop,
        "completed",
    )?;
    write_follow_up_result_artifacts(out, &follow_up_results)?;
    write_follow_up_output_artifacts(out, &follow_up_outputs)?;
    let resolved_candidates =
        resolved_candidate_records(&candidates, &follow_up_results, &follow_up_outputs);
    write_resolved_candidate_artifacts(out, &resolved_candidates)?;
    // The late receipt turn exists to change candidate dispositions, so the
    // final compiler must honor those changes: candidates the follow-up pass
    // resolved to `refuted` or `dropped` lose their review surface here.
    // The full audit trail stays in candidates.json, resolved_candidates.json,
    // and the follow-up artifacts. Candidates resolved to `parked-follow-up`
    // keep their surface — parked items render in the dedicated parked
    // section instead of disappearing.
    let resolved_away_candidate_ids = follow_up_resolved_away_candidate_ids(&resolved_candidates);
    let resolved_away_candidates = candidates
        .iter()
        .filter(|candidate| resolved_away_candidate_ids.contains(&candidate.id))
        .collect::<Vec<_>>();
    write_model_stage_artifacts(out, &review.model_lanes, &follow_up_results, args)?;
    write_shared_context_cache_artifacts(
        out,
        &shared_context,
        &assignments,
        &review.provider_preflights,
        &review.model_lanes,
        &follow_up_results,
        args,
    )?;
    let follow_up_evidence = follow_up_evidence_from_outputs(&follow_up_outputs);
    write_follow_up_evidence_artifact(out, &follow_up_evidence)?;
    append_follow_up_proof_requests(&mut review.proof_requests, &follow_up_evidence);
    let follow_up_proof_loop =
        start_run_loop(event_log, run_started, "proof", "proof", "follow-up-broker")?;
    let follow_up_proof_result = run_follow_up_proof_broker_v0(
        root,
        out,
        diff,
        profile,
        &follow_up_evidence.proof_requests,
        &review.proof_receipts,
        &review.resource_leases,
        args,
    )?;
    review
        .proof_receipts
        .extend(follow_up_proof_result.proof_receipts);
    review
        .resource_leases
        .extend(follow_up_proof_result.resource_leases);
    finish_run_loop(
        event_log,
        run_started,
        run_loop_tracker,
        follow_up_proof_loop,
        "completed",
    )?;
    let receipt_routes = receipt_route_artifacts(&review.proof_receipts, &review.resource_leases);
    write_receipt_route_artifacts(out, &receipt_routes)?;
    // Release lane step 4: lane-emitted follow-up candidates become the
    // issue-capture artifacts. v0 is artifact-only - no PR-body rendering,
    // no GitHub side effects; classification is the whole pipeline.
    let (issue_capture_candidates, issue_capture_actions) =
        classify_issue_candidates(&config.issues, std::mem::take(&mut issue_candidates));
    write_issue_capture_artifacts(out, &issue_capture_candidates, &issue_capture_actions)?;
    // Step 6: under open-high-confidence, `run` decides what the post-time
    // broker may attempt and renders the full issue text into a pure plan
    // artifact. `run` itself never opens issues.
    if config.issues.enabled && config.issues.mode == "open-high-confidence" {
        let broker_plan = build_issue_broker_plan(
            &config.issues,
            &issue_capture_candidates,
            &issue_capture_actions,
            args.github_repo.as_deref(),
            args.github_pull_number
                .or_else(detect_pull_number_from_event),
        );
        write_issue_broker_plan(out, &broker_plan)?;
    }
    let suggested_issue_ids = issue_capture_actions
        .iter()
        .filter(|action| action.action == "suggested")
        .map(|action| action.candidate_id.as_str())
        .collect::<BTreeSet<_>>();
    let suggested_issues = issue_capture_candidates
        .iter()
        .filter(|candidate| suggested_issue_ids.contains(candidate.id.as_str()))
        .cloned()
        .collect::<Vec<_>>();
    let final_orchestrator_plan = build_final_orchestrator_plan(
        &candidates,
        &observation_summary.unique,
        &review.proof_receipts,
        &review.resource_leases,
    );
    write_final_orchestrator_artifact(out, &final_orchestrator_plan)?;
    let final_compiler_loop =
        start_run_loop(event_log, run_started, "compiler", "coordination", "final")?;
    let compiler_inline_comments = review
        .inline_comments
        .iter()
        .filter(|comment| {
            !resolved_away_candidates
                .iter()
                .any(|candidate| candidate_matches_inline_comment(candidate, comment))
        })
        .cloned()
        .collect::<Vec<_>>();
    let mut compiler_summary_only_findings = review.summary_only_findings.clone();
    compiler_summary_only_findings.retain(|finding| {
        !resolved_away_candidates
            .iter()
            .any(|candidate| candidate_matches_summary_finding(candidate, finding))
    });
    compiler_summary_only_findings.extend(follow_up_evidence.summary_only_findings.clone());
    let mut compiler_observations = review.observations.clone();
    compiler_observations.extend(follow_up_evidence.observations.clone());
    write_final_compiler_input_artifact(
        out,
        FinalCompilerInputArtifact {
            schema: FINAL_COMPILER_INPUT_V2_SCHEMA,
            phase: "final",
            source_artifacts: &[
                "review/review.json",
                "review/follow_up_evidence.json",
                "review/resolved_candidates.json",
                "review/proof_receipts.json",
                "review/receipt_routes.json",
                "review/final_orchestrator_plan.json",
            ],
            model_lanes: &review.model_lanes,
            missing_or_failed_sensor_evidence: &review.missing_or_failed_sensor_evidence,
            missing_or_failed_model_evidence: &review.missing_or_failed_model_evidence,
            follow_up_resolved_candidate_ids: &resolved_away_candidate_ids,
            inline_comments: &compiler_inline_comments,
            summary_only_findings: &compiler_summary_only_findings,
            observations: &compiler_observations,
            proof_receipts: &review.proof_receipts,
        },
    )?;
    let final_surface = compile_review_surface(ReviewCompilerInput {
        shared_context_id: &review.shared_context_id,
        review_body_policy: &config.review_body,
        run_pass,
        post_review_on: &config.gate.post_review_on,
        args,
        plan,
        diff,
        model_lanes: &review.model_lanes,
        missing_or_failed_sensor_evidence: &review.missing_or_failed_sensor_evidence,
        missing_or_failed_model_evidence: &review.missing_or_failed_model_evidence,
        inline_comments: &compiler_inline_comments,
        summary_only_findings: &compiler_summary_only_findings,
        observations: &compiler_observations,
        proof_receipts: &review.proof_receipts,
        suggested_issues: &suggested_issues,
        final_follow_up_tasks: final_orchestrator_plan.follow_up_tasks.len(),
    })?;
    let review_payload_status = final_surface.review_payload_status;
    let should_prepare_github_review = final_surface.should_prepare_github_review;
    let summary_only_policy_posted = final_surface.summary_only_policy_posted;
    let mut github_review = final_surface.github_review;
    let artifact_body = final_surface.artifact_body;
    // Inject unsafe-review comment-plan entries as inline review comments (#360).
    // These are appended after the final model-lane surface so the grouped
    // review body is unaffected. Only `changed_line: true` entries are eligible
    // (GitHub API requirement). Dedup against already-present comments prevents
    // double-posting on any path:line pair claimed by a model lane. Advisory
    // only — they never change the deterministic merge gate.
    if should_prepare_github_review {
        let unsafe_review_sensor_dir = out.join("sensors").join("unsafe-review");
        let existing: std::collections::BTreeSet<(String, u32)> = github_review
            .comments
            .iter()
            .map(|c| (normalize_repo_path(&c.path), c.line))
            .collect();
        let extra = build_unsafe_review_inline_comments(
            &unsafe_review_sensor_dir,
            &existing,
            args.max_inline_comments
                .saturating_sub(github_review.comments.len()),
        );
        github_review.comments.extend(extra);
    }
    let terminal_state = final_surface.terminal_state;
    review.terminal_state = terminal_state.clone();
    review.body = artifact_body.clone();
    let mut witnesses = build_witness_records(
        &review.inline_comments,
        &review.summary_only_findings,
        &observations,
        &review.proof_receipts,
    );
    append_follow_up_evidence_witnesses(
        &mut witnesses,
        &follow_up_evidence,
        &review.proof_receipts,
    );
    write_witness_artifacts(out, &witnesses)?;
    write_proof_receipt_artifacts(out, &review.proof_receipts)?;
    write_resource_lease_artifacts(out, &review.resource_leases)?;
    write_proof_request_artifacts(
        out,
        diff,
        profile,
        &review.proof_requests,
        &review.proof_receipts,
    )?;
    finish_run_loop(
        event_log,
        run_started,
        run_loop_tracker,
        final_compiler_loop,
        "completed",
    )?;
    event_log.append(
        "terminal_state",
        serde_json::json!({
            "status": review.terminal_state.status,
            "review_payload_status": review.terminal_state.review_payload_status,
        }),
    )?;
    let run_loop_metrics = run_loop_tracker.metrics();
    let metrics = build_review_metrics(ReviewMetricsInput {
        out,
        diff,
        plan,
        review: &review,
        github_review: if should_prepare_github_review {
            Some(&github_review)
        } else {
            None
        },
        review_payload_status,
        observations_count: observations.len(),
        follow_up_results: &follow_up_results,
        final_follow_up_tasks: final_orchestrator_plan.follow_up_tasks.len(),
        run: run_loop_metrics,
        elapsed,
    });

    fs::write(
        review_dir.join("review.json"),
        serde_json::to_vec_pretty(&review)?,
    )?;
    fs::write(
        review_dir.join("metrics.json"),
        serde_json::to_vec_pretty(&metrics)?,
    )?;
    write_scheduler_artifact(&review_dir, &metrics.run)?;
    fs::write(
        review_dir.join("terminal_state.json"),
        serde_json::to_vec_pretty(&review.terminal_state)?,
    )?;
    let gate_outcome = build_gate_outcome(GateOutcomeInput {
        args,
        config,
        plan,
        terminal_state: &review.terminal_state,
        proof_requests: &review.proof_requests,
        proof_receipts: &review.proof_receipts,
        tool_gate_outcomes,
        missing_or_failed_sensor_evidence: &review.missing_or_failed_sensor_evidence,
        missing_or_failed_model_evidence: &review.missing_or_failed_model_evidence,
    });
    fs::write(
        review_dir.join("gate_outcome.json"),
        serde_json::to_vec_pretty(&gate_outcome)?,
    )?;
    event_log.append(
        "gate_outcome",
        serde_json::json!({
            "conclusion": gate_outcome.conclusion,
            "terminal_status": gate_outcome.terminal_status,
            "reasons": gate_outcome.reasons.len(),
            "fail_on_gate": args.fail_on_gate.key(),
            "fail_on_gate_resolved": args.fail_on_gate.resolved(args.mode),
        }),
    )?;
    fs::write(
        review_dir.join("provider-preflight-status.json"),
        serde_json::to_vec_pretty(&review.provider_preflights)?,
    )?;
    fs::write(review_dir.join("review.md"), artifact_body)?;
    if should_prepare_github_review {
        write_github_review_payload(
            &review_dir,
            &github_review,
            &line_map,
            &config.review_body,
            summary_only_policy_posted,
        )?;
    } else {
        write_github_review_skip_receipt(
            &review_dir,
            build_github_review_skip_receipt(args, &review, config.review_body.summary_only_body),
        )?;
    }
    Ok(gate_outcome)
}

fn should_prepare_github_review_payload(
    args: &RunArgs,
    inline_comments: &[ReviewInlineComment],
    _summary_only_findings: &[SummaryOnlyFinding],
    proof_receipts: &[ProofReceipt],
    pr_body: &str,
) -> bool {
    if matches!(args.model_mode, ModelMode::Off) {
        return false;
    }
    if has_reviewer_value(inline_comments, pr_body) {
        return true;
    }
    if proof_receipts
        .iter()
        .any(proof_receipt_changes_review_value)
    {
        return true;
    }
    pr_body_has_reviewer_value(pr_body)
}

fn pr_body_has_reviewer_value(body: &str) -> bool {
    [
        "## Confirmed findings",
        "## Findings",
        "## Verification questions",
        "## Test proof",
        "## Proof results",
        "## Refuted",
        "## Parked follow-ups",
        "## Suggested follow-up",
        "## Evidence gaps",
        "## Missing evidence",
    ]
    .iter()
    .any(|heading| body.contains(heading))
}

struct ReviewCompilerInput<'a> {
    shared_context_id: &'a str,
    review_body_policy: &'a ReviewBodyPolicy,
    /// Resolved run pass (never `RunPass::Auto` from the run flow).
    run_pass: RunPass,
    /// `[gate].post_review_on` event actions from the selected profile.
    post_review_on: &'a [String],
    args: &'a RunArgs,
    plan: &'a Plan,
    diff: &'a DiffContext,
    model_lanes: &'a [ModelLaneReceipt],
    missing_or_failed_sensor_evidence: &'a [SensorEvidenceIssue],
    missing_or_failed_model_evidence: &'a [ModelEvidenceIssue],
    inline_comments: &'a [ReviewInlineComment],
    summary_only_findings: &'a [SummaryOnlyFinding],
    observations: &'a [Observation],
    proof_receipts: &'a [ProofReceipt],
    /// Issue candidates the action ledger marked `suggested` (release lane
    /// step 5): rendered as a follow-up section, never blocking.
    suggested_issues: &'a [IssueCandidate],
    final_follow_up_tasks: usize,
}

#[derive(Debug, Serialize)]
struct FinalCompilerInputArtifact<'a> {
    schema: &'static str,
    phase: &'static str,
    source_artifacts: &'static [&'static str],
    model_lanes: &'a [ModelLaneReceipt],
    missing_or_failed_sensor_evidence: &'a [SensorEvidenceIssue],
    missing_or_failed_model_evidence: &'a [ModelEvidenceIssue],
    /// Candidates the follow-up pass resolved to `refuted` or `dropped`;
    /// their original review surfaces are excluded from `inline_comments`
    /// and `summary_only_findings` below (v2 contract).
    follow_up_resolved_candidate_ids: &'a [String],
    inline_comments: &'a [ReviewInlineComment],
    summary_only_findings: &'a [SummaryOnlyFinding],
    observations: &'a [Observation],
    proof_receipts: &'a [ProofReceipt],
}

struct CompiledReviewSurface {
    artifact_body: String,
    github_review: GitHubReview,
    should_prepare_github_review: bool,
    /// True when `[review_body].summary_only_body` posted a body the
    /// suppressor classified as no-value boilerplate; the payload writer
    /// waives the suppressible body-policy checks for exactly this case.
    summary_only_policy_posted: bool,
    review_payload_status: &'static str,
    terminal_state: ReviewTerminalState,
}

/// Pass-level posting policy: when the resolved posting mode is `review`, a
/// pass may carry the grouped PR review only if the profile's
/// `[gate].post_review_on` lists its `pull_request` event action. Manual runs
/// (workflow_dispatch/local) are explicit operator requests and are not gated;
/// catch-all `pull_request_other` passes never post. Artifact-only runs keep
/// preparing the payload artifact because nothing is posted from them.
fn pass_policy_permits_review_post(
    posting: PostingMode,
    run_pass: RunPass,
    post_review_on: &[String],
) -> bool {
    if !matches!(posting, PostingMode::Review) {
        return true;
    }
    match run_pass.event_action() {
        Some(action) => post_review_on.iter().any(|allowed| allowed == action),
        // Only an explicit operator request (`manual`) bypasses the profile
        // pass list. `Auto` must be resolved before compilation; if it leaks
        // here, denying the post is the safe failure (gate inline finding on
        // run 27053765285: an Auto leak would post on every profile).
        None => matches!(run_pass, RunPass::Manual),
    }
}

fn compile_review_surface(input: ReviewCompilerInput<'_>) -> Result<CompiledReviewSurface> {
    let artifact_body = render_review_body(
        input.shared_context_id,
        input.plan,
        input.diff,
        input.model_lanes,
        input.missing_or_failed_sensor_evidence,
        input.missing_or_failed_model_evidence,
        input.inline_comments,
        input.summary_only_findings,
        input.observations,
        input.proof_receipts,
        input.args.review_body_max_bytes,
        ReviewBodyAudience::Artifact,
    );
    let mut pr_body = render_review_body(
        input.shared_context_id,
        input.plan,
        input.diff,
        input.model_lanes,
        input.missing_or_failed_sensor_evidence,
        input.missing_or_failed_model_evidence,
        input.inline_comments,
        input.summary_only_findings,
        input.observations,
        input.proof_receipts,
        input.args.review_body_max_bytes,
        ReviewBodyAudience::PullRequest,
    );
    // Release lane step 5: suggested follow-ups render last - they explain
    // why the PR's scope was not broadened, never block, and only appear
    // when the action ledger promoted a candidate to `suggested`. The full
    // draft (plan + acceptance) lives in review/suggested_issues.md.
    if !input.suggested_issues.is_empty() {
        let mut section = String::from(
            "
## Suggested follow-up

",
        );
        for candidate in input.suggested_issues {
            section.push_str(&format!(
                "- {} (`{}`). {} Plan and acceptance criteria: review/suggested_issues.md.
",
                escape_md(&candidate.title),
                candidate.target_repo,
                escape_md(&candidate.why_not_this_pr)
            ));
        }
        if pr_body.is_empty() {
            // A suggested follow-up is reviewer value on its own: it tells
            // the reviewer why this PR stays small.
            pr_body = section.trim_start().to_owned();
        } else {
            pr_body.push_str(&section);
        }
        pr_body = cap_review_body(pr_body.clone(), input.args.review_body_max_bytes);
    }
    let substantive_summary_only_findings =
        count_substantive_summary_only_findings(input.summary_only_findings);
    let mut suppressed_artifact_only_pr_body = false;
    let mut summary_only_policy_posted = false;
    if let Err(err) = validate_pr_review_body_policy(&pr_body, input.review_body_policy) {
        if !is_suppressible_pr_body_policy_error(&err) {
            return Err(err).with_context(|| "validate pull request review body policy");
        }
        if !matches!(input.args.model_mode, ModelMode::Off)
            && summary_only_body_policy_permits_post(
                input.review_body_policy.summary_only_body,
                input.summary_only_findings.len(),
                substantive_summary_only_findings,
            )
        {
            // The configured [review_body].summary_only_body posture posts
            // this body despite the suppressible classification. Everything
            // outside the suppressible classes must still hold; rendered PR
            // bodies never carry those sections, so a failure here means a
            // body-construction bug, not reviewer content worth withholding.
            validate_pr_review_body_policy_with_waiver(&pr_body, input.review_body_policy, true)
                .with_context(
                    || "validate pull request review body policy under summary_only_body waiver",
                )?;
            summary_only_policy_posted = true;
        } else {
            pr_body.clear();
            suppressed_artifact_only_pr_body = true;
        }
    }
    let pr_inline_comments: &[ReviewInlineComment] = if suppressed_artifact_only_pr_body {
        &[]
    } else {
        input.inline_comments
    };
    let github_review = GitHubReview {
        event: "COMMENT".to_owned(),
        body: pr_body.clone(),
        comments: pr_inline_comments
            .iter()
            .map(|comment| GitHubReviewComment {
                path: comment.path.clone(),
                line: comment.line,
                side: comment.side.clone(),
                body: comment.body.clone(),
                suggestion: None,
            })
            .collect(),
    };
    let pass_policy_permits_post =
        pass_policy_permits_review_post(input.args.posting, input.run_pass, input.post_review_on);
    let should_prepare_github_review = pass_policy_permits_post
        && !suppressed_artifact_only_pr_body
        && (summary_only_policy_posted
            || should_prepare_github_review_payload(
                input.args,
                pr_inline_comments,
                input.summary_only_findings,
                input.proof_receipts,
                &pr_body,
            ));
    let review_payload_status = if should_prepare_github_review {
        "prepared"
    } else if !pass_policy_permits_post {
        "skipped_pass_policy"
    } else if suppressed_artifact_only_pr_body {
        "skipped_artifact_only_body"
    } else {
        "skipped_empty_smoke"
    };
    let terminal_state = build_review_terminal_state(TerminalStateInput {
        args: input.args,
        plan: input.plan,
        run_pass: input.run_pass,
        review_payload_status,
        should_prepare_github_review,
        pr_body: &pr_body,
        inline_comments: pr_inline_comments,
        summary_only_findings: input.summary_only_findings,
        summary_only_body: input.review_body_policy.summary_only_body,
        model_lanes: input.model_lanes,
        missing_or_failed_sensor_evidence: input.missing_or_failed_sensor_evidence,
        missing_or_failed_model_evidence: input.missing_or_failed_model_evidence,
        proof_receipts: input.proof_receipts,
        final_follow_up_tasks: input.final_follow_up_tasks,
    });
    Ok(CompiledReviewSurface {
        artifact_body,
        github_review,
        should_prepare_github_review,
        summary_only_policy_posted,
        review_payload_status,
        terminal_state,
    })
}

/// A summary-only finding is substantive when it carries reviewer-relevant
/// weight on its own: severity medium or higher, or confidence medium-high or
/// higher. Pure lane-status and guardrail notes
/// (`is_pr_body_artifact_only_finding`) are never substantive regardless of
/// the severity/confidence they record.
fn summary_only_finding_is_substantive(finding: &SummaryOnlyFinding) -> bool {
    if is_pr_body_artifact_only_finding(finding) {
        return false;
    }
    matches!(finding.severity.as_str(), "blocker" | "high" | "medium")
        || matches!(finding.confidence.as_str(), "high" | "medium-high")
}

fn count_substantive_summary_only_findings(findings: &[SummaryOnlyFinding]) -> usize {
    findings
        .iter()
        .filter(|finding| summary_only_finding_is_substantive(finding))
        .count()
}

/// `[review_body].summary_only_body` decision for a PR body the suppressor
/// classified as no-value boilerplate: `suppress` always withholds,
/// `post_substantive` posts when at least one summary-only finding is
/// substantive, `post_all` posts whenever any summary-only finding exists.
fn summary_only_body_policy_permits_post(
    policy: SummaryOnlyBodyPolicy,
    summary_only_findings: usize,
    substantive_summary_only_findings: usize,
) -> bool {
    match policy {
        SummaryOnlyBodyPolicy::Suppress => false,
        SummaryOnlyBodyPolicy::PostSubstantive => substantive_summary_only_findings > 0,
        SummaryOnlyBodyPolicy::PostAll => summary_only_findings > 0,
    }
}

const MAX_PR_REVIEW_BODY_BYTES: usize = 6_000;
const MAX_PR_REVIEW_BODY_BULLETS: usize = 12;

fn is_suppressible_pr_body_policy_error(error: &anyhow::Error) -> bool {
    let text = error.to_string();
    text.contains("artifact-only boilerplate")
        || text.contains("refuted-only artifact note")
        || text.contains("not concise enough")
}

fn validate_pr_review_body_policy(body: &str, policy: &ReviewBodyPolicy) -> Result<()> {
    validate_pr_review_body_policy_with_waiver(body, policy, false)
}

/// Body-policy validation with an optional waiver for the suppressible
/// classes (`is_suppressible_pr_body_policy_error`: conciseness, artifact-only
/// boilerplate, refuted-only note). The waiver exists for exactly one caller
/// posture: `[review_body].summary_only_body` decided to post a body the
/// suppressor would have withheld. The non-suppressible checks (lane,
/// provider, and sensor tables plus the execution summary) always run.
fn validate_pr_review_body_policy_with_waiver(
    body: &str,
    policy: &ReviewBodyPolicy,
    waive_suppressible: bool,
) -> Result<()> {
    let trimmed = body.trim();
    if trimmed.is_empty() {
        return Ok(());
    }
    if !waive_suppressible {
        if trimmed.len() > MAX_PR_REVIEW_BODY_BYTES {
            bail!(
                "github review body is not concise enough: {} bytes over max {}",
                trimmed.len(),
                MAX_PR_REVIEW_BODY_BYTES
            );
        }
        let bullet_count = pr_body_bullet_count(trimmed);
        if bullet_count > MAX_PR_REVIEW_BODY_BULLETS {
            bail!(
                "github review body is not concise enough: {bullet_count} bullets over max {MAX_PR_REVIEW_BODY_BULLETS}"
            );
        }
        if has_forbidden_pr_review_boilerplate(trimmed) {
            bail!("github review body contains artifact-only boilerplate");
        }
        if is_refuted_only_pr_body(trimmed) {
            bail!("github review body contains refuted-only artifact note");
        }
    }
    if !policy.include_successful_lane_table && contains_successful_lane_table(trimmed) {
        bail!("github review body contains successful lane table");
    }
    match policy.include_provider_table {
        ReviewBodyTablePolicy::Always => {}
        ReviewBodyTablePolicy::Never | ReviewBodyTablePolicy::OnFailure => {
            if contains_provider_status_table(trimmed) {
                bail!("github review body contains provider status table");
            }
        }
    }
    match policy.include_sensor_table {
        ReviewBodyTablePolicy::Always => {}
        ReviewBodyTablePolicy::Never | ReviewBodyTablePolicy::OnFailure => {
            if contains_sensor_status_table(trimmed) {
                bail!("github review body contains sensor status table");
            }
        }
    }
    match policy.include_execution_summary {
        ReviewBodyExecutionSummaryPolicy::Always => {}
        ReviewBodyExecutionSummaryPolicy::None => {
            if contains_execution_summary(trimmed) {
                bail!("github review body contains execution summary");
            }
        }
        ReviewBodyExecutionSummaryPolicy::OnFailure => {
            if contains_execution_summary(trimmed) && !pr_body_has_failure_context(trimmed) {
                bail!("github review body contains success execution summary");
            }
        }
    }
    Ok(())
}

fn pr_body_bullet_count(body: &str) -> usize {
    body.lines()
        .filter(|line| {
            let line = line.trim_start();
            line.starts_with("- ") || line.starts_with("* ")
        })
        .count()
}

fn has_forbidden_pr_review_boilerplate(body: &str) -> bool {
    let lower = body.to_ascii_lowercase();
    is_workflow_trust_posture_review_noise(&lower)
        || [
            "no blocking finding after",
            "no blocking ub finding",
            "no actionable findings",
            "a human should still inspect",
            "human should still review",
            "residual risk remains for human review",
            "bounded review",
            "## residual risk",
            "cached prior observation",
            "refuter demoted inline candidate",
            "gate proof is pending",
            "cannot perform from cached context",
            "commit-existence/ancestry proof",
            "upstream commit-existence",
            "general bot output",
            "pr-body contract hardening",
            "actionlint ran ok",
            "lane transcript",
            "lane roster",
            "model lane roster",
            "raw observations",
            "provider preflight",
            "provider status",
            "sensor status",
            "shared context hash",
            "cache manifest",
            "runtime profile",
            "review payload status",
            "terminal state",
            "github-review-skip",
        ]
        .iter()
        .any(|needle| lower.contains(needle))
}

fn is_refuted_only_pr_body(body: &str) -> bool {
    let lower = body.to_ascii_lowercase();
    lower.contains("## refuted")
        && ![
            "## decision",
            "## confirmed findings",
            "## verification questions",
            "## test proof",
            "## proof results",
            "## parked follow-ups",
            "## evidence gaps",
            "## missing evidence",
        ]
        .iter()
        .any(|heading| lower.contains(heading))
}

fn contains_successful_lane_table(body: &str) -> bool {
    [
        "## Model lanes",
        "## Model lane status",
        "## Lane status",
        "## Lane roster",
    ]
    .iter()
    .any(|needle| body.contains(needle))
}

fn contains_provider_status_table(body: &str) -> bool {
    [
        "## Provider preflights",
        "## Provider status",
        "## Model provider status",
    ]
    .iter()
    .any(|needle| body.contains(needle))
}

fn contains_sensor_status_table(body: &str) -> bool {
    ["## Sensors", "## Sensor status", "## Sensor receipts"]
        .iter()
        .any(|needle| body.contains(needle))
}

fn contains_execution_summary(body: &str) -> bool {
    [
        "- Shared context:",
        "- Profile:",
        "- Base:",
        "- Head:",
        "- Changed files:",
        "- Inline comments:",
        "## Review efficiency",
        "Runtime:",
        "Terminal state:",
        "Review payload:",
        "Follow-up results:",
    ]
    .iter()
    .any(|needle| body.contains(needle))
}

fn pr_body_has_failure_context(body: &str) -> bool {
    [
        "## Decision",
        "## Evidence gaps",
        "## Missing evidence",
        "## Missing or failed evidence",
        "Needs ",
        "failed",
        "timed out",
        "unavailable",
    ]
    .iter()
    .any(|needle| body.contains(needle))
}

struct TerminalStateInput<'a> {
    args: &'a RunArgs,
    plan: &'a Plan,
    run_pass: RunPass,
    review_payload_status: &'a str,
    should_prepare_github_review: bool,
    pr_body: &'a str,
    inline_comments: &'a [ReviewInlineComment],
    summary_only_findings: &'a [SummaryOnlyFinding],
    summary_only_body: SummaryOnlyBodyPolicy,
    model_lanes: &'a [ModelLaneReceipt],
    missing_or_failed_sensor_evidence: &'a [SensorEvidenceIssue],
    missing_or_failed_model_evidence: &'a [ModelEvidenceIssue],
    proof_receipts: &'a [ProofReceipt],
    final_follow_up_tasks: usize,
}

fn build_review_terminal_state(input: TerminalStateInput<'_>) -> ReviewTerminalState {
    let substantive_summary_only_findings =
        count_substantive_summary_only_findings(input.summary_only_findings);
    let usable_model_lanes = input
        .model_lanes
        .iter()
        .filter(|receipt| model_lane_is_usable_for_terminal_state(receipt))
        .count();
    let evidence_gaps = input.missing_or_failed_sensor_evidence.len()
        + input.missing_or_failed_model_evidence.len();
    let reviewer_value_present = input.should_prepare_github_review
        || has_reviewer_value(input.inline_comments, input.pr_body)
        || input
            .proof_receipts
            .iter()
            .any(proof_receipt_changes_review_value);

    let (status, reason) = if reviewer_value_present {
        let reason = if input.should_prepare_github_review {
            "Reviewer-value content survived compilation; a grouped PR review was prepared."
                .to_owned()
        } else if input.review_payload_status == "skipped_pass_policy" {
            format!(
                "Reviewer-value content survived compilation, but pass `{}` is not in [gate].post_review_on; diagnostics remain in artifacts.",
                input.run_pass.key()
            )
        } else {
            format!(
                "Reviewer-value content survived compilation, but summary_only_body = `{}` withheld the PR-facing payload as no-value boilerplate: {} summary-only findings, {} substantive; diagnostics remain in artifacts.",
                input.summary_only_body.key(),
                input.summary_only_findings.len(),
                substantive_summary_only_findings
            )
        };
        ("needs-reviewer-attention", reason)
    } else if input.args.dry_run {
        (
            "artifact-only",
            "Dry run requested; this run produced artifacts but no reviewer-facing review."
                .to_owned(),
        )
    } else if matches!(input.args.mode, RunMode::IntelligentCi)
        && has_required_sensor_evidence_gap(input.plan, input.missing_or_failed_sensor_evidence)
    {
        (
            "failed-to-review",
            "A required intelligent-ci sensor was missing, skipped, failed, or timed out, so the gate did not reach a sufficient review state.".to_owned(),
        )
    } else if matches!(input.args.model_mode, ModelMode::Off) {
        (
            "artifact-only",
            "Model mode was off; this run produced artifacts but no reviewer-facing review."
                .to_owned(),
        )
    } else if input.plan.diff_class == DiffClass::ArtifactOnlySmoke {
        (
            "artifact-only",
            "Artifact-only smoke diff; diagnostics remain in artifacts and no PR review was prepared.".to_owned(),
        )
    } else if usable_model_lanes == 0 && input.proof_receipts.is_empty() {
        (
            "failed-to-review",
            "No usable model lane or proof receipt was available, so the run did not reach a sufficient review state.".to_owned(),
        )
    } else {
        (
            "sufficient",
            "No reviewer-value content survived compilation; the run reached a sufficient terminal state and stayed artifact-only.".to_owned(),
        )
    };

    ReviewTerminalState {
        schema: TERMINAL_STATE_SCHEMA.to_owned(),
        status: status.to_owned(),
        reason,
        review_payload_status: input.review_payload_status.to_owned(),
        reviewer_value_present,
        diff_class: input.plan.diff_class.key().to_owned(),
        model_mode: input.args.model_mode.key().to_owned(),
        usable_model_lanes,
        model_lanes: input.model_lanes.len(),
        evidence_gaps,
        proof_receipts: input.proof_receipts.len(),
        final_follow_up_tasks: input.final_follow_up_tasks,
        inline_comments: input.inline_comments.len(),
        summary_only_findings: input.summary_only_findings.len(),
        substantive_summary_only_findings,
    }
}

/// Shared predicate for gate blocking and terminal-state routing: a sensor
/// evidence issue is blocking material only when the plan marks that sensor as
/// required. Keeping one helper prevents the two call sites from drifting.
fn sensor_issue_is_required(plan: &Plan, issue: &SensorEvidenceIssue) -> bool {
    plan.sensors
        .iter()
        .any(|sensor| sensor.id == issue.sensor && sensor.required)
}

fn has_required_sensor_evidence_gap(plan: &Plan, issues: &[SensorEvidenceIssue]) -> bool {
    issues
        .iter()
        .any(|issue| sensor_issue_is_required(plan, issue))
}

fn model_lane_is_usable_for_terminal_state(receipt: &ModelLaneReceipt) -> bool {
    matches!(receipt.status.as_str(), "ok" | "degraded")
}

fn write_github_review_payload(
    review_dir: &Path,
    github_review: &GitHubReview,
    right_lines: &BTreeSet<(String, u32)>,
    review_body_policy: &ReviewBodyPolicy,
    waive_suppressible_body_policy: bool,
) -> Result<()> {
    validate_github_review_payload_for_right_lines(
        github_review,
        right_lines,
        "generated diff context",
        review_body_policy,
        waive_suppressible_body_policy,
    )?;
    fs::write(
        review_dir.join("github-review.json"),
        serde_json::to_vec_pretty(github_review)?,
    )?;
    Ok(())
}

struct ReviewMetricsInput<'a> {
    out: &'a Path,
    diff: &'a DiffContext,
    plan: &'a Plan,
    review: &'a ReviewArtifacts,
    github_review: Option<&'a GitHubReview>,
    review_payload_status: &'a str,
    observations_count: usize,
    follow_up_results: &'a [FollowUpResult],
    final_follow_up_tasks: usize,
    run: RunLoopMetrics,
    elapsed: Duration,
}

fn build_review_metrics(input: ReviewMetricsInput<'_>) -> ReviewMetrics {
    let ReviewMetricsInput {
        out,
        diff,
        plan,
        review,
        github_review,
        review_payload_status,
        observations_count,
        follow_up_results,
        final_follow_up_tasks,
        mut run,
        elapsed,
    } = input;
    let sensor_statuses = plan
        .sensors
        .iter()
        .map(|sensor| sensor_status_for_metrics(out, sensor))
        .collect::<Vec<_>>();
    let preflight_statuses = review
        .provider_preflights
        .iter()
        .map(|receipt| receipt.status.as_str())
        .collect::<Vec<_>>();
    let model_lane_statuses = review
        .model_lanes
        .iter()
        .map(|receipt| receipt.status.as_str())
        .collect::<Vec<_>>();
    let follow_up_result_statuses = follow_up_results
        .iter()
        .map(|result| result.status.as_str())
        .collect::<Vec<_>>();
    run.model_call_duration_ms_sum = model_call_duration_ms_sum(review, follow_up_results);
    run.proof_command_duration_ms_sum = proof_command_duration_ms_sum(&review.proof_receipts);
    let prompt_cache = model_prompt_cache_metrics(review, follow_up_results);

    ReviewMetrics {
        schema_version: 1,
        wall_clock_ms: elapsed.as_millis(),
        wall_clock_seconds: elapsed.as_secs(),
        run,
        shared_context_id: review.shared_context_id.clone(),
        base: diff.base.clone(),
        head: diff.head.clone(),
        review_profile: review.review_profile.clone(),
        profile_name: plan.profile_name.clone(),
        runtime_profile: review.runtime_profile.clone(),
        mode: review.mode.clone(),
        posting: review.posting.clone(),
        run_pass: review.run_pass.clone(),
        model_mode: review.model_mode.clone(),
        depth: review.depth.clone(),
        provider_policy: review.provider_policy.clone(),
        lane_width: review.lane_width,
        model_concurrency: review.model_concurrency,
        max_model_calls: review.max_model_calls,
        max_inline_comments: review.max_inline_comments,
        changed_files: diff.changed_files.len(),
        diff_flags: diff.flags.clone(),
        lane_packets: lane_packet_count(out),
        sensors: SensorMetrics {
            total: plan.sensors.len(),
            planned: plan.sensors.iter().filter(|sensor| sensor.run).count(),
            skipped_by_plan: plan.sensors.iter().filter(|sensor| !sensor.run).count(),
            status_counts: status_counts(sensor_statuses.iter().map(String::as_str)),
        },
        models: ModelMetrics {
            provider_preflights: review.provider_preflights.len(),
            provider_preflight_status_counts: status_counts(preflight_statuses.iter().copied()),
            provider_preflight_calls_attempted: review
                .provider_preflights
                .iter()
                .filter(|receipt| model_call_attempted_status(&receipt.status))
                .count(),
            model_lanes: review.model_lanes.len(),
            model_lane_status_counts: status_counts(model_lane_statuses.iter().copied()),
            model_lane_calls_attempted: review
                .model_lanes
                .iter()
                .filter(|receipt| model_call_attempted_status(&receipt.status))
                .count(),
            model_fallbacks_used: review
                .model_lanes
                .iter()
                .filter(|receipt| receipt.fallback_from.is_some())
                .count(),
            prompt_cache_creation_input_tokens: prompt_cache.creation_input_tokens,
            prompt_cache_read_input_tokens: prompt_cache.read_input_tokens,
            prompt_cache_lane_hits: prompt_cache.lane_hits,
            prompt_cache_lane_misses: prompt_cache.lane_misses,
            prompt_cache_lane_unknown: prompt_cache.lane_unknown,
        },
        inline_comments: review.inline_comments.len(),
        github_review_comments: github_review.map_or(0, |review| review.comments.len()),
        summary_only_findings: review.summary_only_findings.len(),
        observations: observations_count,
        follow_up_results: FollowUpResultMetrics {
            total: follow_up_results.len(),
            status_counts: status_counts(follow_up_result_statuses.iter().copied()),
            calls_attempted: follow_up_results
                .iter()
                .filter(|result| model_call_attempted_status(&result.status))
                .count(),
        },
        final_follow_up_tasks,
        proof_requests: review.proof_requests.len(),
        proof_receipts: review.proof_receipts.len(),
        resource_leases: review.resource_leases.len(),
        off_diff_candidates_rejected: review
            .summary_only_findings
            .iter()
            .filter(|finding| finding.reason.contains("line_valid=false"))
            .count(),
        missing_or_failed_sensor_evidence: review.missing_or_failed_sensor_evidence.len(),
        missing_or_failed_model_evidence: review.missing_or_failed_model_evidence.len(),
        provider_evidence_failures: review
            .provider_preflights
            .iter()
            .filter(|receipt| is_model_evidence_issue(&receipt.status))
            .count(),
        terminal_state: review.terminal_state.status.clone(),
        review_payload_status: review_payload_status.to_owned(),
        post_status: "not_attempted_by_run".to_owned(),
        review_body_bytes: review.body.len(),
        artifact_review_body_bytes: review.body.len(),
        github_review_body_bytes: github_review.map_or(0, |review| review.body.len()),
        review_body_truncated: review.body.contains(REVIEW_BODY_TRUNCATED_SUFFIX.trim()),
        github_review_body_truncated: github_review
            .is_some_and(|review| review.body.contains(REVIEW_BODY_TRUNCATED_SUFFIX.trim())),
    }
}

fn write_scheduler_artifact(review_dir: &Path, run: &RunLoopMetrics) -> Result<()> {
    let artifact = SchedulerArtifact {
        schema: SCHEDULER_SCHEMA,
        concurrency_model: &run.concurrency_model,
        scheduler_profile: &run.scheduler_profile,
        local_proof_wall_excludes_model_wait: run.local_proof_wall_excludes_model_wait,
        elapsed_wall_ms: run.elapsed_wall_ms,
        scheduler_roles: &run.scheduler_roles,
        streams: &run.streams,
        loops: &run.loops,
        overlaps: SchedulerOverlapArtifact {
            investigation_proof_overlap_ms: run.investigation_proof_overlap_ms,
            model_proof_overlap_ms: run.model_proof_overlap_ms,
            proof_overlap_ms: run.proof_overlap_ms,
        },
        phases: &run.phases,
    };
    fs::write(
        review_dir.join("scheduler.json"),
        serde_json::to_vec_pretty(&artifact)?,
    )?;
    Ok(())
}

fn model_call_duration_ms_sum(
    review: &ReviewArtifacts,
    follow_up_results: &[FollowUpResult],
) -> u128 {
    review
        .provider_preflights
        .iter()
        .filter_map(|receipt| receipt.duration_ms)
        .chain(
            review
                .model_lanes
                .iter()
                .filter_map(|receipt| receipt.duration_ms),
        )
        .chain(
            follow_up_results
                .iter()
                .filter_map(|result| result.duration_ms),
        )
        .sum()
}

fn proof_command_duration_ms_sum(proof_receipts: &[ProofReceipt]) -> u128 {
    proof_receipts
        .iter()
        .flat_map(|receipt| receipt.commands.iter())
        .map(|command| command.duration_ms)
        .sum()
}

struct PromptCacheMetrics {
    creation_input_tokens: u64,
    read_input_tokens: u64,
    lane_hits: usize,
    lane_misses: usize,
    lane_unknown: usize,
}

fn model_prompt_cache_metrics(
    review: &ReviewArtifacts,
    follow_up_results: &[FollowUpResult],
) -> PromptCacheMetrics {
    let creation_input_tokens = review
        .provider_preflights
        .iter()
        .filter_map(|receipt| receipt.cache_usage.cache_creation_input_tokens)
        .chain(
            review
                .model_lanes
                .iter()
                .filter_map(|receipt| receipt.cache_usage.cache_creation_input_tokens),
        )
        .chain(
            follow_up_results
                .iter()
                .filter_map(|result| result.cache_usage.cache_creation_input_tokens),
        )
        .sum();
    let read_input_tokens = review
        .provider_preflights
        .iter()
        .filter_map(|receipt| receipt.cache_usage.cache_read_input_tokens)
        .chain(
            review
                .model_lanes
                .iter()
                .filter_map(|receipt| receipt.cache_usage.cache_read_input_tokens),
        )
        .chain(
            follow_up_results
                .iter()
                .filter_map(|result| result.cache_usage.cache_read_input_tokens),
        )
        .sum();
    let mut lane_hits = 0;
    let mut lane_misses = 0;
    let mut lane_unknown = 0;
    for receipt in &review.model_lanes {
        if !model_call_attempted_status(&receipt.status)
            || model_cache_mode(&receipt.provider, &receipt.endpoint_kind)
                != "explicit-anthropic-cache-control"
        {
            continue;
        }
        if receipt.cache_usage.cache_read_input_tokens.unwrap_or(0) > 0 {
            lane_hits += 1;
        } else if receipt.cache_usage.cache_creation_input_tokens.unwrap_or(0) > 0 {
            lane_misses += 1;
        } else {
            lane_unknown += 1;
        }
    }
    PromptCacheMetrics {
        creation_input_tokens,
        read_input_tokens,
        lane_hits,
        lane_misses,
        lane_unknown,
    }
}

fn combined_observations(review: &ReviewArtifacts) -> Vec<Observation> {
    let mut observations = review.observations.clone();
    observations.extend(build_observations(review));
    for (index, observation) in observations.iter_mut().enumerate() {
        let short = observation
            .fingerprint
            .get(..12)
            .unwrap_or(&observation.fingerprint);
        observation.id = format!("obs-{index:04}-{short}");
    }
    observations
}

fn build_observations(review: &ReviewArtifacts) -> Vec<Observation> {
    let mut observations = Vec::new();
    for comment in &review.inline_comments {
        observations.push(make_observation(ObservationInput {
            index: observations.len(),
            lane: &comment.lane,
            question: &comment.lane,
            claim: &comment.body,
            kind: infer_observation_kind(&comment.lane, &comment.body, &comment.evidence),
            status: "confirmed",
            severity: &comment.severity,
            confidence: &comment.confidence,
            path: Some(&comment.path),
            line: Some(comment.line),
            evidence: vec![comment.evidence.clone()],
            dedupe_key: None,
            source: "inline-comment",
        }));
    }
    for finding in &review.summary_only_findings {
        let parked = is_parked_follow_up(finding);
        let kind = if parked {
            "parked-follow-up"
        } else {
            infer_observation_kind(&finding.lane, &finding.reason, &finding.evidence)
        };
        let status = if parked { "parked" } else { "open" };
        observations.push(make_observation(ObservationInput {
            index: observations.len(),
            lane: &finding.lane,
            question: &finding.lane,
            claim: &finding.reason,
            kind,
            status,
            severity: &finding.severity,
            confidence: &finding.confidence,
            path: None,
            line: None,
            evidence: vec![finding.evidence.clone()],
            dedupe_key: None,
            source: "summary-only-finding",
        }));
    }
    for issue in &review.missing_or_failed_sensor_evidence {
        let claim = format!(
            "Sensor `{}` evidence is `{}`: {}",
            issue.sensor, issue.status, issue.reason
        );
        observations.push(make_observation(ObservationInput {
            index: observations.len(),
            lane: &format!("sensor-{}", issue.sensor),
            question: "missing-sensor-evidence",
            claim: &claim,
            kind: "missing-evidence",
            status: "open",
            severity: "medium",
            confidence: "high",
            path: None,
            line: None,
            evidence: vec![issue.reason.clone()],
            dedupe_key: None,
            source: "missing-sensor-evidence",
        }));
    }
    for issue in &review.missing_or_failed_model_evidence {
        let claim = format!(
            "Lane `{}` via `{}` model `{}` endpoint `{}` is `{}`: {}",
            issue.lane,
            issue.provider,
            issue.model,
            issue.endpoint_kind,
            issue.status,
            issue.reason
        );
        observations.push(make_observation(ObservationInput {
            index: observations.len(),
            lane: &issue.lane,
            question: "missing-model-evidence",
            claim: &claim,
            kind: "missing-evidence",
            status: "open",
            severity: "medium",
            confidence: "high",
            path: None,
            line: None,
            evidence: vec![issue.reason.clone()],
            dedupe_key: None,
            source: "missing-model-evidence",
        }));
    }
    observations
}

struct ObservationInput<'a> {
    index: usize,
    lane: &'a str,
    question: &'a str,
    claim: &'a str,
    kind: &'a str,
    status: &'a str,
    severity: &'a str,
    confidence: &'a str,
    path: Option<&'a String>,
    line: Option<u32>,
    evidence: Vec<String>,
    dedupe_key: Option<&'a str>,
    source: &'a str,
}

fn make_observation(input: ObservationInput<'_>) -> Observation {
    let path = input.path.cloned();
    let line = input.line.filter(|line| *line > 0);
    let fingerprint_input = format!(
        "{}\n{}\n{}\n{}\n{:?}\n{:?}\n{}",
        input.lane,
        input.kind,
        input.status,
        input.claim,
        path,
        line,
        input.evidence.join("\n")
    );
    let fingerprint = sha256_hex(fingerprint_input.as_bytes());
    let short = &fingerprint[..12];
    Observation {
        schema: OBSERVATION_SCHEMA.to_owned(),
        id: format!("obs-{index:04}-{short}", index = input.index),
        lane: input.lane.to_owned(),
        question: input.question.to_owned(),
        claim: input.claim.to_owned(),
        kind: input.kind.to_owned(),
        status: input.status.to_owned(),
        severity: input.severity.to_owned(),
        confidence: input.confidence.to_owned(),
        path: path.clone(),
        line,
        fingerprint,
        evidence: input.evidence,
        dedupe_key: input
            .dedupe_key
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| {
                observation_dedupe_key(input.lane, input.kind, path.as_deref(), line)
            }),
        source: input.source.to_owned(),
    }
}

fn observation_dedupe_key(lane: &str, kind: &str, path: Option<&str>, line: Option<u32>) -> String {
    match (path, line) {
        (Some(path), Some(line)) => format!("{kind}:{path}:{line}"),
        _ => format!("{kind}:{}", sanitize_artifact_name(lane)),
    }
}

fn infer_observation_kind(lane: &str, claim: &str, evidence: &str) -> &'static str {
    let lane = lane.to_ascii_lowercase();
    let text = format!("{claim}\n{evidence}").to_ascii_lowercase();
    if text.contains("missing") || text.contains("unavailable") || text.contains("skipped") {
        "missing-evidence"
    } else if text.contains("parked") || text.contains("follow-up") {
        "parked-follow-up"
    } else if lane.contains("test") || text.contains("test") || text.contains("oracle") {
        "test-gap"
    } else if lane.contains("source-route") || lane.contains("sibling") || text.contains("route") {
        "source-route-gap"
    } else if lane.contains("security") || text.contains("exploit") || text.contains("secret") {
        "security-risk"
    } else if text.contains("verify") || text.contains("confirm") || text.contains("question") {
        "verification-question"
    } else {
        "bug"
    }
}

fn write_observation_artifacts(out: &Path, observations: &[Observation]) -> Result<()> {
    let observations_dir = out.join("observations");
    if observations_dir.exists() {
        fs::remove_dir_all(&observations_dir)
            .with_context(|| format!("remove {}", observations_dir.display()))?;
    }
    fs::create_dir_all(&observations_dir)
        .with_context(|| format!("create {}", observations_dir.display()))?;

    let questions_dir = out.join("questions");
    if questions_dir.exists() {
        fs::remove_dir_all(&questions_dir)
            .with_context(|| format!("remove {}", questions_dir.display()))?;
    }
    fs::create_dir_all(&questions_dir)
        .with_context(|| format!("create {}", questions_dir.display()))?;

    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("observations.json"),
        serde_json::to_vec_pretty(observations)?,
    )?;
    let observation_summary = observation_summary_artifacts(observations);
    fs::write(
        review_dir.join("unique_observations.json"),
        serde_json::to_vec_pretty(&observation_summary.unique)?,
    )?;
    fs::write(
        review_dir.join("merged_observations.json"),
        serde_json::to_vec_pretty(&observation_summary.merged)?,
    )?;
    fs::write(
        review_dir.join("dropped_observations.json"),
        serde_json::to_vec_pretty(&observation_summary.dropped)?,
    )?;

    let mut by_lane: BTreeMap<&str, Vec<&Observation>> = BTreeMap::new();
    let mut by_question: BTreeMap<(String, String), QuestionObservationArtifact<'_>> =
        BTreeMap::new();
    for observation in observations {
        by_lane
            .entry(observation.lane.as_str())
            .or_default()
            .push(observation);
        let lane_name = sanitize_artifact_name(&observation.lane);
        let question_name = sanitize_artifact_name(&observation.question);
        let artifact = by_question
            .entry((lane_name, question_name))
            .or_insert_with(|| QuestionObservationArtifact {
                schema: QUESTION_OBSERVATIONS_SCHEMA,
                lane: &observation.lane,
                question: &observation.question,
                observations: Vec::new(),
            });
        if artifact.lane != observation.lane || artifact.question != observation.question {
            bail!(
                "questions artifact path collision for {}/{}",
                observation.lane,
                observation.question
            );
        }
        artifact.observations.push(observation);
    }
    for (lane, lane_observations) in by_lane {
        let path = observations_dir.join(format!("{}.ndjson", sanitize_artifact_name(lane)));
        let mut text = String::new();
        for observation in lane_observations {
            text.push_str(&serde_json::to_string(observation)?);
            text.push('\n');
        }
        fs::write(path, text)?;
    }
    for ((lane_name, question_name), artifact) in by_question {
        let lane_dir = questions_dir.join(lane_name);
        fs::create_dir_all(&lane_dir).with_context(|| format!("create {}", lane_dir.display()))?;
        fs::write(
            lane_dir.join(format!("{question_name}.json")),
            serde_json::to_vec_pretty(&artifact)?,
        )?;
    }
    Ok(())
}

fn build_witness_records(
    inline_comments: &[ReviewInlineComment],
    summary_only_findings: &[SummaryOnlyFinding],
    observations: &[Observation],
    proof_receipts: &[ProofReceipt],
) -> Vec<WitnessRecord> {
    let mut witnesses = Vec::new();
    for comment in inline_comments {
        witnesses.push(witness_record(WitnessRecordInput {
            status: "needs-witness",
            kind: "inline-finding",
            source: "inline-comment",
            claim: &comment.body,
            dedupe_key: &format!(
                "inline:{}:{}:{}",
                comment.path,
                comment.line,
                sha256_hex(comment.body.as_bytes())
            ),
            evidence: vec![comment.evidence.clone()],
            lane: Some(comment.lane.clone()),
            path: Some(comment.path.clone()),
            line: Some(comment.line),
            observation_id: None,
            proof_receipt_id: None,
        }));
    }
    for finding in summary_only_findings {
        witnesses.push(witness_record(WitnessRecordInput {
            status: witness_status_for_summary_finding(finding),
            kind: "summary-finding",
            source: "summary-only-finding",
            claim: &finding.reason,
            dedupe_key: &format!(
                "summary:{}:{}",
                finding.lane,
                sha256_hex(format!("{}\n{}", finding.reason, finding.evidence).as_bytes())
            ),
            evidence: vec![finding.evidence.clone()],
            lane: Some(finding.lane.clone()),
            path: None,
            line: None,
            observation_id: None,
            proof_receipt_id: None,
        }));
    }
    for observation in observations {
        witnesses.push(witness_record(WitnessRecordInput {
            status: witness_status_for_observation(observation),
            kind: &observation.kind,
            source: &observation.source,
            claim: &observation.claim,
            dedupe_key: &observation.dedupe_key,
            evidence: observation.evidence.clone(),
            lane: Some(observation.lane.clone()),
            path: observation.path.clone(),
            line: observation.line,
            observation_id: Some(observation.id.clone()),
            proof_receipt_id: None,
        }));
    }
    for receipt in proof_receipts {
        witnesses.push(witness_record(WitnessRecordInput {
            status: witness_status_for_proof_receipt(receipt),
            kind: &receipt.kind,
            source: "proof-receipt",
            claim: &receipt.reason,
            dedupe_key: &receipt.id,
            evidence: proof_receipt_witness_evidence(receipt),
            lane: None,
            path: None,
            line: None,
            observation_id: None,
            proof_receipt_id: Some(receipt.id.clone()),
        }));
    }
    witnesses
}

fn append_follow_up_evidence_witnesses(
    witnesses: &mut Vec<WitnessRecord>,
    evidence: &FollowUpEvidenceArtifact,
    proof_receipts: &[ProofReceipt],
) {
    for comment in &evidence.inline_comments {
        witnesses.push(witness_record(WitnessRecordInput {
            status: "needs-witness",
            kind: "inline-finding",
            source: "follow-up-inline-comment",
            claim: &comment.body,
            dedupe_key: &format!(
                "follow-up-inline:{}:{}:{}",
                comment.path,
                comment.line,
                sha256_hex(comment.body.as_bytes())
            ),
            evidence: vec![comment.evidence.clone()],
            lane: Some(comment.lane.clone()),
            path: Some(comment.path.clone()),
            line: Some(comment.line),
            observation_id: None,
            proof_receipt_id: None,
        }));
    }
    for finding in &evidence.summary_only_findings {
        witnesses.push(witness_record(WitnessRecordInput {
            status: witness_status_for_summary_finding(finding),
            kind: "summary-finding",
            source: "follow-up-summary-only-finding",
            claim: &finding.reason,
            dedupe_key: &format!(
                "follow-up-summary:{}:{}",
                finding.lane,
                sha256_hex(format!("{}\n{}", finding.reason, finding.evidence).as_bytes())
            ),
            evidence: vec![finding.evidence.clone()],
            lane: Some(finding.lane.clone()),
            path: None,
            line: None,
            observation_id: None,
            proof_receipt_id: None,
        }));
    }
    for observation in &evidence.observations {
        witnesses.push(witness_record(WitnessRecordInput {
            status: witness_status_for_observation(observation),
            kind: &observation.kind,
            source: &format!("follow-up-{}", observation.source),
            claim: &observation.claim,
            dedupe_key: &format!("follow-up-observation:{}", observation.dedupe_key),
            evidence: observation.evidence.clone(),
            lane: Some(observation.lane.clone()),
            path: observation.path.clone(),
            line: observation.line,
            observation_id: None,
            proof_receipt_id: None,
        }));
    }
    for request in &evidence.proof_requests {
        let matched_receipt = proof_receipt_for_request(proof_receipts, &request.id);
        let (status, mut request_evidence, proof_receipt_id) = match matched_receipt {
            Some(receipt) => (
                witness_status_for_proof_receipt(receipt),
                proof_receipt_witness_evidence(receipt),
                Some(receipt.id.clone()),
            ),
            None => ("needs-witness", vec![request.command.clone()], None),
        };
        request_evidence.insert(0, format!("Follow-up proof request: {}", request.command));
        witnesses.push(witness_record(WitnessRecordInput {
            status,
            kind: "proof-request",
            source: "follow-up-proof-request",
            claim: &request.reason,
            dedupe_key: &format!("follow-up-proof-request:{}", request.id),
            evidence: request_evidence,
            lane: Some(request.lane.clone()),
            path: None,
            line: None,
            observation_id: None,
            proof_receipt_id,
        }));
    }
}

fn proof_receipt_for_request<'a>(
    proof_receipts: &'a [ProofReceipt],
    request_id: &str,
) -> Option<&'a ProofReceipt> {
    proof_receipts
        .iter()
        .find(|receipt| receipt.request_ids.iter().any(|id| id == request_id))
}

fn build_candidate_records(
    inline_comments: &[ReviewInlineComment],
    summary_only_findings: &[SummaryOnlyFinding],
) -> Vec<CandidateRecord> {
    let mut candidates = Vec::new();
    for comment in inline_comments {
        let fingerprint = sha256_hex(
            format!(
                "inline-comment\n{}\n{}\n{}\n{}\n{}",
                comment.lane, comment.path, comment.line, comment.body, comment.evidence
            )
            .as_bytes(),
        );
        candidates.push(CandidateRecord {
            schema: CANDIDATE_SCHEMA.to_owned(),
            id: format!(
                "candidate-{index:04}-{short}",
                index = candidates.len(),
                short = &fingerprint[..12]
            ),
            lane: comment.lane.clone(),
            source: "inline-comment".to_owned(),
            status: "accepted-inline".to_owned(),
            disposition: "inline".to_owned(),
            severity: comment.severity.clone(),
            confidence: comment.confidence.clone(),
            claim: comment.body.clone(),
            evidence: comment.evidence.clone(),
            path: Some(comment.path.clone()),
            line: Some(comment.line),
            side: Some(comment.side.clone()),
        });
    }
    for finding in summary_only_findings {
        let fingerprint = sha256_hex(
            format!(
                "summary-only-finding\n{}\n{}\n{}",
                finding.lane, finding.reason, finding.evidence
            )
            .as_bytes(),
        );
        candidates.push(CandidateRecord {
            schema: CANDIDATE_SCHEMA.to_owned(),
            id: format!(
                "candidate-{index:04}-{short}",
                index = candidates.len(),
                short = &fingerprint[..12]
            ),
            lane: finding.lane.clone(),
            source: "summary-only-finding".to_owned(),
            status: "summary-only".to_owned(),
            disposition: candidate_disposition_for_summary_finding(finding).to_owned(),
            severity: finding.severity.clone(),
            confidence: finding.confidence.clone(),
            claim: finding.reason.clone(),
            evidence: finding.evidence.clone(),
            path: None,
            line: None,
            side: None,
        });
    }
    candidates
}

fn candidate_disposition_for_summary_finding(finding: &SummaryOnlyFinding) -> &'static str {
    let reason = finding.reason.to_ascii_lowercase();
    let evidence = finding.evidence.to_ascii_lowercase();
    if is_parked_follow_up(finding) {
        "parked-follow-up"
    } else if reason.contains("false premise")
        || reason.contains("refuted")
        || evidence.contains("false premise")
        || evidence.contains("refuted")
    {
        "refuted"
    } else if reason.contains("duplicate inline candidate merged")
        || reason.contains("summary-only guard rejected candidate")
    {
        "dropped"
    } else {
        "summary-only"
    }
}

fn write_candidate_artifacts(out: &Path, candidates: &[CandidateRecord]) -> Result<()> {
    let candidates_dir = out.join("candidates");
    if candidates_dir.exists() {
        fs::remove_dir_all(&candidates_dir)
            .with_context(|| format!("remove {}", candidates_dir.display()))?;
    }
    fs::create_dir_all(&candidates_dir)
        .with_context(|| format!("create {}", candidates_dir.display()))?;

    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("candidates.json"),
        serde_json::to_vec_pretty(candidates)?,
    )?;

    let mut ndjson = String::new();
    for candidate in candidates {
        ndjson.push_str(&serde_json::to_string(candidate)?);
        ndjson.push('\n');
        fs::write(
            candidates_dir.join(format!("{}.json", sanitize_artifact_name(&candidate.id))),
            serde_json::to_vec_pretty(candidate)?,
        )?;
    }
    fs::write(out.join("candidates.ndjson"), ndjson)?;
    Ok(())
}

fn read_candidate_review_surfaces(
    out: &Path,
) -> Result<(Vec<ReviewInlineComment>, Vec<SummaryOnlyFinding>)> {
    let candidates = read_candidate_records(out)?;
    candidate_review_surfaces(&candidates)
}

fn read_candidate_records(out: &Path) -> Result<Vec<CandidateRecord>> {
    let path = out.join("review/candidates.json");
    serde_json::from_slice(&fs::read(&path).with_context(|| format!("read {}", path.display()))?)
        .with_context(|| format!("parse {}", path.display()))
}

fn candidate_review_surfaces(
    candidates: &[CandidateRecord],
) -> Result<(Vec<ReviewInlineComment>, Vec<SummaryOnlyFinding>)> {
    let mut inline_comments = Vec::new();
    let mut summary_only_findings = Vec::new();
    for candidate in candidates {
        if candidate.schema != CANDIDATE_SCHEMA {
            bail!("candidate {} has unsupported schema", candidate.id);
        }
        if !matches!(
            candidate.disposition.as_str(),
            "inline" | "summary-only" | "parked-follow-up" | "refuted" | "dropped"
        ) {
            bail!(
                "candidate {} has unsupported disposition {}",
                candidate.id,
                candidate.disposition
            );
        }
        match (candidate.source.as_str(), candidate.status.as_str()) {
            ("inline-comment", "accepted-inline") => {
                if candidate.disposition != "inline" {
                    bail!(
                        "inline candidate {} disposition must be inline",
                        candidate.id
                    );
                }
                let path = candidate
                    .path
                    .clone()
                    .ok_or_else(|| anyhow::anyhow!("candidate {} missing path", candidate.id))?;
                let line = candidate
                    .line
                    .ok_or_else(|| anyhow::anyhow!("candidate {} missing line", candidate.id))?;
                let side = candidate
                    .side
                    .clone()
                    .ok_or_else(|| anyhow::anyhow!("candidate {} missing side", candidate.id))?;
                if side != "RIGHT" {
                    bail!("candidate {} side must be RIGHT", candidate.id);
                }
                inline_comments.push(ReviewInlineComment {
                    lane: candidate.lane.clone(),
                    severity: candidate.severity.clone(),
                    confidence: candidate.confidence.clone(),
                    path,
                    line,
                    side,
                    body: candidate.claim.clone(),
                    evidence: candidate.evidence.clone(),
                });
            }
            ("summary-only-finding", "summary-only") => {
                if candidate.disposition == "inline" {
                    bail!(
                        "summary-only candidate {} disposition cannot be inline",
                        candidate.id
                    );
                }
                if candidate.path.is_some() || candidate.line.is_some() || candidate.side.is_some()
                {
                    bail!("summary-only candidate {} has inline fields", candidate.id);
                }
                summary_only_findings.push(SummaryOnlyFinding {
                    lane: candidate.lane.clone(),
                    severity: candidate.severity.clone(),
                    confidence: candidate.confidence.clone(),
                    reason: candidate.claim.clone(),
                    evidence: candidate.evidence.clone(),
                });
            }
            _ => bail!(
                "candidate {} has unsupported source/status {}/{}",
                candidate.id,
                candidate.source,
                candidate.status
            ),
        }
    }
    Ok((inline_comments, summary_only_findings))
}

fn build_orchestrator_plan(
    candidates: &[CandidateRecord],
    observations: &[ObservationGroup],
    proof_receipts: &[ProofReceipt],
    resource_leases: &[ResourceLease],
) -> OrchestratorPlanArtifact {
    let mut grouped: BTreeMap<(String, String), Vec<&CandidateRecord>> = BTreeMap::new();
    for candidate in candidates {
        let evidence_need = candidate_evidence_need(candidate);
        grouped
            .entry((candidate.disposition.clone(), evidence_need))
            .or_default()
            .push(candidate);
    }

    let mut evidence_groups = Vec::new();
    let mut follow_up_tasks = Vec::new();
    for ((disposition, evidence_need), group_candidates) in grouped {
        let candidate_ids = group_candidates
            .iter()
            .map(|candidate| candidate.id.clone())
            .collect::<Vec<_>>();
        let lanes = unique_sorted(
            group_candidates
                .iter()
                .map(|candidate| candidate.lane.clone())
                .collect(),
        );
        let routed_evidence =
            routed_evidence_for_group(&evidence_need, &lanes, proof_receipts, resource_leases);
        let fingerprint = sha256_hex(format!("{disposition}\n{evidence_need}").as_bytes());
        let group_id = format!("evidence-group-{}", &fingerprint[..12]);
        let group = OrchestratorEvidenceGroup {
            schema: ORCHESTRATOR_EVIDENCE_GROUP_SCHEMA.to_owned(),
            id: group_id.clone(),
            evidence_need: evidence_need.clone(),
            disposition: disposition.clone(),
            candidate_ids: candidate_ids.clone(),
            lanes,
            routed_evidence: routed_evidence.clone(),
            duplicate_count: candidate_ids.len().saturating_sub(1),
            reason: orchestrator_group_reason(&disposition, &evidence_need),
        };
        if let Some(task) = follow_up_task_for_group(
            &group_id,
            &disposition,
            &evidence_need,
            &candidate_ids,
            &routed_evidence,
        ) {
            follow_up_tasks.push(task);
        }
        evidence_groups.push(group);
    }

    let mut observation_groups = Vec::new();
    for observation in observations {
        let evidence_need = observation_evidence_need(observation);
        let routed_evidence = routed_evidence_for_group(
            &evidence_need,
            &observation.lanes,
            proof_receipts,
            resource_leases,
        );
        let group_id = format!("orchestrator-{}", observation.id);
        let group = OrchestratorObservationGroup {
            schema: ORCHESTRATOR_OBSERVATION_GROUP_SCHEMA.to_owned(),
            id: group_id.clone(),
            observation_group_id: observation.id.clone(),
            dedupe_key: observation.dedupe_key.clone(),
            evidence_need: evidence_need.clone(),
            claim: observation.claim.clone(),
            kind: observation.kind.clone(),
            status: observation.status.clone(),
            lanes: observation.lanes.clone(),
            sources: observation.sources.clone(),
            observation_ids: observation.observation_ids.clone(),
            duplicate_count: observation.duplicate_count,
            routed_evidence: routed_evidence.clone(),
            reason: format!(
                "routed unique observation group `{}` under evidence need `{evidence_need}`",
                observation.id
            ),
        };
        if let Some(task) =
            follow_up_task_for_observation_group(observation, &group, &routed_evidence)
        {
            follow_up_tasks.push(task);
        }
        observation_groups.push(group);
    }

    OrchestratorPlanArtifact {
        schema: ORCHESTRATOR_PLAN_SCHEMA.to_owned(),
        candidates: candidates.len(),
        observations: observations.len(),
        evidence_groups,
        observation_groups,
        follow_up_tasks,
    }
}

fn build_final_orchestrator_plan(
    candidates: &[CandidateRecord],
    observations: &[ObservationGroup],
    proof_receipts: &[ProofReceipt],
    resource_leases: &[ResourceLease],
) -> OrchestratorPlanArtifact {
    let mut plan =
        build_orchestrator_plan(candidates, observations, proof_receipts, resource_leases);
    plan.follow_up_tasks
        .retain(|task| !final_follow_up_task_resolved_by_tool_proof(task));
    plan
}

fn final_follow_up_task_resolved_by_tool_proof(task: &FollowUpQuestionTask) -> bool {
    task.evidence_need == "proof-confirmation"
        && task
            .routed_evidence
            .iter()
            .any(|evidence| evidence.kind == "proof-receipt" && evidence.status == "tool-confirmed")
}

fn write_orchestrator_artifacts(
    out: &Path,
    plan: &OrchestratorPlanArtifact,
    proof_receipts: &[ProofReceipt],
) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("orchestrator_plan.json"),
        serde_json::to_vec_pretty(plan)?,
    )?;

    let mut ndjson = String::new();
    for task in &plan.follow_up_tasks {
        ndjson.push_str(&serde_json::to_string(task)?);
        ndjson.push('\n');
    }
    fs::write(out.join("follow_up_questions.ndjson"), ndjson)?;
    write_follow_up_question_packets(out, &plan.follow_up_tasks, proof_receipts)?;
    Ok(())
}

