/// Issue-candidate kinds the capture surface accepts (release lane step 4;
/// security/release/deploy/compliance classes are deliberately absent - they
/// stay suggest-only by contract even after the broker exists).
const ISSUE_CANDIDATE_KINDS: &[&str] = &[
    "implementation-follow-up",
    "tool-defect",
    "repo-policy",
    "test-gap",
    "proof-broker-gap",
];

fn issue_candidate_fingerprint(candidate: &IssueCandidate) -> String {
    let normalized_title = candidate
        .title
        .to_ascii_lowercase()
        .chars()
        .map(|ch| if ch.is_ascii_alphanumeric() { ch } else { ' ' })
        .collect::<String>()
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ");
    sha256_hex(
        format!(
            "{}\n{}\n{normalized_title}",
            candidate.target_repo, candidate.kind
        )
        .as_bytes(),
    )
}

/// The bar a follow-up must meet to exist at all: specific repo, specific
/// problem, why it is not in this PR, evidence, an implementation plan, and
/// acceptance criteria. Below the bar is `invalid`, never silently dropped.
fn issue_candidate_invalid_reason(candidate: &IssueCandidate) -> Option<String> {
    if candidate.target_repo.trim().is_empty() {
        return Some("target_repo is required".to_owned());
    }
    if candidate.title.trim().is_empty() {
        return Some("title is required".to_owned());
    }
    if candidate.problem.trim().is_empty() {
        return Some("problem is required".to_owned());
    }
    if candidate.why_not_this_pr.trim().is_empty() {
        return Some("why_not_this_pr is required".to_owned());
    }
    if !ISSUE_CANDIDATE_KINDS.contains(&candidate.kind.as_str()) {
        return Some(format!(
            "kind `{}` is not in the allowed set {ISSUE_CANDIDATE_KINDS:?}",
            candidate.kind
        ));
    }
    if !matches!(candidate.confidence.as_str(), "low" | "medium" | "high") {
        return Some(format!(
            "confidence `{}` must be low, medium, or high",
            candidate.confidence
        ));
    }
    if !matches!(
        candidate.current_pr_disposition.as_str(),
        "do-not-block" | "blocks-if-claimed"
    ) {
        return Some(format!(
            "current_pr_disposition `{}` must be do-not-block or blocks-if-claimed",
            candidate.current_pr_disposition
        ));
    }
    if !candidate.evidence.iter().any(|evidence| {
        evidence
            .path
            .as_deref()
            .is_some_and(|value| !value.trim().is_empty())
            || evidence
                .url
                .as_deref()
                .is_some_and(|value| !value.trim().is_empty())
    }) {
        return Some("at least one evidence entry with a path or url is required".to_owned());
    }
    if candidate
        .implementation_plan
        .iter()
        .all(|step| step.trim().is_empty())
    {
        return Some("a non-empty implementation_plan is required".to_owned());
    }
    if candidate
        .acceptance
        .iter()
        .all(|item| item.trim().is_empty())
    {
        return Some("non-empty acceptance criteria are required".to_owned());
    }
    None
}

/// True when the issue posture lets a valid candidate render for the
/// reviewer: enabled, mode suggest or open-high-confidence, high confidence,
/// and a do-not-block disposition. Suggested follow-ups never block; under
/// open-high-confidence the broker may additionally attempt opening at post
/// time, but the run-side action stays `suggested` either way.
fn issue_candidate_renders(issues: &IssuesConfig, candidate: &IssueCandidate) -> bool {
    issues.enabled
        && matches!(issues.mode.as_str(), "suggest" | "open-high-confidence")
        && candidate.confidence == "high"
        && candidate.current_pr_disposition == "do-not-block"
}

fn classify_issue_candidates(
    issues: &IssuesConfig,
    raw: Vec<IssueCandidate>,
) -> (Vec<IssueCandidate>, Vec<IssueAction>) {
    let mut candidates = Vec::new();
    let mut actions = Vec::new();
    let mut seen: BTreeMap<String, String> = BTreeMap::new();
    for (index, mut candidate) in raw.into_iter().enumerate() {
        candidate.schema = ISSUE_CANDIDATE_SCHEMA.to_owned();
        let fingerprint = issue_candidate_fingerprint(&candidate);
        candidate.id = format!("issue-candidate-{index:03}-{}", &fingerprint[..12]);
        let action = if let Some(reason) = issue_candidate_invalid_reason(&candidate) {
            IssueAction {
                schema: ISSUE_ACTION_SCHEMA.to_owned(),
                candidate_id: candidate.id.clone(),
                action: "invalid".to_owned(),
                reason,
                existing: None,
            }
        } else if let Some(existing) = seen.get(&fingerprint) {
            IssueAction {
                schema: ISSUE_ACTION_SCHEMA.to_owned(),
                candidate_id: candidate.id.clone(),
                action: "duplicate".to_owned(),
                reason: "same target repo, kind, and normalized title as an earlier candidate"
                    .to_owned(),
                existing: Some(existing.clone()),
            }
        } else {
            seen.insert(fingerprint, candidate.id.clone());
            if issue_candidate_renders(issues, &candidate) {
                IssueAction {
                    schema: ISSUE_ACTION_SCHEMA.to_owned(),
                    candidate_id: candidate.id.clone(),
                    action: "suggested".to_owned(),
                    reason: if issues.mode == "open-high-confidence" {
                        "high-confidence follow-up rendered for the reviewer; the \
                         issue broker attempts opening at post time for allowlisted \
                         target repos"
                            .to_owned()
                    } else {
                        "high-confidence follow-up rendered for the reviewer; \
                         suggested follow-ups never block"
                            .to_owned()
                    },
                    existing: None,
                }
            } else {
                IssueAction {
                    schema: ISSUE_ACTION_SCHEMA.to_owned(),
                    candidate_id: candidate.id.clone(),
                    action: "artifact-only".to_owned(),
                    reason: "below the rendering bar or rendering disabled; preserved \
                             in artifacts with no GitHub side effects"
                        .to_owned(),
                    existing: None,
                }
            }
        };
        actions.push(action);
        candidates.push(candidate);
    }
    (candidates, actions)
}

fn write_issue_capture_artifacts(
    out: &Path,
    candidates: &[IssueCandidate],
    actions: &[IssueAction],
) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("issue_candidates.json"),
        serde_json::to_vec_pretty(candidates)?,
    )?;
    fs::write(
        review_dir.join("issue_actions.json"),
        serde_json::to_vec_pretty(actions)?,
    )?;
    let mut candidate_lines = String::new();
    for candidate in candidates {
        candidate_lines.push_str(&serde_json::to_string(candidate)?);
        candidate_lines.push('\n');
    }
    fs::write(out.join("issue_candidates.ndjson"), candidate_lines)?;
    let mut action_lines = String::new();
    for action in actions {
        action_lines.push_str(&serde_json::to_string(action)?);
        action_lines.push('\n');
    }
    fs::write(out.join("issue_actions.ndjson"), action_lines)?;

    let mut drafts = String::from(
        "# Suggested issues\n\nHuman-readable drafts for valid issue candidates. v0 is \
         artifact-only: nothing here was posted, suggested in the PR body, or opened on \
         GitHub - those are later release-lane steps.\n",
    );
    let valid_ids = actions
        .iter()
        .filter(|action| matches!(action.action.as_str(), "artifact-only" | "suggested"))
        .map(|action| action.candidate_id.as_str())
        .collect::<BTreeSet<_>>();
    for candidate in candidates {
        if !valid_ids.contains(candidate.id.as_str()) {
            continue;
        }
        drafts.push_str(&format!(
            "\n## {} ({})\n\nProblem: {}\n\nSource lane: {}\n",
            candidate.title, candidate.target_repo, candidate.problem, candidate.source
        ));
        for evidence in &candidate.evidence {
            if let Some(path) = &evidence.path {
                drafts.push_str(&format!("- {}: {path}\n", evidence.kind));
            }
            if let Some(url) = &evidence.url {
                drafts.push_str(&format!("- {}: {url}\n", evidence.kind));
            }
        }
        drafts.push_str(&format!(
            "\nWhy not this PR: {}\n\nImplementation plan:\n",
            candidate.why_not_this_pr
        ));
        for (index, step) in candidate.implementation_plan.iter().enumerate() {
            drafts.push_str(&format!("{}. {step}\n", index + 1));
        }
        drafts.push_str("\nAcceptance:\n");
        for item in &candidate.acceptance {
            drafts.push_str(&format!("- [ ] {item}\n"));
        }
    }
    fs::write(review_dir.join("suggested_issues.md"), drafts)?;
    Ok(())
}

/// The body marker the broker's remote duplicate search keys on. Embedded in
/// every broker-opened issue; searched verbatim before any open attempt.
fn issue_broker_fingerprint_marker(fingerprint: &str) -> String {
    format!("ub-review-fingerprint: {fingerprint}")
}

/// Render the full GitHub issue body for a broker attempt at `run` time so
/// `post` performs zero formatting. Carries the candidate's problem,
/// why-not-this-PR, evidence, plan, acceptance, a provenance line, and the
/// fingerprint marker.
fn issue_broker_body(
    candidate: &IssueCandidate,
    fingerprint: &str,
    source_repo: Option<&str>,
    pull_number: Option<u64>,
) -> String {
    let mut body = format!(
        "{}\n\nWhy not the source PR: {}\n",
        candidate.problem, candidate.why_not_this_pr
    );
    if !candidate.evidence.is_empty() {
        body.push_str("\n## Evidence\n\n");
        for evidence in &candidate.evidence {
            if let Some(path) = &evidence.path {
                body.push_str(&format!("- {}: {path}\n", evidence.kind));
            }
            if let Some(url) = &evidence.url {
                body.push_str(&format!("- {}: {url}\n", evidence.kind));
            }
        }
    }
    body.push_str("\n## Implementation plan\n\n");
    for (index, step) in candidate.implementation_plan.iter().enumerate() {
        body.push_str(&format!("{}. {step}\n", index + 1));
    }
    body.push_str("\n## Acceptance\n\n");
    for item in &candidate.acceptance {
        body.push_str(&format!("- [ ] {item}\n"));
    }
    let provenance = match (source_repo, pull_number) {
        (Some(repo), Some(number)) => {
            format!(
                "opened by ub-review from {repo}#{number}, lane {}",
                candidate.source
            )
        }
        _ => format!("opened by ub-review, lane {}", candidate.source),
    };
    body.push_str(&format!(
        "\n---\n{provenance}\n{}\n",
        issue_broker_fingerprint_marker(fingerprint)
    ));
    body
}

/// Decide at `run` time what the post-time broker may do. Pure: only
/// `suggested` candidates are considered, in ledger order; each becomes an
/// `attempt` (valid allowlisted slug, under `open_cap`) or a `skip` with the
/// reason recorded. Returns an empty plan unless mode is
/// open-high-confidence. No silent caps: cap-excluded candidates appear as
/// skips.
fn build_issue_broker_plan(
    issues: &IssuesConfig,
    candidates: &[IssueCandidate],
    actions: &[IssueAction],
    source_repo: Option<&str>,
    pull_number: Option<u64>,
) -> Vec<IssueBrokerPlanEntry> {
    if !issues.enabled || issues.mode != "open-high-confidence" {
        return Vec::new();
    }
    let by_id: BTreeMap<&str, &IssueCandidate> = candidates
        .iter()
        .map(|candidate| (candidate.id.as_str(), candidate))
        .collect();
    let mut plan = Vec::new();
    let mut attempts = 0u32;
    for action in actions {
        if action.action != "suggested" {
            continue;
        }
        let Some(candidate) = by_id.get(action.candidate_id.as_str()) else {
            continue;
        };
        let fingerprint = issue_candidate_fingerprint(candidate);
        let (decision, reason) = if !is_valid_repo_slug(&candidate.target_repo) {
            (
                "skip",
                "target repo is not a valid owner/repo slug".to_owned(),
            )
        } else if !issues
            .open_in
            .iter()
            .any(|allowed| allowed == &candidate.target_repo)
        {
            (
                "skip",
                "target repo is not in the issues.open_in allowlist; the candidate \
                 stays suggested"
                    .to_owned(),
            )
        } else if attempts >= issues.open_cap {
            (
                "skip",
                format!(
                    "issues.open_cap={} reached for this post; the candidate stays \
                     suggested",
                    issues.open_cap
                ),
            )
        } else {
            attempts += 1;
            (
                "attempt",
                "high-confidence do-not-block candidate targeting an allowlisted \
                 repo; post runs a fingerprint duplicate search before opening"
                    .to_owned(),
            )
        };
        plan.push(IssueBrokerPlanEntry {
            schema: ISSUE_BROKER_PLAN_SCHEMA.to_owned(),
            candidate_id: candidate.id.clone(),
            fingerprint: fingerprint.clone(),
            target_repo: candidate.target_repo.clone(),
            decision: decision.to_owned(),
            reason,
            title: candidate.title.clone(),
            body: issue_broker_body(candidate, &fingerprint, source_repo, pull_number),
            labels: candidate.labels.clone(),
        });
    }
    plan
}

/// Persist the broker plan (review/issue_broker_plan.json + NDJSON twin).
/// Written only when the broker is opted in; an absent file means mode never
/// reached open-high-confidence, an empty list means it did and there was
/// nothing suggested.
fn write_issue_broker_plan(out: &Path, plan: &[IssueBrokerPlanEntry]) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("issue_broker_plan.json"),
        serde_json::to_vec_pretty(plan)?,
    )?;
    let mut lines = String::new();
    for entry in plan {
        lines.push_str(&serde_json::to_string(entry)?);
        lines.push('\n');
    }
    fs::write(out.join("issue_broker_plan.ndjson"), lines)?;
    Ok(())
}

fn resolved_candidate_records(
    candidates: &[CandidateRecord],
    follow_up_results: &[FollowUpResult],
    follow_up_outputs: &[FollowUpOutputRecord],
) -> Vec<ResolvedCandidateRecord> {
    let follow_up_result_task_ids = follow_up_results
        .iter()
        .map(|result| result.task_id.clone())
        .collect::<BTreeSet<_>>();
    candidates
        .iter()
        .map(|candidate| {
            let linked_outputs = follow_up_outputs
                .iter()
                .filter(|output| {
                    follow_up_result_task_ids.contains(&output.task_id)
                        && output.candidate_ids.iter().any(|id| id == &candidate.id)
                })
                .collect::<Vec<_>>();
            resolved_candidate_record(candidate, &linked_outputs)
        })
        .collect()
}

/// Candidate ids whose follow-up outputs resolved them to `refuted` or
/// `dropped`. The final compiler excludes these candidates' original review
/// surfaces: the late receipt turn exists to change dispositions (confirm,
/// refute, or demote), so a refutation that only reached an artifact would
/// leave the posted review contradicting the run's own evidence.
/// `parked-follow-up` resolutions are deliberately not in this set — parked
/// items keep their surface and render in the parked section.
fn follow_up_resolved_away_candidate_ids(
    resolved_candidates: &[ResolvedCandidateRecord],
) -> Vec<String> {
    resolved_candidates
        .iter()
        .filter(|record| {
            record.resolved_status == "resolved"
                && matches!(record.resolved_disposition.as_str(), "refuted" | "dropped")
        })
        .map(|record| record.candidate_id.clone())
        .collect()
}

/// Inline-comment candidates are built 1:1 from `ReviewInlineComment` in
/// `build_candidate_records`, so matching back uses the same fields the
/// fingerprint hashed: lane, path, line, and body-as-claim.
fn candidate_matches_inline_comment(
    candidate: &CandidateRecord,
    comment: &ReviewInlineComment,
) -> bool {
    candidate.source == "inline-comment"
        && candidate.lane == comment.lane
        && candidate.path.as_deref() == Some(comment.path.as_str())
        && candidate.line == Some(comment.line)
        && candidate.claim == comment.body
}

/// Summary-only candidates are built 1:1 from `SummaryOnlyFinding` in
/// `build_candidate_records`; matching back uses lane, reason-as-claim, and
/// evidence.
fn candidate_matches_summary_finding(
    candidate: &CandidateRecord,
    finding: &SummaryOnlyFinding,
) -> bool {
    candidate.source == "summary-only-finding"
        && candidate.lane == finding.lane
        && candidate.claim == finding.reason
        && candidate.evidence == finding.evidence
}

fn resolved_candidate_record(
    candidate: &CandidateRecord,
    follow_up_outputs: &[&FollowUpOutputRecord],
) -> ResolvedCandidateRecord {
    let follow_up_task_ids = unique_follow_up_values(follow_up_outputs, |output| &output.task_id);
    let follow_up_stages = unique_follow_up_values(follow_up_outputs, |output| &output.stage);
    let follow_up_statuses = unique_follow_up_values(follow_up_outputs, |output| &output.status);
    let (resolved_status, resolved_disposition, resolution_source, reason, evidence) =
        resolve_candidate_from_follow_ups(candidate, follow_up_outputs);
    ResolvedCandidateRecord {
        schema: RESOLVED_CANDIDATE_SCHEMA.to_owned(),
        candidate_id: candidate.id.clone(),
        lane: candidate.lane.clone(),
        source: candidate.source.clone(),
        original_status: candidate.status.clone(),
        original_disposition: candidate.disposition.clone(),
        resolved_status,
        resolved_disposition,
        resolution_source,
        source_artifacts: vec![
            "review/candidates.json".to_owned(),
            "review/follow_up_results.json".to_owned(),
            "review/follow_up_outputs.json".to_owned(),
        ],
        reason,
        follow_up_task_ids,
        follow_up_stages,
        follow_up_statuses,
        evidence,
    }
}

fn unique_follow_up_values<F>(follow_up_outputs: &[&FollowUpOutputRecord], value: F) -> Vec<String>
where
    F: Fn(&FollowUpOutputRecord) -> &String,
{
    let mut values = Vec::new();
    for output in follow_up_outputs {
        let value = value(output).clone();
        if !values.contains(&value) {
            values.push(value);
        }
    }
    values
}

fn resolve_candidate_from_follow_ups(
    candidate: &CandidateRecord,
    follow_up_outputs: &[&FollowUpOutputRecord],
) -> (String, String, String, String, Vec<String>) {
    if follow_up_outputs.is_empty() {
        return (
            "unchanged".to_owned(),
            candidate.disposition.clone(),
            "candidate".to_owned(),
            "no candidate-targeted follow-up output".to_owned(),
            vec![format!(
                "Original candidate disposition `{}`",
                candidate.disposition
            )],
        );
    }

    let mut signals = resolved_candidate_signals(follow_up_outputs);
    if !signals.is_empty() {
        let dispositions = signals
            .iter()
            .map(|signal| signal.disposition)
            .collect::<BTreeSet<_>>();
        if dispositions.len() > 1 {
            return (
                "conflicting".to_owned(),
                candidate.disposition.clone(),
                "orchestrator-follow-up".to_owned(),
                "candidate-targeted follow-ups produced conflicting disposition signals".to_owned(),
                signals
                    .into_iter()
                    .flat_map(|signal| signal.evidence)
                    .collect(),
            );
        }
        let signal = signals.remove(0);
        return (
            "resolved".to_owned(),
            signal.disposition.to_owned(),
            "orchestrator-follow-up".to_owned(),
            signal.reason,
            signal.evidence,
        );
    }

    let evidence = follow_up_outputs
        .iter()
        .map(|output| {
            format!(
                "Follow-up task `{}` stage `{}` status `{}`",
                output.task_id, output.stage, output.status
            )
        })
        .collect::<Vec<_>>();
    if follow_up_outputs
        .iter()
        .any(|output| matches!(output.status.as_str(), "ok" | "degraded"))
    {
        (
            "unresolved".to_owned(),
            candidate.disposition.clone(),
            "orchestrator-follow-up".to_owned(),
            "candidate-targeted follow-up ran without a refuted, parked, or dropped disposition"
                .to_owned(),
            evidence,
        )
    } else {
        (
            "follow-up-unavailable".to_owned(),
            candidate.disposition.clone(),
            "orchestrator-follow-up".to_owned(),
            "candidate-targeted follow-up did not produce usable model output".to_owned(),
            evidence,
        )
    }
}

struct ResolvedCandidateSignal {
    disposition: &'static str,
    reason: String,
    evidence: Vec<String>,
}

fn resolved_candidate_signals(
    follow_up_outputs: &[&FollowUpOutputRecord],
) -> Vec<ResolvedCandidateSignal> {
    let mut signals = Vec::new();
    for output in follow_up_outputs {
        if let Some(evidence) = follow_up_refuted_evidence(output) {
            signals.push(ResolvedCandidateSignal {
                disposition: "refuted",
                reason: format!("follow-up task `{}` refuted the candidate", output.task_id),
                evidence,
            });
        }
    }
    for output in follow_up_outputs {
        if let Some(evidence) = follow_up_parked_evidence(output) {
            signals.push(ResolvedCandidateSignal {
                disposition: "parked-follow-up",
                reason: format!("follow-up task `{}` parked the candidate", output.task_id),
                evidence,
            });
        }
    }
    for output in follow_up_outputs {
        if let Some(evidence) = follow_up_dropped_evidence(output) {
            signals.push(ResolvedCandidateSignal {
                disposition: "dropped",
                reason: format!("follow-up task `{}` dropped the candidate", output.task_id),
                evidence,
            });
        }
    }
    signals
}

fn follow_up_refuted_evidence(output: &FollowUpOutputRecord) -> Option<Vec<String>> {
    if output.observations.iter().any(observation_is_refuted) {
        return Some(vec![format!(
            "Follow-up `{}` emitted a refuted/resolved observation",
            output.task_id
        )]);
    }
    output
        .summary_only_findings
        .iter()
        .find(|finding| candidate_disposition_for_summary_finding(finding) == "refuted")
        .map(|finding| vec![format!("Follow-up summary: {}", finding.reason)])
}

fn follow_up_parked_evidence(output: &FollowUpOutputRecord) -> Option<Vec<String>> {
    if output.observations.iter().any(observation_is_parked) {
        return Some(vec![format!(
            "Follow-up `{}` emitted a parked observation",
            output.task_id
        )]);
    }
    output
        .summary_only_findings
        .iter()
        .find(|finding| candidate_disposition_for_summary_finding(finding) == "parked-follow-up")
        .map(|finding| vec![format!("Follow-up summary: {}", finding.reason)])
}

fn follow_up_dropped_evidence(output: &FollowUpOutputRecord) -> Option<Vec<String>> {
    output
        .summary_only_findings
        .iter()
        .find(|finding| candidate_disposition_for_summary_finding(finding) == "dropped")
        .map(|finding| vec![format!("Follow-up summary: {}", finding.reason)])
}

fn observation_is_refuted(observation: &Observation) -> bool {
    observation.status == "refuted"
}

fn observation_is_parked(observation: &Observation) -> bool {
    observation.status == "parked"
}

fn write_model_stage_artifacts(
    out: &Path,
    model_lanes: &[ModelLaneReceipt],
    follow_up_results: &[FollowUpResult],
    args: &RunArgs,
) -> Result<()> {
    let records = model_stage_records(model_lanes, follow_up_results, args);
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("model_stages.json"),
        serde_json::to_vec_pretty(&records)?,
    )?;
    let mut ndjson = String::new();
    for record in &records {
        ndjson.push_str(&serde_json::to_string(record)?);
        ndjson.push('\n');
    }
    fs::write(out.join("model_stages.ndjson"), ndjson)?;
    Ok(())
}

fn write_final_compiler_input_artifact(
    out: &Path,
    artifact: FinalCompilerInputArtifact<'_>,
) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("final_compiler_input.json"),
        serde_json::to_vec_pretty(&artifact)?,
    )?;
    Ok(())
}

fn model_stage_records(
    model_lanes: &[ModelLaneReceipt],
    follow_up_results: &[FollowUpResult],
    args: &RunArgs,
) -> Vec<ModelStageRecord> {
    let mut records = model_lanes
        .iter()
        .map(model_lane_stage_record)
        .collect::<Vec<_>>();
    let follow_up_spec = direct_minimax_spec(args);
    records.extend(
        follow_up_results
            .iter()
            .map(|result| follow_up_stage_record(result, &follow_up_spec)),
    );
    records
}

fn model_lane_stage_record(receipt: &ModelLaneReceipt) -> ModelStageRecord {
    let (source, stage, stage_reason) = model_lane_stage_metadata(&receipt.lane);
    ModelStageRecord {
        schema: MODEL_STAGE_SCHEMA.to_owned(),
        lane: receipt.lane.clone(),
        source: source.to_owned(),
        stage: stage.to_owned(),
        stage_reason: stage_reason.to_owned(),
        status: receipt.status.clone(),
        reason: receipt.reason.clone(),
        provider: receipt.provider.clone(),
        model: receipt.model.clone(),
        endpoint_kind: receipt.endpoint_kind.clone(),
        task_id: None,
        group_id: None,
        packet_path: None,
        duration_ms: receipt.duration_ms,
        http_status: receipt.http_status,
        response_shape: receipt.response_shape.clone(),
        cache_usage: receipt.cache_usage.clone(),
    }
}

fn model_lane_stage_metadata(lane: &str) -> (&'static str, &'static str, &'static str) {
    match lane {
        "proof-planner" => (
            "proof-planner",
            "primary",
            "proof-planner scopes local proof from the shared packet and early lane evidence",
        ),
        "refuter" => (
            "refuter",
            "tertiary",
            "refuter classifies primary candidates before the final compiler pass",
        ),
        _ => (
            "model-lane",
            "primary",
            "initial cached lane turn over the shared PR packet",
        ),
    }
}

fn follow_up_stage_record(result: &FollowUpResult, spec: &ProviderSpec) -> ModelStageRecord {
    ModelStageRecord {
        schema: MODEL_STAGE_SCHEMA.to_owned(),
        lane: result.model_lane.clone(),
        source: "orchestrator-follow-up".to_owned(),
        stage: result.stage.clone(),
        stage_reason: follow_up_stage_reason(&result.stage).to_owned(),
        status: result.status.clone(),
        reason: result.reason.clone(),
        provider: spec.provider.key().to_owned(),
        model: spec.model.clone(),
        endpoint_kind: spec.endpoint_kind.key().to_owned(),
        task_id: Some(result.task_id.clone()),
        group_id: Some(result.group_id.clone()),
        packet_path: Some(result.packet_path.clone()),
        duration_ms: result.duration_ms,
        http_status: result.http_status,
        response_shape: result.response_shape.clone(),
        cache_usage: result.cache_usage.clone(),
    }
}

fn follow_up_evidence_from_outputs(outputs: &[FollowUpOutputRecord]) -> FollowUpEvidenceArtifact {
    let mut inline_comments = Vec::new();
    let mut summary_only_findings = Vec::new();
    let mut observations = Vec::new();
    let mut proof_requests = Vec::new();
    for output in outputs {
        inline_comments.extend(output.inline_comments.iter().cloned());
        summary_only_findings.extend(output.summary_only_findings.iter().cloned());
        observations.extend(output.observations.iter().cloned());
        proof_requests.extend(output.proof_requests.iter().cloned());
    }
    FollowUpEvidenceArtifact {
        schema: FOLLOW_UP_EVIDENCE_SCHEMA.to_owned(),
        follow_up_outputs: outputs.len(),
        inline_comments,
        summary_only_findings,
        observations,
        proof_requests,
    }
}

fn write_follow_up_evidence_artifact(
    out: &Path,
    evidence: &FollowUpEvidenceArtifact,
) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("follow_up_evidence.json"),
        serde_json::to_vec_pretty(evidence)?,
    )?;
    Ok(())
}

fn write_follow_up_question_packets(
    out: &Path,
    tasks: &[FollowUpQuestionTask],
    proof_receipts: &[ProofReceipt],
) -> Result<()> {
    let follow_up_dir = out.join("questions").join("orchestrator-follow-up");
    if follow_up_dir.exists() {
        fs::remove_dir_all(&follow_up_dir)
            .with_context(|| format!("remove {}", follow_up_dir.display()))?;
    }
    if tasks.is_empty() {
        return Ok(());
    }
    fs::create_dir_all(&follow_up_dir)
        .with_context(|| format!("create {}", follow_up_dir.display()))?;
    for task in tasks {
        // Excerpts are resolved at packet-write time so the packet artifact
        // records exactly the prompt the model later receives.
        let excerpts = routed_receipt_excerpts_for_task(out, task, proof_receipts);
        let packet = follow_up_question_packet(task, &excerpts);
        fs::write(
            follow_up_dir.join(format!("{}.json", sanitize_artifact_name(&task.id))),
            serde_json::to_vec_pretty(&packet)?,
        )?;
    }
    Ok(())
}

fn follow_up_question_packet<'a>(
    task: &'a FollowUpQuestionTask,
    routed_excerpts: &BTreeMap<String, String>,
) -> FollowUpQuestionPacket<'a> {
    FollowUpQuestionPacket {
        schema: FOLLOW_UP_QUESTION_PACKET_SCHEMA,
        id: task.id.as_str(),
        task_id: task.id.as_str(),
        group_id: task.group_id.as_str(),
        stage: task.stage.as_str(),
        stage_reason: task.stage_reason.as_str(),
        evidence_need: task.evidence_need.as_str(),
        disposition: task.disposition.as_str(),
        candidate_ids: &task.candidate_ids,
        observation_group_ids: &task.observation_group_ids,
        routed_evidence: &task.routed_evidence,
        question: task.question.as_str(),
        status: task.status.as_str(),
        source_artifact: "review/orchestrator_plan.json",
        prompt: render_follow_up_question_prompt(task, routed_excerpts),
    }
}

fn render_follow_up_question_prompt(
    task: &FollowUpQuestionTask,
    routed_excerpts: &BTreeMap<String, String>,
) -> String {
    let mut prompt = String::new();
    prompt.push_str("Follow-up question task\n\n");
    prompt.push_str(&format!("- Task: `{}`\n", task.id));
    prompt.push_str(&format!("- Group: `{}`\n", task.group_id));
    prompt.push_str(&format!(
        "- Stage: `{}` - {}\n",
        task.stage, task.stage_reason
    ));
    prompt.push_str(&format!("- Evidence need: `{}`\n", task.evidence_need));
    prompt.push_str(&format!("- Disposition: `{}`\n", task.disposition));
    if !task.candidate_ids.is_empty() {
        prompt.push_str(&format!(
            "- Candidate ids: `{}`\n",
            task.candidate_ids.join("`, `")
        ));
    }
    if !task.observation_group_ids.is_empty() {
        prompt.push_str(&format!(
            "- Observation group ids: `{}`\n",
            task.observation_group_ids.join("`, `")
        ));
    }
    prompt.push_str(&format!("\nQuestion: {}\n\n", task.question));
    if task.routed_evidence.is_empty() {
        prompt.push_str("Routed evidence: none.\n\n");
    } else {
        prompt.push_str("Routed evidence:\n");
        for evidence in &task.routed_evidence {
            prompt.push_str(&format!(
                "- `{}` kind=`{}` status=`{}` result=`{}` artifact=`{}` reason={}\n",
                evidence.id,
                evidence.kind,
                evidence.status,
                evidence.result,
                evidence.artifact,
                evidence.reason
            ));
            if let Some(excerpt) = routed_excerpts.get(&evidence.id) {
                prompt.push_str(
                    "  Receipt content (bounded command-output tails; full streams in the artifact):\n",
                );
                prompt.push_str(excerpt);
            }
        }
        prompt.push('\n');
    }
    match task.stage.as_str() {
        "tertiary" => prompt.push_str(
            "Stage instruction: use routed evidence to refine, refute, drop, or park the concern; do not repeat an already-resolved question.\n",
        ),
        _ => prompt.push_str(
            "Stage instruction: identify the smallest remaining evidence or proof request needed before promotion.\n",
        ),
    }
    prompt.push_str(
        &format!(
            "Return strict JSON with observations, summary_only_findings, failed_objections, and proof_requests. Use question `{}` for observations. Do not emit candidate_findings or inline_comments. Do not post, mutate, or run shell commands.\n",
            task.id
        ),
    );
    prompt
}

fn candidate_evidence_need(candidate: &CandidateRecord) -> String {
    match candidate.disposition.as_str() {
        "inline" => "accepted-inline-review".to_owned(),
        "parked-follow-up" => "parked-follow-up-confirmation".to_owned(),
        "refuted" => "refutation-confirmation".to_owned(),
        "dropped" => "dropped-candidate-audit".to_owned(),
        _ => {
            let text = format!("{}\n{}", candidate.claim, candidate.evidence).to_ascii_lowercase();
            if text.contains("proof") || text.contains("red") || text.contains("green") {
                "proof-confirmation".to_owned()
            } else if text.contains("route") || text.contains("sibling") {
                "source-route-confirmation".to_owned()
            } else if text.contains("test") || text.contains("oracle") {
                "test-oracle-confirmation".to_owned()
            } else {
                "summary-confirmation".to_owned()
            }
        }
    }
}

fn observation_evidence_need(observation: &ObservationGroup) -> String {
    if is_refutation_confirmation_observation(observation) {
        return "refutation-confirmation".to_owned();
    }
    if is_parked_observation(observation) {
        return "parked-follow-up-confirmation".to_owned();
    }
    if observation.kind == "test-gap" {
        return "test-oracle-confirmation".to_owned();
    }
    if observation.kind == "source-route-gap" {
        return "source-route-confirmation".to_owned();
    }

    let text =
        format!("{}\n{}", observation.claim, observation.evidence.join("\n")).to_ascii_lowercase();
    if text.contains("proof")
        || text.contains("red")
        || text.contains("green")
        || text.contains("base+tests")
    {
        "proof-confirmation".to_owned()
    } else if text.contains("route") || text.contains("sibling") {
        "source-route-confirmation".to_owned()
    } else if text.contains("test") || text.contains("oracle") {
        "test-oracle-confirmation".to_owned()
    } else if is_missing_evidence_observation(observation) {
        "evidence-gap-confirmation".to_owned()
    } else if is_residual_risk_observation(observation) {
        "residual-risk-confirmation".to_owned()
    } else {
        "observation-confirmation".to_owned()
    }
}

fn follow_up_task_for_group(
    group_id: &str,
    disposition: &str,
    evidence_need: &str,
    candidate_ids: &[String],
    routed_evidence: &[OrchestratorRoutedEvidence],
) -> Option<FollowUpQuestionTask> {
    if matches!(disposition, "inline" | "dropped") {
        return None;
    }
    let fingerprint = sha256_hex(format!("{group_id}\n{evidence_need}").as_bytes());
    let stage = follow_up_stage(disposition, evidence_need, routed_evidence);
    Some(FollowUpQuestionTask {
        schema: FOLLOW_UP_QUESTION_SCHEMA.to_owned(),
        id: format!("follow-up-{}", &fingerprint[..12]),
        group_id: group_id.to_owned(),
        stage: stage.to_owned(),
        stage_reason: follow_up_stage_reason(stage).to_owned(),
        evidence_need: evidence_need.to_owned(),
        disposition: disposition.to_owned(),
        candidate_ids: candidate_ids.to_vec(),
        observation_group_ids: Vec::new(),
        routed_evidence: routed_evidence.to_vec(),
        question: follow_up_question_text(disposition, evidence_need),
        status: "planned".to_owned(),
        reason: "deterministic orchestrator skeleton; no shell commands or posting side effects"
            .to_owned(),
    })
}

fn follow_up_task_for_observation_group(
    observation: &ObservationGroup,
    group: &OrchestratorObservationGroup,
    routed_evidence: &[OrchestratorRoutedEvidence],
) -> Option<FollowUpQuestionTask> {
    if is_pr_body_artifact_only_observation(observation)
        || matches!(observation.status.as_str(), "covered" | "duplicate")
    {
        return None;
    }
    let fingerprint = sha256_hex(format!("{}\n{}", group.id, group.evidence_need).as_bytes());
    let stage = follow_up_stage("observation", &group.evidence_need, routed_evidence);
    Some(FollowUpQuestionTask {
        schema: FOLLOW_UP_QUESTION_SCHEMA.to_owned(),
        id: format!("follow-up-{}", &fingerprint[..12]),
        group_id: group.id.clone(),
        stage: stage.to_owned(),
        stage_reason: follow_up_stage_reason(stage).to_owned(),
        evidence_need: group.evidence_need.clone(),
        disposition: "observation".to_owned(),
        candidate_ids: Vec::new(),
        observation_group_ids: vec![observation.id.clone()],
        routed_evidence: routed_evidence.to_vec(),
        question: observation_follow_up_question_text(&group.evidence_need),
        status: "planned".to_owned(),
        reason: "deterministic observation follow-up; no shell commands or posting side effects"
            .to_owned(),
    })
}

fn follow_up_stage(
    disposition: &str,
    evidence_need: &str,
    routed_evidence: &[OrchestratorRoutedEvidence],
) -> &'static str {
    if !routed_evidence.is_empty()
        || matches!(disposition, "refuted" | "parked-follow-up")
        || matches!(
            evidence_need,
            "refutation-confirmation" | "parked-follow-up-confirmation"
        )
    {
        "tertiary"
    } else {
        "secondary"
    }
}

fn follow_up_stage_reason(stage: &str) -> &'static str {
    match stage {
        "tertiary" => {
            "routed evidence or prior disposition is available; refine, refute, drop, or park instead of restating the concern"
        }
        _ => {
            "no routed proof receipt is available; ask for the smallest remaining evidence or proof request"
        }
    }
}

fn routed_evidence_for_group(
    evidence_need: &str,
    lanes: &[String],
    proof_receipts: &[ProofReceipt],
    resource_leases: &[ResourceLease],
) -> Vec<OrchestratorRoutedEvidence> {
    if !matches!(
        evidence_need,
        "proof-confirmation" | "test-oracle-confirmation"
    ) {
        return Vec::new();
    }
    let mut routed = Vec::new();
    for receipt in proof_receipts {
        if !proof_receipt_routes_to_lanes(receipt, lanes) {
            continue;
        }
        routed.push(proof_receipt_routed_evidence(receipt));
        for lease in resource_leases
            .iter()
            .filter(|lease| lease.consumer == receipt.id)
        {
            routed.push(resource_lease_routed_evidence(lease));
        }
    }
    routed
}

/// Byte caps for routed receipt-content tails. The second model turn judges
/// proof it was routed, so prompts carry bounded command-output tails instead
/// of only artifact pointers (the runner owns the read; direct provider lanes
/// cannot open files mid-call). stderr gets the larger budget: failure text
/// lives there.
const ROUTED_RECEIPT_STDERR_TAIL_BYTES: usize = 1200;
const ROUTED_RECEIPT_STDOUT_TAIL_BYTES: usize = 600;

/// Bounded content excerpt for a routed proof receipt, or `None` for
/// non-receipt evidence kinds and unknown receipt ids. Each command
/// contributes its status line plus lossy-decoded byte tails of stderr and
/// stdout with explicit truncation markers, so follow-up packets stay
/// bounded no matter how loud the proof command was.
fn routed_proof_receipt_excerpt(
    out: &Path,
    evidence: &OrchestratorRoutedEvidence,
    proof_receipts: &[ProofReceipt],
) -> Option<String> {
    if evidence.kind != "proof-receipt" {
        return None;
    }
    let receipt = proof_receipts
        .iter()
        .find(|receipt| receipt.id == evidence.id)?;
    let mut excerpt = String::new();
    for command in &receipt.commands {
        excerpt.push_str(&format!(
            "  command `{}` side=`{}` status=`{}` exit={:?}\n",
            command.command, command.side, command.status, command.exit_code
        ));
        for (label, relative, cap) in [
            ("stderr", &command.stderr, ROUTED_RECEIPT_STDERR_TAIL_BYTES),
            ("stdout", &command.stdout, ROUTED_RECEIPT_STDOUT_TAIL_BYTES),
        ] {
            if relative.is_empty() {
                continue;
            }
            match fs::read(out.join(relative)) {
                Ok(bytes) if bytes.is_empty() => {
                    excerpt.push_str(&format!("    {label}: (empty)\n"));
                }
                Ok(bytes) => {
                    let truncated = bytes.len() > cap;
                    let mut start = bytes.len().saturating_sub(cap);
                    // Trim forward to a UTF-8 boundary so a mid-character
                    // byte cut cannot produce lossy-decode drift against the
                    // verifier's Python mirror of this excerpt.
                    while start < bytes.len() && (bytes[start] & 0xC0) == 0x80 {
                        start += 1;
                    }
                    let tail = String::from_utf8_lossy(&bytes[start..]);
                    if truncated {
                        excerpt.push_str(&format!(
                            "    {label} (last {cap} bytes of {total}):\n",
                            total = bytes.len()
                        ));
                    } else {
                        excerpt.push_str(&format!("    {label}:\n"));
                    }
                    for line in tail.lines() {
                        excerpt.push_str("      ");
                        excerpt.push_str(line);
                        excerpt.push('\n');
                    }
                }
                Err(_) => {
                    // An unreadable stream is reported, never silently
                    // dropped: the model should know the excerpt is partial.
                    excerpt.push_str(&format!("    {label}: (unavailable at `{relative}`)\n"));
                }
            }
        }
    }
    (!excerpt.is_empty()).then_some(excerpt)
}

/// Per-evidence-id excerpts for one follow-up task.
fn routed_receipt_excerpts_for_task(
    out: &Path,
    task: &FollowUpQuestionTask,
    proof_receipts: &[ProofReceipt],
) -> BTreeMap<String, String> {
    task.routed_evidence
        .iter()
        .filter_map(|evidence| {
            routed_proof_receipt_excerpt(out, evidence, proof_receipts)
                .map(|excerpt| (evidence.id.clone(), excerpt))
        })
        .collect()
}

fn proof_receipt_routes_to_lanes(receipt: &ProofReceipt, lanes: &[String]) -> bool {
    receipt
        .requested_by
        .iter()
        .any(|lane| lane == "proof-broker")
        || receipt
            .requested_by
            .iter()
            .any(|lane| lanes.iter().any(|group_lane| group_lane == lane))
}

fn proof_receipt_routed_evidence(receipt: &ProofReceipt) -> OrchestratorRoutedEvidence {
    OrchestratorRoutedEvidence {
        schema: ORCHESTRATOR_ROUTED_EVIDENCE_SCHEMA.to_owned(),
        id: receipt.id.clone(),
        kind: "proof-receipt".to_owned(),
        artifact: "review/proof_receipts.json".to_owned(),
        status: routed_status_for_proof_receipt(receipt).to_owned(),
        result: receipt.result.clone(),
        reason: receipt.reason.clone(),
    }
}

fn resource_lease_routed_evidence(lease: &ResourceLease) -> OrchestratorRoutedEvidence {
    OrchestratorRoutedEvidence {
        schema: ORCHESTRATOR_ROUTED_EVIDENCE_SCHEMA.to_owned(),
        id: lease.id.clone(),
        kind: "resource-lease".to_owned(),
        artifact: "review/resource_leases.json".to_owned(),
        status: lease.status.clone(),
        result: lease.status.clone(),
        reason: lease.reason.clone(),
    }
}

fn routed_status_for_proof_receipt(receipt: &ProofReceipt) -> &'static str {
    if proof_receipt_is_test_proof_result(receipt) {
        "tool-confirmed"
    } else if proof_receipt_is_missing_evidence(receipt) {
        "missing-evidence"
    } else if proof_receipt_is_residual_risk(receipt) {
        "residual-risk"
    } else {
        "recorded"
    }
}

fn observation_follow_up_question_text(evidence_need: &str) -> String {
    match evidence_need {
        "proof-confirmation" => {
            "Confirm whether routed proof evidence resolves this observation.".to_owned()
        }
        "source-route-confirmation" => {
            "Confirm the changed source route or sibling path before promoting this observation."
                .to_owned()
        }
        "test-oracle-confirmation" => {
            "Confirm the test oracle strength before promoting this observation.".to_owned()
        }
        "refutation-confirmation" => {
            "Confirm the observation refutation still matches current PR evidence.".to_owned()
        }
        "parked-follow-up-confirmation" => {
            "Confirm whether this observation remains parked outside current PR scope.".to_owned()
        }
        "evidence-gap-confirmation" => {
            "Confirm whether this observation is still trust-affecting missing evidence.".to_owned()
        }
        "residual-risk-confirmation" => {
            "Confirm whether this observation remains specific residual risk.".to_owned()
        }
        _ => "Confirm whether this observation needs promotion, refutation, or parking.".to_owned(),
    }
}

fn follow_up_question_text(disposition: &str, evidence_need: &str) -> String {
    match (disposition, evidence_need) {
        ("refuted", _) => "Confirm the refutation still matches the current PR evidence.".to_owned(),
        ("parked-follow-up", _) => {
            "Confirm whether this parked follow-up should remain outside current PR scope.".to_owned()
        }
        (_, "proof-confirmation") => {
            "Confirm whether focused proof can resolve this summary-only candidate.".to_owned()
        }
        (_, "source-route-confirmation") => {
            "Confirm the changed source route or sibling path before promoting this candidate."
                .to_owned()
        }
        (_, "test-oracle-confirmation") => {
            "Confirm the test oracle strength before promoting this candidate.".to_owned()
        }
        _ => "Confirm whether additional evidence should promote or keep this candidate summary-only."
            .to_owned(),
    }
}

fn orchestrator_group_reason(disposition: &str, evidence_need: &str) -> String {
    format!("grouped candidate disposition `{disposition}` under evidence need `{evidence_need}`")
}

fn unique_sorted(values: Vec<String>) -> Vec<String> {
    values
        .into_iter()
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect()
}

struct WitnessRecordInput<'a> {
    status: &'a str,
    kind: &'a str,
    source: &'a str,
    claim: &'a str,
    dedupe_key: &'a str,
    evidence: Vec<String>,
    lane: Option<String>,
    path: Option<String>,
    line: Option<u32>,
    observation_id: Option<String>,
    proof_receipt_id: Option<String>,
}

fn witness_record(input: WitnessRecordInput<'_>) -> WitnessRecord {
    let fingerprint = sha256_hex(
        format!(
            "{}\n{}\n{}\n{}",
            input.status, input.kind, input.source, input.dedupe_key
        )
        .as_bytes(),
    );
    WitnessRecord {
        schema: WITNESS_SCHEMA.to_owned(),
        id: format!("witness-{}", &fingerprint[..12]),
        status: input.status.to_owned(),
        kind: input.kind.to_owned(),
        source: input.source.to_owned(),
        claim: input.claim.to_owned(),
        dedupe_key: input.dedupe_key.to_owned(),
        evidence: non_empty_evidence(input.evidence, "witness registry source artifact"),
        lane: input.lane,
        path: input.path,
        line: input.line,
        observation_id: input.observation_id,
        proof_receipt_id: input.proof_receipt_id,
    }
}

fn witness_status_for_summary_finding(finding: &SummaryOnlyFinding) -> &'static str {
    if is_parked_follow_up(finding) {
        "parked"
    } else {
        "needs-witness"
    }
}

fn witness_status_for_observation(observation: &Observation) -> &'static str {
    if observation.status == "refuted"
        || matches!(
            observation.kind.as_str(),
            "false-premise" | "resolved-check"
        )
    {
        "refuted"
    } else if observation.status == "parked" || observation.kind == "parked-follow-up" {
        "parked"
    } else if observation.status == "confirmed"
        || matches!(observation.kind.as_str(), "bug" | "security-risk")
    {
        "tool-confirmed"
    } else {
        "needs-witness"
    }
}

fn witness_status_for_proof_receipt(receipt: &ProofReceipt) -> &'static str {
    match receipt.result.as_str() {
        "discriminating" | "head_passed" | "head_failed" => "tool-confirmed",
        _ => "needs-witness",
    }
}

fn proof_receipt_witness_evidence(receipt: &ProofReceipt) -> Vec<String> {
    let mut evidence = Vec::new();
    for command in &receipt.commands {
        evidence.push(format!(
            "{} `{}` status=`{}` reason=`{}` stdout=`{}` stderr=`{}`",
            command.side,
            command.command,
            command.status,
            command.reason,
            command.stdout,
            command.stderr
        ));
    }
    if evidence.is_empty() {
        evidence.push(receipt.reason.clone());
    }
    evidence
}

fn witness_registry_artifact(witnesses: &[WitnessRecord]) -> WitnessRegistryArtifact {
    let mut status_counts = BTreeMap::new();
    let mut kind_counts = BTreeMap::new();
    let mut source_counts = BTreeMap::new();
    let mut follow_up_status_counts = BTreeMap::new();
    let mut witness_ids_by_status: BTreeMap<String, Vec<String>> = BTreeMap::new();
    let mut follow_up_witness_ids_by_status: BTreeMap<String, Vec<String>> = BTreeMap::new();
    let mut follow_up_total = 0;

    for witness in witnesses {
        *status_counts.entry(witness.status.clone()).or_insert(0) += 1;
        *kind_counts.entry(witness.kind.clone()).or_insert(0) += 1;
        *source_counts.entry(witness.source.clone()).or_insert(0) += 1;
        witness_ids_by_status
            .entry(witness.status.clone())
            .or_default()
            .push(witness.id.clone());

        if witness.source.starts_with("follow-up-") {
            follow_up_total += 1;
            *follow_up_status_counts
                .entry(witness.status.clone())
                .or_insert(0) += 1;
            follow_up_witness_ids_by_status
                .entry(witness.status.clone())
                .or_default()
                .push(witness.id.clone());
        }
    }

    WitnessRegistryArtifact {
        schema: WITNESS_REGISTRY_SCHEMA.to_owned(),
        total: witnesses.len(),
        status_counts,
        kind_counts,
        source_counts,
        follow_up_total,
        follow_up_status_counts,
        witness_ids_by_status,
        follow_up_witness_ids_by_status,
    }
}

fn write_witness_artifacts(out: &Path, witnesses: &[WitnessRecord]) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    let registry = witness_registry_artifact(witnesses);
    fs::write(
        review_dir.join("witnesses.json"),
        serde_json::to_vec_pretty(witnesses)?,
    )?;
    fs::write(
        review_dir.join("witness_registry.json"),
        serde_json::to_vec_pretty(&registry)?,
    )?;
    let mut ndjson = String::new();
    for witness in witnesses {
        ndjson.push_str(&serde_json::to_string(witness)?);
        ndjson.push('\n');
    }
    fs::write(out.join("witnesses.ndjson"), ndjson)?;
    Ok(())
}

fn proof_task_artifact(
    plan: FocusedProofPlan,
    budget: ProofBudget,
    lease_budget: ProofLeaseBudget,
) -> ProofTaskArtifact {
    let base_plus_tests_command =
        (plan.mode == FocusedProofMode::RedGreen).then(|| plan.base_plus_tests_command.clone());
    let command = match &base_plus_tests_command {
        Some(base_command) => format!("{} && {}", plan.head_command, base_command),
        None => plan.head_command.clone(),
    };
    let purpose = focused_proof_task_purpose(&plan);
    let timeout_sec = plan
        .timeout_sec
        .saturating_mul(plan.mode.command_count())
        .min(budget.max_total_seconds);
    ProofTaskArtifact {
        schema: PROOF_TASK_SCHEMA,
        id: plan.id,
        kind: "focused-test".to_owned(),
        source: "proof-planner".to_owned(),
        priority: "high".to_owned(),
        packet_policy: "late-follow-up".to_owned(),
        deadline_sec: timeout_sec,
        gate_policy: "trust-affecting".to_owned(),
        status: plan.status,
        command,
        head_command: plan.head_command,
        base_plus_tests_command,
        purpose,
        consumers: vec![
            "tests-oracle".to_owned(),
            "opposition".to_owned(),
            "compiler".to_owned(),
        ],
        value: "high".to_owned(),
        cost: "low".to_owned(),
        timeout_sec,
        lease: ProofTaskLease {
            cpu: lease_budget.cpu,
            memory_mb: lease_budget.memory_mb,
            disk_mb: lease_budget.disk_mb,
            network: lease_budget.network,
            timeout_sec,
        },
        test_file: plan.test_file,
        test_name: plan.test_name,
        mode: plan.mode.key().to_owned(),
        requested_by: plan.requested_by,
        request_ids: plan.request_ids,
    }
}

fn focused_build_task_artifact(
    plan: FocusedBuildPlan,
    budget: ProofBudget,
    lease_budget: ProofLeaseBudget,
) -> ProofTaskArtifact {
    let timeout_sec = plan.timeout_sec.min(budget.max_total_seconds);
    ProofTaskArtifact {
        schema: PROOF_TASK_SCHEMA,
        id: plan.id,
        kind: "focused-build".to_owned(),
        source: "proof-planner".to_owned(),
        priority: "medium".to_owned(),
        packet_policy: "late-follow-up".to_owned(),
        deadline_sec: timeout_sec,
        gate_policy: "trust-affecting".to_owned(),
        status: plan.status,
        command: plan.command.clone(),
        head_command: plan.command.clone(),
        base_plus_tests_command: None,
        purpose: format!("Run focused HEAD build proof `{}`.", plan.command),
        consumers: focused_build_task_consumers(&plan.requested_by),
        value: "medium".to_owned(),
        cost: "focused-build".to_owned(),
        timeout_sec,
        lease: ProofTaskLease {
            cpu: lease_budget.cpu,
            memory_mb: lease_budget.memory_mb,
            disk_mb: lease_budget.disk_mb,
            network: lease_budget.network,
            timeout_sec,
        },
        test_file: "workspace".to_owned(),
        test_name: None,
        mode: FocusedProofMode::HeadOnly.key().to_owned(),
        requested_by: plan.requested_by,
        request_ids: plan.request_ids,
    }
}

fn write_work_queue_artifacts(
    out: &Path,
    plan: &Plan,
    proof_tasks: &[ProofTaskArtifact],
) -> Result<()> {
    let mut tasks = plan
        .sensors
        .iter()
        .map(|sensor| work_queue_task_from_sensor(out, sensor))
        .collect::<Vec<_>>();
    tasks.extend(proof_tasks.iter().map(work_queue_task_from_proof_task));
    let queue = WorkQueueArtifact {
        schema: WORK_QUEUE_SCHEMA,
        initial_packet_deadline_sec: DEFAULT_INITIAL_PACKET_DEADLINE_SEC,
        follow_up_deadline_sec: DEFAULT_FOLLOW_UP_PACKET_DEADLINE_SEC,
        tasks: &tasks,
    };
    fs::write(
        out.join("work_queue.json"),
        serde_json::to_vec_pretty(&queue)?,
    )?;

    let mut ndjson = String::new();
    for task in &tasks {
        let event = WorkEventArtifact {
            schema: WORK_EVENT_SCHEMA,
            kind: "task_planned",
            task_id: task.id.clone(),
            task_kind: task.kind.clone(),
            source: task.source.clone(),
            packet_policy: task.packet_policy.clone(),
            deadline_sec: task.deadline_sec,
            consumers: task.consumers.clone(),
            gate_policy: task.gate_policy.clone(),
            status: task.status.clone(),
            initial_packet_status: task.initial_packet_status.clone(),
            receipt_path: task.receipt_path.clone(),
        };
        ndjson.push_str(&serde_json::to_string(&event)?);
        ndjson.push('\n');
    }
    fs::write(out.join("work_events.ndjson"), ndjson)?;
    Ok(())
}

fn work_queue_task_from_sensor(out: &Path, sensor: &SensorPlan) -> WorkQueueTaskArtifact {
    let packet_policy = work_queue_sensor_packet_policy(sensor);
    let receipt_path = format!("sensors/{}/ub-review-sensor-status.json", sensor.id);
    let status = if sensor.run { "planned" } else { "skipped" }.to_owned();
    let receipt_ready = out.join(&receipt_path).is_file();
    WorkQueueTaskArtifact {
        schema: WORK_QUEUE_TASK_SCHEMA,
        id: format!("sensor-{}", sensor.id),
        kind: "sensor".to_owned(),
        source: "tool-registry".to_owned(),
        priority: work_queue_sensor_priority(sensor),
        packet_policy: packet_policy.clone(),
        deadline_sec: work_queue_sensor_deadline(sensor),
        consumers: work_queue_sensor_consumers(&sensor.id),
        gate_policy: work_queue_sensor_gate_policy(sensor),
        dedupe_key: format!("tool-registry:sensor:{}", sensor.id),
        lease: work_queue_sensor_lease(sensor),
        receipt_path,
        status: status.clone(),
        initial_packet_status: work_queue_initial_packet_status(
            &packet_policy,
            &status,
            receipt_ready,
        ),
        task_path: "resolved-tools.json".to_owned(),
    }
}

fn work_queue_task_from_proof_task(task: &ProofTaskArtifact) -> WorkQueueTaskArtifact {
    let receipt_ready = false;
    WorkQueueTaskArtifact {
        schema: WORK_QUEUE_TASK_SCHEMA,
        id: task.id.clone(),
        kind: task.kind.clone(),
        source: task.source.clone(),
        priority: task.priority.clone(),
        packet_policy: task.packet_policy.clone(),
        deadline_sec: task.deadline_sec,
        consumers: task.consumers.clone(),
        gate_policy: task.gate_policy.clone(),
        dedupe_key: work_queue_dedupe_key(task),
        lease: task.lease.clone(),
        receipt_path: "review/proof_receipts.json".to_owned(),
        status: task.status.clone(),
        initial_packet_status: work_queue_initial_packet_status(
            &task.packet_policy,
            &task.status,
            receipt_ready,
        ),
        task_path: "proof_tasks.ndjson".to_owned(),
    }
}

fn work_queue_initial_packet_status(
    packet_policy: &str,
    status: &str,
    receipt_ready: bool,
) -> String {
    match packet_policy {
        "must-run" | "include-if-ready" if status == "planned" && receipt_ready => {
            "ready_for_initial_packet".to_owned()
        }
        "must-run" | "include-if-ready" if status == "planned" => {
            "pending_initial_packet".to_owned()
        }
        "late-follow-up" | "adaptive" if status == "planned" => "pending_initial_packet".to_owned(),
        _ => "not_initial_packet".to_owned(),
    }
}

fn work_queue_sensor_priority(sensor: &SensorPlan) -> String {
    if sensor.required {
        "high".to_owned()
    } else if sensor.run {
        "medium".to_owned()
    } else {
        "low".to_owned()
    }
}

fn work_queue_sensor_packet_policy(sensor: &SensorPlan) -> String {
    if sensor.required {
        "must-run".to_owned()
    } else if sensor.run {
        "include-if-ready".to_owned()
    } else {
        "artifact-only".to_owned()
    }
}

fn work_queue_sensor_deadline(sensor: &SensorPlan) -> u64 {
    if sensor.run { sensor.timeout_sec } else { 0 }
}

fn work_queue_sensor_consumers(id: &str) -> Vec<String> {
    let consumers: &[&str] = match id {
        "ripr" => &["tests-oracle", "proof-planner", "compiler"],
        "coverage" => &["tests-oracle", "source-route", "compiler"],
        "unsafe-review" => &["ub-memory-lifetime", "security", "compiler"],
        "actionlint" => &[
            "workflow-permissions",
            "workflow-pinning",
            "workflow-proof",
            "workflow-opposition",
            "compiler",
        ],
        "ast-grep" => &["source-route", "compiler"],
        "tokmd" => &["all-lanes", "compiler"],
        "cargo-allow" => &["security", "compiler"],
        _ => &["compiler"],
    };
    consumers
        .iter()
        .map(|consumer| (*consumer).to_owned())
        .collect()
}

fn work_queue_sensor_gate_policy(sensor: &SensorPlan) -> String {
    if sensor.required {
        "gate-required".to_owned()
    } else if sensor.gate.is_some() {
        "trust-affecting".to_owned()
    } else if sensor.run {
        "review-context".to_owned()
    } else {
        "artifact-only".to_owned()
    }
}

fn work_queue_sensor_lease(sensor: &SensorPlan) -> ProofTaskLease {
    ProofTaskLease {
        cpu: u32::from(sensor.run),
        memory_mb: 0,
        disk_mb: sensor.artifact_budget_mb,
        network: false,
        timeout_sec: work_queue_sensor_deadline(sensor),
    }
}

fn work_queue_dedupe_key(task: &ProofTaskArtifact) -> String {
    if task.request_ids.is_empty() {
        return format!("{}:{}:{}", task.source, task.kind, task.id);
    }
    format!(
        "{}:{}:{}",
        task.source,
        task.kind,
        task.request_ids.join("+")
    )
}

fn focused_build_task_consumers(requested_by: &[String]) -> Vec<String> {
    let mut consumers = requested_by.to_vec();
    push_unique(&mut consumers, "compiler");
    consumers
}

fn focused_proof_task_purpose(plan: &FocusedProofPlan) -> String {
    match plan.mode {
        FocusedProofMode::HeadOnly => {
            format!(
                "Prove the focused test target `{}` passes on HEAD.",
                plan.test_file
            )
        }
        FocusedProofMode::RedGreen => format!(
            "Prove the focused test target `{}` fails on base+tests and passes on HEAD.",
            plan.test_file
        ),
    }
}

fn write_proof_receipt_artifacts(out: &Path, proof_receipts: &[ProofReceipt]) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("proof_receipts.json"),
        serde_json::to_vec_pretty(proof_receipts)?,
    )?;
    let mut ndjson = String::new();
    for receipt in proof_receipts {
        ndjson.push_str(&serde_json::to_string(receipt)?);
        ndjson.push('\n');
    }
    fs::write(out.join("proof_receipts.ndjson"), ndjson)?;
    Ok(())
}

fn write_resource_lease_artifacts(out: &Path, resource_leases: &[ResourceLease]) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    fs::write(
        review_dir.join("resource_leases.json"),
        serde_json::to_vec_pretty(resource_leases)?,
    )?;

    let mut ndjson = String::new();
    for lease in resource_leases {
        ndjson.push_str(&serde_json::to_string(lease)?);
        ndjson.push('\n');
    }
    fs::write(out.join("resource_leases.ndjson"), ndjson)?;

    let mut plan = String::new();
    plan.push_str("# Resource lease plan\n\n");
    if resource_leases.is_empty() {
        plan.push_str("No local proof leases were requested in this packet.\n");
    } else {
        plan.push_str("## Focused proof leases\n\n");
        for lease in resource_leases {
            plan.push_str(&format!(
                "- `{}` kind=`{}` consumer=`{}` status=`{}` cpu=`{}` memory_mb=`{}` disk_mb=`{}` timeout_sec=`{}` network=`{}` scratch=`{}`",
                lease.id,
                lease.kind,
                lease.consumer,
                lease.status,
                lease.cpu,
                lease.memory_mb,
                lease.disk_mb,
                lease.timeout_sec,
                lease.network,
                lease.scratch
            ));
            if let Some(worktree) = &lease.worktree {
                plan.push_str(&format!(" worktree=`{}`", escape_md(worktree)));
            }
            if let Some(command) = &lease.command {
                plan.push_str(&format!(" command=`{}`", escape_md(command)));
            }
            plan.push_str(&format!(". {}\n", escape_md(&lease.reason)));
        }
    }
    fs::write(review_dir.join("resource_plan.md"), plan)?;
    Ok(())
}

fn run_initial_diff_proof_broker_v0(
    root: &Path,
    out: &Path,
    diff: &DiffContext,
    profile: &Profile,
    args: &RunArgs,
) -> Result<ProofBrokerResult> {
    let budget = proof_budget(profile)?;
    let tasks = focused_test_candidates_from_diff(diff, &[]);
    run_focused_red_green_proof_tasks_with_runner(
        root,
        out,
        diff,
        profile,
        args,
        budget,
        tasks,
        run_command_to_files,
        prepare_base_plus_tests_worktree,
    )
}

#[expect(
    clippy::too_many_arguments,
    reason = "seeded proof stream coordinates scheduler phases and proof broker inputs"
)]
fn run_seeded_proof_stream_v0(
    root: &Path,
    out: &Path,
    diff: &DiffContext,
    profile: &Profile,
    args: &RunArgs,
    seeded_proof_requests: &[ProofRequest],
    initial_proof_loop: ActiveRunLoop,
    event_log: &EventLog,
    run_started: &Instant,
) -> Result<(ProofBrokerResult, Vec<RunLoopPhase>)> {
    let mut phases = Vec::new();
    let initial_result = run_initial_diff_proof_broker_v0(root, out, diff, profile, args);
    let initial_status = if initial_result.is_ok() {
        "completed"
    } else {
        "failed"
    };
    phases.push(finish_run_loop_phase(
        event_log,
        run_started,
        initial_proof_loop,
        initial_status,
    )?);
    let mut proof_result = initial_result?;

    if has_unreceipted_proof_request_tasks(seeded_proof_requests, &proof_result.proof_receipts) {
        let seeded_request_loop = start_run_loop(
            event_log,
            run_started,
            "proof",
            "proof",
            "seeded-request-broker",
        )?;
        let request_result = run_request_proof_broker_v0(
            root,
            out,
            diff,
            profile,
            seeded_proof_requests,
            &proof_result.proof_receipts,
            &proof_result.resource_leases,
            args,
        );
        let request_status = if request_result.is_ok() {
            "completed"
        } else {
            "failed"
        };
        phases.push(finish_run_loop_phase(
            event_log,
            run_started,
            seeded_request_loop,
            request_status,
        )?);
        let request_result = request_result?;
        proof_result
            .proof_receipts
            .extend(request_result.proof_receipts);
        proof_result
            .resource_leases
            .extend(request_result.resource_leases);
    }

    Ok((proof_result, phases))
}

#[expect(
    clippy::too_many_arguments,
    reason = "primary request proof broker mirrors follow-up broker inputs"
)]
fn run_request_proof_broker_v0(
    root: &Path,
    out: &Path,
    diff: &DiffContext,
    profile: &Profile,
    proof_requests: &[ProofRequest],
    existing_receipts: &[ProofReceipt],
    existing_leases: &[ResourceLease],
    args: &RunArgs,
) -> Result<ProofBrokerResult> {
    let total_budget = proof_budget(profile)?;
    let budget = remaining_focused_proof_budget(total_budget, existing_leases);
    let tasks = unreceipted_focused_test_tasks(
        focused_test_candidates_from_requests(proof_requests),
        existing_receipts,
    );
    let mut result = run_follow_up_proof_broker_v0_with_runner(
        root,
        out,
        diff,
        profile,
        args,
        budget,
        tasks,
        run_command_to_files,
        prepare_base_plus_tests_worktree,
    )?;
    let mut consumed_leases = existing_leases.to_vec();
    consumed_leases.extend(result.resource_leases.clone());
    let remaining_budget = remaining_focused_proof_budget(total_budget, &consumed_leases);
    let existing_and_new_receipts = existing_receipts
        .iter()
        .chain(result.proof_receipts.iter())
        .cloned()
        .collect::<Vec<_>>();
    let build_tasks = focused_build_candidates_from_requests(proof_requests);
    let build_tasks = unreceipted_focused_build_tasks(build_tasks, &existing_and_new_receipts);
    let build_result = run_focused_build_proof_tasks_with_runner(
        root,
        out,
        diff,
        profile,
        args,
        remaining_budget,
        build_tasks,
        run_command_to_files,
    )?;
    result.proof_receipts.extend(build_result.proof_receipts);
    result.resource_leases.extend(build_result.resource_leases);
    Ok(result)
}

