#[expect(
    clippy::too_many_arguments,
    reason = "tracked in policy/allow.toml#clippy-too-many-arguments-artifact-writers"
)]
fn run_follow_up_proof_broker_v0_with_runner<F, G>(
    root: &Path,
    out: &Path,
    diff: &DiffContext,
    profile: &Profile,
    args: &RunArgs,
    budget: ProofBudget,
    tasks: Vec<FocusedTestTask>,
    runner: F,
    prepare_base_plus_tests: G,
) -> Result<ProofBrokerResult>
where
    F: FnMut(
        &Path,
        &[String],
        &BTreeMap<String, String>,
        u64,
        &Path,
        &Path,
    ) -> Result<CommandStatus>,
    G: FnMut(&Path, &Path, &DiffContext) -> Result<PathBuf>,
{
    run_focused_red_green_proof_tasks_with_runner(
        root,
        out,
        diff,
        profile,
        args,
        budget,
        tasks,
        runner,
        prepare_base_plus_tests,
    )
}

fn attach_request_metadata_to_focused_receipts(
    diff: &DiffContext,
    proof_requests: &[ProofRequest],
    proof_receipts: &mut [ProofReceipt],
) {
    if proof_requests.is_empty() || proof_receipts.is_empty() {
        return;
    }
    let request_metadata = focused_test_candidates_from_diff(diff, proof_requests)
        .into_iter()
        .filter(|task| !task.request_ids.is_empty())
        .map(|task| (task.id, (task.requested_by, task.request_ids)))
        .collect::<BTreeMap<_, _>>();
    for receipt in proof_receipts {
        let Some((requested_by, request_ids)) = request_metadata.get(&receipt.id) else {
            continue;
        };
        for lane in requested_by {
            push_unique(&mut receipt.requested_by, lane);
        }
        for request_id in request_ids {
            push_unique(&mut receipt.request_ids, request_id);
        }
    }
}

fn unreceipted_focused_test_tasks(
    tasks: Vec<FocusedTestTask>,
    existing_receipts: &[ProofReceipt],
) -> Vec<FocusedTestTask> {
    let existing_ids = existing_receipts
        .iter()
        .map(|receipt| receipt.id.clone())
        .collect::<BTreeSet<_>>();
    tasks
        .into_iter()
        .filter(|task| !existing_ids.contains(&task.id))
        .collect()
}

fn unreceipted_focused_build_tasks(
    tasks: Vec<FocusedBuildTask>,
    existing_receipts: &[ProofReceipt],
) -> Vec<FocusedBuildTask> {
    let existing_ids = existing_receipts
        .iter()
        .map(|receipt| receipt.id.clone())
        .collect::<BTreeSet<_>>();
    tasks
        .into_iter()
        .filter(|task| !existing_ids.contains(&task.id))
        .collect()
}

fn has_unreceipted_proof_request_tasks(
    proof_requests: &[ProofRequest],
    existing_receipts: &[ProofReceipt],
) -> bool {
    !unreceipted_focused_test_tasks(
        focused_test_candidates_from_requests(proof_requests),
        existing_receipts,
    )
    .is_empty()
        || !unreceipted_focused_build_tasks(
            focused_build_candidates_from_requests(proof_requests),
            existing_receipts,
        )
        .is_empty()
}

fn focused_test_resource_lease(
    task: &FocusedTestTask,
    budget: ProofBudget,
    lease_budget: ProofLeaseBudget,
    status: &str,
    reason: &str,
) -> ResourceLease {
    ResourceLease {
        schema: RESOURCE_LEASE_SCHEMA.to_owned(),
        id: format!("lease-{}", task.id),
        kind: "focused-test".to_owned(),
        consumer: task.id.clone(),
        status: status.to_owned(),
        reason: reason.to_owned(),
        cpu: lease_budget.cpu,
        memory_mb: lease_budget.memory_mb,
        disk_mb: lease_budget.disk_mb,
        timeout_sec: focused_test_task_command_timeout(task, budget)
            .saturating_mul(task.mode.command_count())
            .min(budget.max_total_seconds),
        network: lease_budget.network,
        scratch: lease_budget.scratch,
        worktree: if task.mode == FocusedProofMode::RedGreen {
            Some("base-plus-tests".to_owned())
        } else {
            None
        },
        command: Some(match task.mode {
            FocusedProofMode::HeadOnly => {
                format!("head: {}", proof_task_plan_command(task, "head", "head"))
            }
            FocusedProofMode::RedGreen => format!(
                "head: {}; base+tests: {}",
                proof_task_plan_command(task, "head", "head"),
                proof_task_plan_command(task, "base-plus-tests", "base-plus-tests")
            ),
        }),
    }
}

fn focused_build_resource_lease(
    task: &FocusedBuildTask,
    budget: ProofBudget,
    lease_budget: ProofLeaseBudget,
    status: &str,
    reason: &str,
) -> ResourceLease {
    ResourceLease {
        schema: RESOURCE_LEASE_SCHEMA.to_owned(),
        id: format!("lease-{}", task.id),
        kind: "focused-build".to_owned(),
        consumer: task.id.clone(),
        status: status.to_owned(),
        reason: reason.to_owned(),
        cpu: lease_budget.cpu,
        memory_mb: lease_budget.memory_mb,
        disk_mb: lease_budget.disk_mb,
        timeout_sec: focused_build_task_command_timeout(task, budget).min(budget.max_total_seconds),
        network: lease_budget.network,
        scratch: lease_budget.scratch,
        worktree: None,
        command: Some(format!("head: {}", task.command)),
    }
}

fn focused_test_names_for_file(patch: &str, file: &str) -> Vec<String> {
    let mut names = Vec::new();
    let mut current_path = String::new();
    for line in patch.lines() {
        if let Some(path) = line.strip_prefix("+++ b/") {
            current_path = normalize_repo_path(path);
            continue;
        }
        if current_path != file || !line.starts_with('+') || line.starts_with("+++") {
            continue;
        }
        if let Some(name) = extract_focused_test_name(&line[1..]) {
            push_unique(&mut names, &name);
        }
    }
    names
}

fn extract_focused_test_name(line: &str) -> Option<String> {
    let trimmed = line.trim_start();
    for callee in ["test", "it", "describe"] {
        if let Some(rest) = trimmed.strip_prefix(callee)
            && let Some(call_args) = strip_focused_test_callee_prefix(rest)
            && let Some(name) = parse_js_string_literal(call_args.trim_start())
        {
            return Some(name);
        }
    }
    None
}

fn strip_focused_test_callee_prefix(mut rest: &str) -> Option<&str> {
    loop {
        let trimmed = rest.trim_start();
        if let Some(call_args) = trimmed.strip_prefix('(') {
            return Some(call_args);
        }
        let after_dot = trimmed.strip_prefix('.')?;
        let (modifier, after_modifier) = parse_js_identifier(after_dot)?;
        if is_simple_test_modifier(modifier) {
            rest = after_modifier;
            continue;
        }
        if is_parameterized_test_modifier(modifier) {
            rest = strip_balanced_js_call(after_modifier.trim_start())?;
            continue;
        }
        return None;
    }
}

fn parse_js_identifier(text: &str) -> Option<(&str, &str)> {
    let end = text
        .char_indices()
        .take_while(|(_, ch)| ch.is_ascii_alphanumeric() || *ch == '_' || *ch == '$')
        .map(|(index, ch)| index + ch.len_utf8())
        .last()?;
    Some((&text[..end], &text[end..]))
}

fn is_simple_test_modifier(value: &str) -> bool {
    matches!(
        value,
        "only" | "skip" | "todo" | "failing" | "concurrent" | "serial"
    )
}

fn is_parameterized_test_modifier(value: &str) -> bool {
    matches!(value, "each")
}

fn strip_balanced_js_call(text: &str) -> Option<&str> {
    if !text.starts_with('(') {
        return None;
    }
    let mut depth = 0_u32;
    let mut quote = None;
    let mut escaped = false;
    for (index, ch) in text.char_indices() {
        if let Some(active_quote) = quote {
            if escaped {
                escaped = false;
            } else if ch == '\\' {
                escaped = true;
            } else if ch == active_quote {
                quote = None;
            }
            continue;
        }
        match ch {
            '"' | '\'' | '`' => quote = Some(ch),
            '(' => depth = depth.saturating_add(1),
            ')' => {
                depth = depth.saturating_sub(1);
                if depth == 0 {
                    return Some(&text[index + ch.len_utf8()..]);
                }
            }
            _ => {}
        }
    }
    None
}

fn parse_js_string_literal(text: &str) -> Option<String> {
    let mut chars = text.chars();
    let quote = chars.next()?;
    if !matches!(quote, '"' | '\'') {
        return None;
    }
    let mut escaped = false;
    let mut out = String::new();
    for ch in chars {
        if escaped {
            out.push(ch);
            escaped = false;
        } else if ch == '\\' {
            escaped = true;
        } else if ch == quote {
            return Some(out.trim().to_owned()).filter(|value| !value.is_empty());
        } else {
            out.push(ch);
        }
    }
    None
}

fn is_bun_focused_test_file(path: &str) -> bool {
    let path = normalize_repo_path(path);
    if !is_repo_relative_path(&path) {
        return false;
    }
    let lower = path.to_ascii_lowercase();
    (lower.starts_with("test/") || lower.starts_with("tests/"))
        && [
            ".test.ts",
            ".test.tsx",
            ".test.js",
            ".test.jsx",
            ".test.mjs",
            ".test.cjs",
        ]
        .iter()
        .any(|suffix| lower.ends_with(suffix))
}

fn proof_task_command_spec(task: &FocusedTestTask, side: &str) -> ProofCommandSpec {
    if let Some(command_specs) = &task.command_specs {
        return if side == "head" {
            command_specs.head.clone()
        } else {
            command_specs.base_plus_tests.clone()
        };
    }
    let mut env = BTreeMap::new();
    let mut argv = if side == "head" {
        vec![
            "bun".to_owned(),
            "bd".to_owned(),
            "test".to_owned(),
            task.file.clone(),
        ]
    } else {
        env.insert("USE_SYSTEM_BUN".to_owned(), "1".to_owned());
        vec!["bun".to_owned(), "test".to_owned(), task.file.clone()]
    };
    if let Some(name) = &task.test_name {
        argv.push("-t".to_owned());
        argv.push(name.clone());
    }
    ProofCommandSpec { argv, env }
}

fn focused_cargo_test_command_spec(command: &str) -> Option<ProofCommandSpec> {
    if has_shell_control_token(command) {
        return None;
    }
    let argv = command
        .split_whitespace()
        .map(ToOwned::to_owned)
        .collect::<Vec<_>>();
    let [program, subcommand, args @ ..] = argv.as_slice() else {
        return None;
    };
    if program != "cargo" || subcommand != "test" {
        return None;
    }
    if !args.iter().any(|arg| arg == "--locked") {
        return None;
    }
    if !focused_cargo_test_args_allowed(args) {
        return None;
    }
    if !focused_cargo_test_has_focus(&argv) {
        return None;
    }
    Some(ProofCommandSpec {
        argv,
        env: BTreeMap::new(),
    })
}

fn focused_cargo_test_args_allowed(args: &[String]) -> bool {
    let mut index = 0;
    let mut passthrough = false;
    while index < args.len() {
        let arg = args[index].as_str();
        if !passthrough && arg == "--" {
            passthrough = true;
            index += 1;
            continue;
        }
        if passthrough {
            match arg {
                "--exact" | "--nocapture" | "--show-output" | "--ignored" | "--include-ignored" => {
                    index += 1;
                }
                "--test-threads" => {
                    let Some(value) = args.get(index + 1) else {
                        return false;
                    };
                    if value.parse::<u16>().is_err() {
                        return false;
                    }
                    index += 2;
                }
                _ => return false,
            }
            continue;
        }
        match arg {
            "--locked"
            | "--workspace"
            | "--all-targets"
            | "--all-features"
            | "--no-default-features"
            | "--tests"
            | "--lib"
            | "--bins"
            | "--examples"
            | "--doc"
            | "--offline"
            | "--frozen" => {
                index += 1;
            }
            "-p" | "--package" | "--features" | "--target" | "--test" | "--bin" | "--example" => {
                let Some(value) = args.get(index + 1) else {
                    return false;
                };
                if !safe_cargo_build_arg_value(value) {
                    return false;
                }
                index += 2;
            }
            _ if arg.starts_with("--package=")
                || arg.starts_with("--features=")
                || arg.starts_with("--target=")
                || arg.starts_with("--test=")
                || arg.starts_with("--bin=")
                || arg.starts_with("--example=") =>
            {
                let Some((_, value)) = arg.split_once('=') else {
                    return false;
                };
                if value.is_empty() || !safe_cargo_build_arg_value(value) {
                    return false;
                }
                index += 1;
            }
            _ => {
                if !safe_cargo_test_filter_value(arg) {
                    return false;
                }
                index += 1;
            }
        }
    }
    true
}

fn focused_cargo_test_has_focus(argv: &[String]) -> bool {
    cargo_arg_value(argv, "--test").is_some()
        || focused_cargo_test_filter_name(argv)
            .as_deref()
            .is_some_and(safe_cargo_test_filter_value)
}

fn safe_cargo_test_filter_value(value: &str) -> bool {
    !value.is_empty()
        && !value.starts_with('-')
        && value.chars().all(|ch| {
            ch.is_ascii_alphanumeric()
                || matches!(ch, '_' | '-' | '.' | '/' | ':' | ',' | '+' | '=')
        })
}

fn focused_cargo_test_target_label(argv: &[String]) -> String {
    if let Some(target) = cargo_arg_value(argv, "--test") {
        return format!("cargo-test:{target}");
    }
    if let Some(package) =
        cargo_arg_value(argv, "--package").or_else(|| cargo_arg_value(argv, "-p"))
    {
        return format!("cargo-package:{package}");
    }
    "cargo-test".to_owned()
}

fn focused_cargo_test_filter_name(argv: &[String]) -> Option<String> {
    let mut index = 2;
    while index < argv.len() {
        let arg = argv[index].as_str();
        if arg == "--" {
            return None;
        }
        if matches!(
            arg,
            "-p" | "--package" | "--features" | "--target" | "--test" | "--bin" | "--example"
        ) {
            index += 2;
            continue;
        }
        if arg.starts_with("--package=")
            || arg.starts_with("--features=")
            || arg.starts_with("--target=")
            || arg.starts_with("--test=")
            || arg.starts_with("--bin=")
            || arg.starts_with("--example=")
            || matches!(
                arg,
                "--locked"
                    | "--workspace"
                    | "--all-targets"
                    | "--all-features"
                    | "--no-default-features"
                    | "--tests"
                    | "--lib"
                    | "--bins"
                    | "--examples"
                    | "--doc"
                    | "--offline"
                    | "--frozen"
            )
        {
            index += 1;
            continue;
        }
        return Some(arg.to_owned());
    }
    None
}

fn cargo_arg_value<'a>(argv: &'a [String], name: &str) -> Option<&'a str> {
    let equals_prefix = format!("{name}=");
    let mut index = 0;
    while index < argv.len() {
        let arg = argv[index].as_str();
        if arg == name {
            return argv.get(index + 1).map(String::as_str);
        }
        if let Some(value) = arg.strip_prefix(&equals_prefix) {
            return Some(value);
        }
        index += 1;
    }
    None
}

fn focused_build_command_spec_for_task(task: &FocusedBuildTask) -> ProofCommandSpec {
    ProofCommandSpec {
        argv: task.argv.clone(),
        env: BTreeMap::new(),
    }
}

fn focused_build_command_spec(command: &str) -> Option<ProofCommandSpec> {
    if has_shell_control_token(command) {
        return None;
    }
    let argv = command
        .split_whitespace()
        .map(ToOwned::to_owned)
        .collect::<Vec<_>>();
    let [program, subcommand, args @ ..] = argv.as_slice() else {
        return None;
    };
    if program != "cargo" {
        return None;
    }
    // `cargo xtask policy-check` is the repo-local parse-only policy receipt
    // validation (see xtask/src/main.rs). Only this exact invocation is
    // brokered so xtask cannot smuggle arbitrary repo commands into the
    // focused proof lane.
    if subcommand == "xtask" {
        return (args == ["policy-check"]).then(|| ProofCommandSpec {
            argv: argv.clone(),
            env: BTreeMap::new(),
        });
    }
    if !matches!(subcommand.as_str(), "build" | "check" | "doc") {
        return None;
    }
    if !args.iter().any(|arg| arg == "--locked") {
        return None;
    }
    if !focused_cargo_build_args_allowed(args) {
        return None;
    }
    Some(ProofCommandSpec {
        argv,
        env: BTreeMap::new(),
    })
}

fn focused_cargo_build_args_allowed(args: &[String]) -> bool {
    let mut index = 0;
    while index < args.len() {
        let arg = args[index].as_str();
        match arg {
            "--locked"
            | "--workspace"
            | "--all-targets"
            | "--all-features"
            | "--no-default-features"
            | "--release"
            | "--tests"
            | "--benches"
            | "--examples"
            | "--bins"
            | "--lib"
            | "--no-deps"
            | "--offline"
            | "--frozen" => {
                index += 1;
            }
            "-p" | "--package" | "--features" | "--target" => {
                let Some(value) = args.get(index + 1) else {
                    return false;
                };
                if !safe_cargo_build_arg_value(value) {
                    return false;
                }
                index += 2;
            }
            _ if arg.starts_with("--package=")
                || arg.starts_with("--features=")
                || arg.starts_with("--target=") =>
            {
                let Some((_, value)) = arg.split_once('=') else {
                    return false;
                };
                if value.is_empty() || !safe_cargo_build_arg_value(value) {
                    return false;
                }
                index += 1;
            }
            _ => return false,
        }
    }
    true
}

fn safe_cargo_build_arg_value(value: &str) -> bool {
    !value.is_empty()
        && value.chars().all(|ch| {
            ch.is_ascii_alphanumeric() || matches!(ch, '_' | '-' | '.' | '/' | ':' | ',' | '+')
        })
}

fn proof_task_plan_command(task: &FocusedTestTask, side: &str, worktree: &str) -> String {
    let spec = proof_task_command_spec(task, side);
    format!(
        "cwd=target/ub-review/proof-worktrees/{worktree} {}",
        command_display_with_env(&spec.env, &spec.argv)
    )
}

fn command_display(argv: &[String]) -> String {
    argv.iter()
        .map(|part| {
            if part
                .chars()
                .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '/' | '.' | '_' | '-' | ':'))
            {
                part.clone()
            } else {
                format!("'{}'", part.replace('\'', "'\\''"))
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

fn command_display_with_env(env: &BTreeMap<String, String>, argv: &[String]) -> String {
    if env.is_empty() {
        return command_display(argv);
    }
    let mut parts = env
        .iter()
        .map(|(key, value)| format!("{key}={value}"))
        .collect::<Vec<_>>();
    parts.push(command_display(argv));
    parts.join(" ")
}

fn push_unique(values: &mut Vec<String>, value: &str) {
    if !values.iter().any(|existing| existing == value) {
        values.push(value.to_owned());
    }
}

#[derive(Clone, Debug, Serialize)]
struct ObservationGroup {
    schema: String,
    id: String,
    dedupe_key: String,
    claim: String,
    kind: String,
    status: String,
    severity: String,
    confidence: String,
    path: Option<String>,
    line: Option<u32>,
    evidence: Vec<String>,
    lanes: Vec<String>,
    sources: Vec<String>,
    observation_ids: Vec<String>,
    duplicate_count: usize,
}

#[derive(Clone, Debug, Serialize)]
struct MergedObservationRecord {
    schema: String,
    group_id: String,
    dedupe_key: String,
    kept_observation_id: String,
    merged_observation_ids: Vec<String>,
    lanes: Vec<String>,
    reason: String,
}

#[derive(Clone, Debug, Serialize)]
struct DroppedObservationRecord {
    schema: String,
    observation_id: String,
    group_id: String,
    dedupe_key: String,
    lane: String,
    reason: String,
}

struct ObservationSummaryArtifacts {
    unique: Vec<ObservationGroup>,
    merged: Vec<MergedObservationRecord>,
    dropped: Vec<DroppedObservationRecord>,
}

fn observation_summary_artifacts(observations: &[Observation]) -> ObservationSummaryArtifacts {
    let mut indexes = BTreeMap::new();
    let mut groups = Vec::<ObservationGroup>::new();
    for observation in observations {
        let key = observation_group_key(observation);
        if let Some(index) = indexes.get(&key).copied() {
            merge_review_observation(&mut groups[index], observation);
        } else {
            let group_id = observation_group_id(groups.len(), &key);
            indexes.insert(key.clone(), groups.len());
            groups.push(ObservationGroup {
                schema: OBSERVATION_GROUP_SCHEMA.to_owned(),
                id: group_id,
                dedupe_key: key,
                claim: observation.claim.clone(),
                kind: observation.kind.clone(),
                status: observation.status.clone(),
                severity: observation.severity.clone(),
                confidence: observation.confidence.clone(),
                path: observation.path.clone(),
                line: observation.line,
                evidence: observation.evidence.iter().take(3).cloned().collect(),
                lanes: vec![observation.lane.clone()],
                sources: vec![observation.source.clone()],
                observation_ids: vec![observation.id.clone()],
                duplicate_count: 0,
            });
        }
    }
    let merged = groups
        .iter()
        .filter(|group| group.observation_ids.len() > 1)
        .map(|group| MergedObservationRecord {
            schema: MERGED_OBSERVATION_SCHEMA.to_owned(),
            group_id: group.id.clone(),
            dedupe_key: group.dedupe_key.clone(),
            kept_observation_id: group.observation_ids[0].clone(),
            merged_observation_ids: group.observation_ids[1..].to_vec(),
            lanes: group.lanes.clone(),
            reason: "merged_duplicate_dedupe_key".to_owned(),
        })
        .collect::<Vec<_>>();
    let observation_lanes = observations
        .iter()
        .map(|observation| (observation.id.as_str(), observation.lane.as_str()))
        .collect::<BTreeMap<_, _>>();
    let dropped = groups
        .iter()
        .flat_map(|group| {
            group
                .observation_ids
                .iter()
                .skip(1)
                .map(|observation_id| DroppedObservationRecord {
                    schema: DROPPED_OBSERVATION_SCHEMA.to_owned(),
                    observation_id: observation_id.clone(),
                    group_id: group.id.clone(),
                    dedupe_key: group.dedupe_key.clone(),
                    lane: observation_lanes
                        .get(observation_id.as_str())
                        .copied()
                        .unwrap_or("unknown")
                        .to_owned(),
                    reason: "merged_into_unique_observation".to_owned(),
                })
                .collect::<Vec<_>>()
        })
        .collect::<Vec<_>>();
    ObservationSummaryArtifacts {
        unique: groups,
        merged,
        dropped,
    }
}

fn unique_review_observations(observations: &[Observation]) -> Vec<ObservationGroup> {
    observation_summary_artifacts(observations).unique
}

fn observation_group_key(observation: &Observation) -> String {
    if observation.dedupe_key.trim().is_empty() {
        observation.fingerprint.clone()
    } else {
        observation.dedupe_key.clone()
    }
}

fn observation_group_id(index: usize, dedupe_key: &str) -> String {
    let digest = sha256_hex(dedupe_key.as_bytes());
    format!("obsgrp-{index:04}-{}", &digest[..12])
}

fn merge_review_observation(group: &mut ObservationGroup, observation: &Observation) {
    if severity_rank(&observation.severity) > severity_rank(&group.severity) {
        group.severity = observation.severity.clone();
    }
    if confidence_rank(&observation.confidence) > confidence_rank(&group.confidence) {
        group.confidence = observation.confidence.clone();
    }
    if observation_status_rank(&observation.status) > observation_status_rank(&group.status) {
        group.status = observation.status.clone();
    }
    if group.path.is_none() {
        group.path = observation.path.clone();
    }
    if group.line.is_none() {
        group.line = observation.line;
    }
    if !group.lanes.contains(&observation.lane) {
        group.lanes.push(observation.lane.clone());
    }
    if !group.sources.contains(&observation.source) {
        group.sources.push(observation.source.clone());
    }
    group.observation_ids.push(observation.id.clone());
    group.duplicate_count = group.observation_ids.len().saturating_sub(1);
    for evidence in &observation.evidence {
        if group.evidence.len() >= 3 {
            break;
        }
        if !group.evidence.contains(evidence) {
            group.evidence.push(evidence.clone());
        }
    }
}

fn observation_status_rank(value: &str) -> u8 {
    match value {
        "refuted" => 7,
        "confirmed" => 6,
        "parked" => 5,
        "demoted" => 4,
        "open" => 3,
        "covered" => 2,
        "duplicate" => 1,
        _ => 0,
    }
}

fn sensor_status_for_metrics(out: &Path, sensor: &SensorPlan) -> String {
    let status_path = out
        .join("sensors")
        .join(&sensor.id)
        .join("ub-review-sensor-status.json");
    read_sensor_receipt(&status_path)
        .map(|receipt| receipt.status)
        .unwrap_or_else(|| {
            if sensor.run {
                "receipt-absent".to_owned()
            } else {
                "skipped".to_owned()
            }
        })
}

fn status_counts<'a>(statuses: impl Iterator<Item = &'a str>) -> BTreeMap<String, usize> {
    let mut counts = BTreeMap::new();
    for status in statuses {
        *counts.entry(status.to_owned()).or_insert(0) += 1;
    }
    counts
}

fn model_call_attempted_status(status: &str) -> bool {
    matches!(
        status,
        "ok" | "failed"
            | "degraded"
            | "invalid_json"
            | "timed_out"
            | "rate_limited"
            | "auth_failed"
            | "bad_envelope"
    )
}

fn write_github_review_skip_receipt(
    review_dir: &Path,
    receipt: GitHubReviewSkipReceipt,
) -> Result<()> {
    let review_json = review_dir.join("github-review.json");
    if review_json.exists() {
        fs::remove_file(&review_json)?;
    }
    fs::write(
        github_review_skip_path(&review_json),
        serde_json::to_vec_pretty(&receipt)?,
    )?;
    Ok(())
}

fn build_github_review_skip_receipt(
    args: &RunArgs,
    review: &ReviewArtifacts,
    summary_only_body: SummaryOnlyBodyPolicy,
) -> GitHubReviewSkipReceipt {
    // The receipt reason must name the skip cause, not restate the terminal
    // state: a pass excluded by the profile's posting policy says so directly
    // instead of borrowing a sentence that can read like a contradiction, and
    // a body withheld by the boilerplate suppressor names the configured
    // [review_body].summary_only_body value and the finding counts it ruled
    // on.
    let reason = if review.terminal_state.review_payload_status == "skipped_pass_policy" {
        format!(
            "pass `{}` is not in [gate].post_review_on; the profile keeps this pass artifact-only.",
            review.run_pass
        )
    } else if review.terminal_state.review_payload_status == "skipped_artifact_only_body" {
        format!(
            "summary_only_body = `{}` withheld the PR-facing body as no-value boilerplate: {} summary-only findings, {} substantive; diagnostics remain in artifacts.",
            summary_only_body.key(),
            review.terminal_state.summary_only_findings,
            review.terminal_state.substantive_summary_only_findings
        )
    } else {
        review.terminal_state.reason.clone()
    };
    GitHubReviewSkipReceipt {
        schema_version: 1,
        status: "skipped".to_owned(),
        reason,
        review_payload_status: review.terminal_state.review_payload_status.clone(),
        terminal_state: review.terminal_state.status.clone(),
        github_review_json: None,
        run_pass: review.run_pass.clone(),
        model_mode: args.model_mode.key().to_owned(),
        inline_comments: review.inline_comments.len(),
        summary_only_findings: review.summary_only_findings.len(),
        missing_or_failed_sensor_evidence: review.missing_or_failed_sensor_evidence.len(),
        missing_or_failed_model_evidence: review.missing_or_failed_model_evidence.len(),
    }
}

fn github_review_skip_path(review_json: &Path) -> PathBuf {
    review_json
        .parent()
        .map(|dir| dir.join("github-review-skip.json"))
        .unwrap_or_else(|| PathBuf::from("github-review-skip.json"))
}

#[expect(
    clippy::too_many_arguments,
    reason = "tracked in policy/allow.toml#clippy-too-many-arguments-artifact-writers"
)]
fn render_shared_context(
    root: &Path,
    out: &Path,
    config: &Config,
    diff: &DiffContext,
    plan: &Plan,
    running_summary: &str,
    args: &RunArgs,
    pr_thread_context: &PrThreadContext,
    profile: &Profile,
    proof_requests: &[ProofRequest],
) -> Result<String> {
    let mut text = String::new();
    text.push_str("# Shared UB Review Context\n\n");
    text.push_str("This stable prefix is intended for lane model calls and future provider-side context caching.\n\n");
    text.push_str("## PR Summary\n\n");
    text.push_str(running_summary);
    text.push_str("\n\n## Diff Summary\n\n");
    text.push_str(&format!("- Base: `{}`\n", diff.base));
    text.push_str(&format!("- Head: `{}`\n", diff.head));
    text.push_str(&format!(
        "- Changed files: `{}`\n",
        diff.changed_files.len()
    ));
    text.push_str(&format!("- Diff class: `{}`\n", diff.diff_class.key()));
    let language_mix = classify_language_mix(&diff.changed_files);
    let languages = if language_mix.languages.is_empty() {
        "none".to_owned()
    } else {
        language_mix.languages.join(", ")
    };
    let surfaces = if language_mix.surfaces.is_empty() {
        "none".to_owned()
    } else {
        language_mix.surfaces.join(", ")
    };
    text.push_str(&format!("- Changed languages: `{languages}`\n"));
    text.push_str(&format!("- Changed surfaces: `{surfaces}`\n"));
    if let Some(primary_language) = &language_mix.primary_language {
        text.push_str(&format!("- Primary language: `{primary_language}`\n"));
    }
    text.push_str(&format!(
        "- Mixed-language diff: `{}`\n",
        language_mix.mixed_language
    ));
    text.push_str(&format!(
        "- Unsafe/native risk touched: `{}`\n",
        diff.flags.unsafe_or_native_risk
    ));
    text.push_str("\n## Changed Files\n\n");
    for file in &diff.changed_files {
        text.push_str(&format!("- `{file}`\n"));
    }
    text.push_str("\n## Sensor Statuses\n\n");
    for sensor in &plan.sensors {
        let status_path = out
            .join("sensors")
            .join(&sensor.id)
            .join("ub-review-sensor-status.json");
        let receipt = read_sensor_receipt(&status_path);
        let status = receipt
            .as_ref()
            .map(|receipt| receipt.status.as_str())
            .unwrap_or("receipt-absent");
        let reason = receipt
            .as_ref()
            .map(|receipt| receipt.reason.as_str())
            .unwrap_or(&sensor.reason);
        text.push_str(&format!(
            "- `{}`: `{}` - {}\n",
            sensor.id,
            status,
            escape_md(reason)
        ));
    }
    // unsafe-review structured evidence block (#359). Included when the sensor
    // was planned and its `unsafe-review-gate.json` is present with the
    // recognised schema. Falls back to a note when absent or schema is unknown.
    // Trust boundary is always advisory; this section supplements the
    // deterministic floor, never overrides it.
    if plan.sensors.iter().any(|s| s.id == "unsafe-review") {
        text.push_str("\n## unsafe-review Coverage Evidence\n\n");
        let sensor_dir = out.join("sensors").join("unsafe-review");
        let status_path = sensor_dir.join("ub-review-sensor-status.json");
        let sensor_status = read_sensor_receipt(&status_path)
            .map(|r| r.status)
            .unwrap_or_else(|| "receipt-absent".to_owned());
        text.push_str(&format!("- Sensor status: `{sensor_status}`\n"));
        if sensor_status == "ok" {
            match read_unsafe_review_artifacts(&sensor_dir) {
                None => {
                    let gate_path = sensor_dir
                        .join(UNSAFE_REVIEW_OUTPUT_SUBDIR)
                        .join("unsafe-review-gate.json");
                    if gate_path.exists() {
                        text.push_str("- Structured evidence: schema_version not recognised; falling back to status-only\n");
                    } else {
                        text.push_str("- Structured evidence: unsafe-review-gate.json not found; falling back to status-only\n");
                    }
                }
                Some(artifacts) => {
                    let gate = &artifacts.gate;
                    let trust = gate.trust_boundary.as_deref().unwrap_or("advisory");
                    let summary = &gate.summary;
                    // Provenance from the real manifest: which tool/version/dialect
                    // produced this evidence. Context only, never a gate input.
                    let tool = gate.tool.as_deref().unwrap_or("unsafe-review");
                    let tool_version = gate.tool_version.as_deref().unwrap_or("unknown");
                    let dialect = gate.dialect.as_deref().unwrap_or("unsafe-review");
                    text.push_str(&format!(
                        "- Source: `{tool}` `{tool_version}` (dialect: `{dialect}`)\n"
                    ));
                    text.push_str(&format!(
                        "- Advisory status (trust_boundary: `{trust}`): `{}`\n",
                        gate.status
                    ));
                    text.push_str(&format!(
                        "- Movement: new_gaps={}, worsened={}, resolved={}, inherited={}\n",
                        summary.new_gaps,
                        summary.worsened_gaps,
                        summary.resolved_gaps,
                        summary.inherited_gaps
                    ));
                    text.push_str(&format!(
                        "- Comment-plan candidates: {}\n",
                        artifacts.comment_plan.len()
                    ));
                    if !artifacts.comment_plan.is_empty() {
                        text.push_str(
                            "\n### Comment-plan entries (advisory, for #360 inline posting)\n\n",
                        );
                        text.push_str("```json\n");
                        let cp_json = serde_json::to_string_pretty(&artifacts.comment_plan)
                            .unwrap_or_else(|_| "[]".to_owned());
                        text.push_str(&cp_json);
                        text.push_str("\n```\n");
                    }
                }
            }
        }
    }
    text.push_str("\n## Initial Work Queue\n\n");
    text.push_str(&render_initial_work_queue_context(
        out,
        plan,
        diff,
        profile,
        proof_requests,
    )?);
    text.push_str(&format!(
        "\n## {} Review Posture\n\n",
        diff_class_posture_heading(diff.diff_class)
    ));
    text.push_str(review_posture_for_diff_class(diff.diff_class));
    text.push_str("\n\n## PR Thread Context\n\n");
    text.push_str(&render_pr_thread_context(pr_thread_context));
    text.push_str("\n\n## UB Ledger Context\n\n");
    text.push_str(&render_ledger_context(root, config, args)?);
    text.push_str("\n\n## Diff Patch\n\n```diff\n");
    text.push_str(&diff.patch);
    if !diff.patch.ends_with('\n') {
        text.push('\n');
    }
    text.push_str("```\n");
    Ok(text)
}

fn render_initial_work_queue_context(
    out: &Path,
    plan: &Plan,
    diff: &DiffContext,
    profile: &Profile,
    proof_requests: &[ProofRequest],
) -> Result<String> {
    let sensor_tasks = plan
        .sensors
        .iter()
        .map(|sensor| {
            (
                work_queue_task_from_sensor(out, sensor),
                sensor.reason.clone(),
            )
        })
        .collect::<Vec<_>>();
    let proof_output = build_proof_planner_output(diff, profile, proof_requests)?;
    let proof_tasks = proof_output
        .proof_tasks
        .iter()
        .map(|task| {
            (
                work_queue_task_from_proof_task(task),
                format!("{} {}", task.kind, task.purpose),
            )
        })
        .collect::<Vec<_>>();
    let mut tasks = Vec::with_capacity(sensor_tasks.len() + proof_tasks.len());
    tasks.extend(sensor_tasks);
    tasks.extend(proof_tasks);

    let mut counts = BTreeMap::new();
    for (task, _) in &tasks {
        *counts
            .entry(task.initial_packet_status.as_str())
            .or_insert(0usize) += 1;
    }

    let mut text = String::new();
    text.push_str(&format!(
        "- Ready for initial packet: `{}`\n",
        counts
            .get("ready_for_initial_packet")
            .copied()
            .unwrap_or_default()
    ));
    text.push_str(&format!(
        "- Pending initial packet: `{}`\n",
        counts
            .get("pending_initial_packet")
            .copied()
            .unwrap_or_default()
    ));
    text.push_str(&format!(
        "- Not initial packet: `{}`\n",
        counts
            .get("not_initial_packet")
            .copied()
            .unwrap_or_default()
    ));
    text.push_str("- Rule: pending work is unfinished, not missing evidence.\n");
    render_initial_work_queue_task_group(
        &mut text,
        "Ready Initial Packet Receipts",
        &tasks,
        "ready_for_initial_packet",
    );
    render_initial_work_queue_task_group(
        &mut text,
        "Pending Initial Packet Tasks",
        &tasks,
        "pending_initial_packet",
    );
    Ok(text)
}

fn render_initial_work_queue_task_group(
    text: &mut String,
    heading: &str,
    tasks: &[(WorkQueueTaskArtifact, String)],
    status: &str,
) {
    const MAX_QUEUE_ITEMS: usize = 8;
    text.push_str(&format!("\n### {heading}\n\n"));
    let matching = tasks
        .iter()
        .filter(|(task, _)| task.initial_packet_status == status)
        .collect::<Vec<_>>();
    if matching.is_empty() {
        text.push_str("- None.\n");
        return;
    }
    for (task, detail) in matching.iter().take(MAX_QUEUE_ITEMS) {
        text.push_str(&format!(
            "- `{}` (`{}`, `{}`) -> `{}`; consumers: `{}`; {}\n",
            task.id,
            task.packet_policy,
            task.gate_policy,
            task.receipt_path,
            task.consumers.join(", "),
            escape_md(detail)
        ));
    }
    let remaining = matching.len().saturating_sub(MAX_QUEUE_ITEMS);
    if remaining > 0 {
        text.push_str(&format!(
            "- `{remaining}` more task(s) are listed in `work_queue.json`.\n"
        ));
    }
}

fn write_shared_context_cache_artifacts(
    out: &Path,
    shared_context: &str,
    assignments: &[ModelAssignment],
    provider_preflights: &[ProviderPreflightReceipt],
    model_lanes: &[ModelLaneReceipt],
    follow_up_results: &[FollowUpResult],
    args: &RunArgs,
) -> Result<()> {
    let review_dir = out.join("review");
    fs::create_dir_all(&review_dir).with_context(|| format!("create {}", review_dir.display()))?;
    let shared_context_hash = sha256_hex(shared_context.as_bytes());
    fs::write(
        review_dir.join("shared_context_cache_block.md"),
        shared_context,
    )?;
    fs::write(
        review_dir.join("shared_context_hash.txt"),
        format!("{shared_context_hash}\n"),
    )?;

    let lanes = shared_context_cache_lanes(
        &shared_context_hash,
        assignments,
        model_lanes,
        follow_up_results,
        args,
    );
    let manifest = SharedContextCacheManifest {
        schema: CACHE_MANIFEST_SCHEMA,
        shared_context_hash: shared_context_hash.clone(),
        shared_context_bytes: shared_context.len(),
        cache_block_path: "review/shared_context_cache_block.md",
        hash_path: "review/shared_context_hash.txt",
        events_path: "review/cache_events.ndjson",
        explicit_cache_provider: "minimax",
        explicit_cache_endpoint: "anthropic-messages",
        cache_lifetime: "provider-ephemeral",
        lanes,
    };
    fs::write(
        review_dir.join("cache_manifest.json"),
        serde_json::to_vec_pretty(&manifest)?,
    )?;

    let mut events = Vec::new();
    events.push(SharedContextCacheEvent {
        schema: CACHE_EVENT_SCHEMA,
        kind: "shared_context_prepared".to_owned(),
        shared_context_hash: shared_context_hash.clone(),
        lane: None,
        provider: None,
        endpoint_kind: None,
        cache_mode: "artifact-prepared".to_owned(),
        cache_creation_input_tokens: None,
        cache_read_input_tokens: None,
    });
    for receipt in provider_preflights
        .iter()
        .filter(|receipt| model_call_attempted_status(&receipt.status))
    {
        events.push(SharedContextCacheEvent {
            schema: CACHE_EVENT_SCHEMA,
            kind: "provider_preflight_cache_usage".to_owned(),
            shared_context_hash: shared_context_hash.clone(),
            lane: Some("provider-preflight".to_owned()),
            provider: Some(receipt.provider.clone()),
            endpoint_kind: Some(receipt.endpoint_kind.clone()),
            cache_mode: model_cache_mode(&receipt.provider, &receipt.endpoint_kind).to_owned(),
            cache_creation_input_tokens: receipt.cache_usage.cache_creation_input_tokens,
            cache_read_input_tokens: receipt.cache_usage.cache_read_input_tokens,
        });
    }
    for receipt in model_lanes
        .iter()
        .filter(|receipt| model_call_attempted_status(&receipt.status))
    {
        events.push(SharedContextCacheEvent {
            schema: CACHE_EVENT_SCHEMA,
            kind: "model_lane_cache_usage".to_owned(),
            shared_context_hash: shared_context_hash.clone(),
            lane: Some(receipt.lane.clone()),
            provider: Some(receipt.provider.clone()),
            endpoint_kind: Some(receipt.endpoint_kind.clone()),
            cache_mode: model_cache_mode(&receipt.provider, &receipt.endpoint_kind).to_owned(),
            cache_creation_input_tokens: receipt.cache_usage.cache_creation_input_tokens,
            cache_read_input_tokens: receipt.cache_usage.cache_read_input_tokens,
        });
    }
    let follow_up_spec = direct_minimax_spec(args);
    for result in follow_up_results
        .iter()
        .filter(|result| model_call_attempted_status(&result.status))
    {
        events.push(SharedContextCacheEvent {
            schema: CACHE_EVENT_SCHEMA,
            kind: "follow_up_cache_usage".to_owned(),
            shared_context_hash: shared_context_hash.clone(),
            lane: Some(result.model_lane.clone()),
            provider: Some(follow_up_spec.provider.key().to_owned()),
            endpoint_kind: Some(follow_up_spec.endpoint_kind.key().to_owned()),
            cache_mode: model_cache_mode(
                follow_up_spec.provider.key(),
                follow_up_spec.endpoint_kind.key(),
            )
            .to_owned(),
            cache_creation_input_tokens: result.cache_usage.cache_creation_input_tokens,
            cache_read_input_tokens: result.cache_usage.cache_read_input_tokens,
        });
    }
    let mut ndjson = String::new();
    for event in events {
        ndjson.push_str(&serde_json::to_string(&event)?);
        ndjson.push('\n');
    }
    fs::write(review_dir.join("cache_events.ndjson"), ndjson)?;
    Ok(())
}

fn shared_context_cache_lanes(
    shared_context_hash: &str,
    assignments: &[ModelAssignment],
    model_lanes: &[ModelLaneReceipt],
    follow_up_results: &[FollowUpResult],
    args: &RunArgs,
) -> Vec<SharedContextCacheLane> {
    if model_lanes.is_empty() {
        return assignments
            .iter()
            .map(|assignment| {
                shared_context_cache_lane(
                    shared_context_hash,
                    &assignment.lane.id,
                    assignment.spec.provider.key(),
                    &assignment.spec.model,
                    assignment.spec.endpoint_kind.key(),
                )
            })
            .collect();
    }
    let mut lanes = model_lanes
        .iter()
        .map(|receipt| {
            shared_context_cache_lane(
                shared_context_hash,
                &receipt.lane,
                &receipt.provider,
                &receipt.model,
                &receipt.endpoint_kind,
            )
        })
        .collect::<Vec<_>>();
    let follow_up_spec = direct_minimax_spec(args);
    for result in follow_up_results
        .iter()
        .filter(|result| model_call_attempted_status(&result.status))
    {
        lanes.push(shared_context_cache_lane(
            shared_context_hash,
            &result.model_lane,
            follow_up_spec.provider.key(),
            &follow_up_spec.model,
            follow_up_spec.endpoint_kind.key(),
        ));
    }
    lanes
}

fn shared_context_cache_lane(
    shared_context_hash: &str,
    lane: &str,
    provider: &str,
    model: &str,
    endpoint_kind: &str,
) -> SharedContextCacheLane {
    SharedContextCacheLane {
        lane: lane.to_owned(),
        provider: provider.to_owned(),
        model: model.to_owned(),
        endpoint_kind: endpoint_kind.to_owned(),
        cache_mode: model_cache_mode(provider, endpoint_kind).to_owned(),
        shared_context_hash: shared_context_hash.to_owned(),
    }
}

fn model_cache_mode(provider: &str, endpoint_kind: &str) -> &'static str {
    if provider == ModelProvider::MiniMaxDirect.key()
        && endpoint_kind == ProviderEndpointKind::AnthropicMessages.key()
    {
        "explicit-anthropic-cache-control"
    } else {
        "not-supported"
    }
}

fn collect_pr_thread_context(root: &Path, args: &RunArgs) -> Result<PrThreadContext> {
    let mut context = PrThreadContext {
        schema: PR_THREAD_CONTEXT_SCHEMA.to_owned(),
        status: "absent".to_owned(),
        max_bytes: args.pr_thread_context_max_bytes,
        sources: Vec::new(),
        warnings: Vec::new(),
        pull_number: None,
        title: None,
        body: None,
        body_truncated: false,
        thread_context_path: None,
        thread_context: None,
        thread_context_truncated: false,
    };

    if let Some(event_path) = std::env::var_os("GITHUB_EVENT_PATH") {
        let event_path = PathBuf::from(event_path);
        context
            .sources
            .push(format!("github-event:{}", event_path.display()));
        match read_github_event_pr_context(&event_path, args.pr_thread_context_max_bytes) {
            Ok(event_context) => {
                context.pull_number = event_context.pull_number;
                context.title = event_context.title;
                context.body = event_context.body;
                context.body_truncated = event_context.body_truncated;
            }
            Err(err) => context
                .warnings
                .push(format!("github-event unavailable: {err}")),
        }
    }
    context.pull_number = args.github_pull_number.or(context.pull_number);

    let configured_thread_path = args.pr_thread_context.trim();
    if !configured_thread_path.is_empty() {
        let configured_path = PathBuf::from(configured_thread_path);
        let path = if configured_path.is_absolute() {
            configured_path
        } else {
            root.join(configured_path)
        };
        context
            .sources
            .push(format!("thread-context-file:{}", path.display()));
        context.thread_context_path = Some(path.display().to_string());
        match read_bounded_text_with_status(&path, args.pr_thread_context_max_bytes) {
            Ok(text) => {
                context.thread_context = Some(text.text);
                context.thread_context_truncated = text.truncated;
            }
            Err(err) => context
                .warnings
                .push(format!("thread-context-file unavailable: {err}")),
        }
    }

    match github_thread_api_request(args, context.pull_number) {
        None => {}
        Some(Err(err)) => context
            .warnings
            .push(format!("github-api thread context unavailable: {err}")),
        Some(Ok(request)) => {
            match read_github_pr_thread_context(root, &request, args.pr_thread_context_max_bytes) {
                Ok(api_context) => {
                    context.sources.extend(api_context.sources);
                    append_thread_context(
                        &mut context,
                        &api_context.thread_context,
                        args.pr_thread_context_max_bytes,
                    );
                }
                Err(err) => context
                    .warnings
                    .push(format!("github-api thread context unavailable: {err}")),
            }
        }
    }

    context.status =
        if context.title.is_some() || context.body.is_some() || context.thread_context.is_some() {
            "seeded".to_owned()
        } else if context.warnings.is_empty() {
            "absent".to_owned()
        } else {
            "unavailable".to_owned()
        };

    Ok(context)
}

struct GitHubThreadApiRequest<'a> {
    auth: &'a str,
    repo: &'a str,
    pull_number: u64,
    api_url: &'a str,
}

struct GitHubThreadApiContext {
    sources: Vec<String>,
    thread_context: String,
}

fn github_thread_api_request<'a>(
    args: &'a RunArgs,
    event_pull_number: Option<u64>,
) -> Option<Result<GitHubThreadApiRequest<'a>>> {
    let auth = args
        .pr_thread_auth
        .as_deref()
        .map(str::trim)
        .filter(|v| !v.is_empty())?;
    let Some(repo) = args
        .github_repo
        .as_deref()
        .map(str::trim)
        .filter(|v| !v.is_empty())
    else {
        return Some(Err(anyhow::anyhow!(
            "GitHub repository slug is unavailable"
        )));
    };
    if !is_valid_repo_slug(repo) {
        return Some(Err(anyhow::anyhow!(
            "GitHub repository slug is invalid: {repo}"
        )));
    }
    let Some(pull_number) = args.github_pull_number.or(event_pull_number) else {
        return Some(Err(anyhow::anyhow!("pull request number is unavailable")));
    };
    Some(Ok(GitHubThreadApiRequest {
        auth,
        repo,
        pull_number,
        api_url: args.github_api_url.trim_end_matches('/'),
    }))
}

fn read_github_pr_thread_context(
    root: &Path,
    request: &GitHubThreadApiRequest<'_>,
    max_bytes: usize,
) -> Result<GitHubThreadApiContext> {
    let endpoints = [
        (
            "issue-comments",
            format!(
                "{}/repos/{}/issues/{}/comments?per_page=30",
                request.api_url, request.repo, request.pull_number
            ),
        ),
        (
            "review-summaries",
            format!(
                "{}/repos/{}/pulls/{}/reviews?per_page=30",
                request.api_url, request.repo, request.pull_number
            ),
        ),
        (
            "review-comments",
            format!(
                "{}/repos/{}/pulls/{}/comments?per_page=50",
                request.api_url, request.repo, request.pull_number
            ),
        ),
    ];
    let mut sections = Vec::new();
    let mut sources = Vec::new();
    for (kind, url) in endpoints {
        let value = run_github_api_get(root, &url, request.auth)
            .with_context(|| format!("fetch GitHub PR thread {kind}"))?;
        sources.push(format!(
            "github-api:{}/{}/{}",
            request.repo, request.pull_number, kind
        ));
        sections.push(render_github_pr_thread_section(kind, &value, max_bytes));
    }

    let mut text = String::new();
    text.push_str("## GitHub PR Thread Snapshot\n\n");
    text.push_str(&format!(
        "Source: `{}` PR `#{}`. Bounded to lane context; full GitHub thread remains source of truth.\n\n",
        escape_md(request.repo),
        request.pull_number
    ));
    text.push_str(&sections.join("\n"));
    let bounded = bounded_string(&text, max_bytes);
    Ok(GitHubThreadApiContext {
        sources,
        thread_context: bounded.text,
    })
}

fn run_github_api_get(root: &Path, url: &str, auth: &str) -> Result<serde_json::Value> {
    let mut command = ProcessCommand::new("curl");
    command
        .arg("-sS")
        .arg("--fail-with-body")
        .arg("--max-time")
        .arg("30")
        .arg("-w")
        .arg("\nUB_REVIEW_HTTP_STATUS:%{http_code}\n")
        .arg("-K")
        .arg("-")
        .arg(url)
        .current_dir(root)
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped());
    let mut child = command.spawn().with_context(|| "spawn GitHub API curl")?;
    {
        let mut stdin = child
            .stdin
            .take()
            .ok_or_else(|| anyhow::anyhow!("curl stdin unavailable"))?;
        use std::io::Write as _;
        const AUTH_HEADER_NAME: &str = "Authorization";
        let auth_scheme = ["Bear", "er"].concat();
        for header in [
            "Accept: application/vnd.github+json",
            "X-GitHub-Api-Version: 2022-11-28",
            &format!("{AUTH_HEADER_NAME}: {auth_scheme} {auth}"),
        ] {
            writeln!(stdin, "header = \"{}\"", curl_config_quote(header))?;
        }
    }
    let output = child
        .wait_with_output()
        .with_context(|| "wait for GitHub API curl")?;
    let (stdout, http_status) = split_curl_http_status(output.stdout);
    if !output.status.success() {
        bail!(
            "GitHub API curl exited {:?} with http status {:?}: stderr: {}; stdout: {}",
            output.status.code(),
            http_status,
            String::from_utf8_lossy(&output.stderr),
            String::from_utf8_lossy(&stdout)
        );
    }
    serde_json::from_slice(&stdout).with_context(|| "parse GitHub API response")
}

fn render_github_pr_thread_section(
    kind: &str,
    value: &serde_json::Value,
    max_bytes: usize,
) -> String {
    let title = match kind {
        "issue-comments" => "Issue Comments",
        "review-summaries" => "Review Summaries",
        "review-comments" => "Review Comments",
        _ => "Thread Items",
    };
    let mut text = format!("### {title}\n\n");
    let Some(items) = value.as_array() else {
        text.push_str("- GitHub response was not an array.\n");
        return text;
    };
    if items.is_empty() {
        text.push_str("- None found.\n");
        return text;
    }
    for item in items {
        text.push_str(&render_github_pr_thread_item(kind, item, max_bytes));
    }
    text
}

fn render_github_pr_thread_item(kind: &str, item: &serde_json::Value, max_bytes: usize) -> String {
    let author = item
        .pointer("/user/login")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("unknown");
    let created_at = item
        .get("created_at")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("unknown-time");
    let state = item
        .get("state")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("");
    let path = item
        .get("path")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("");
    let line = item
        .get("line")
        .or_else(|| item.get("original_line"))
        .and_then(serde_json::Value::as_u64);
    let body = item
        .get("body")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("");
    let bounded_body = bounded_string(body.trim(), max_bytes.min(1200));
    let location = if !path.is_empty() {
        match line {
            Some(line) => format!(" `{}`:`{line}`", escape_md(path)),
            None => format!(" `{}`", escape_md(path)),
        }
    } else {
        String::new()
    };
    let state = if state.is_empty() {
        String::new()
    } else {
        format!(" `{}`", escape_md(state))
    };
    let item_kind = match kind {
        "issue-comments" => "issue-comment",
        "review-summaries" => "review",
        "review-comments" => "review-comment",
        _ => "thread-item",
    };
    let mut text = format!(
        "- `{}` `{}` by `{}`{}{}\n",
        item_kind,
        escape_md(created_at),
        escape_md(author),
        state,
        location
    );
    if !bounded_body.text.is_empty() {
        text.push_str("  ```text\n");
        text.push_str(&bounded_body.text);
        if !bounded_body.text.ends_with('\n') {
            text.push('\n');
        }
        text.push_str("  ```\n");
    }
    text
}

fn append_thread_context(context: &mut PrThreadContext, addition: &str, max_bytes: usize) {
    if addition.trim().is_empty() {
        return;
    }
    let mut merged = String::new();
    if let Some(existing) = context.thread_context.as_deref() {
        merged.push_str(existing);
        if !existing.ends_with('\n') {
            merged.push('\n');
        }
        merged.push('\n');
    }
    merged.push_str(addition);
    let bounded = bounded_string(&merged, max_bytes);
    context.thread_context = Some(bounded.text);
    context.thread_context_truncated |= bounded.truncated;
}

struct GitHubEventPrContext {
    pull_number: Option<u64>,
    title: Option<String>,
    body: Option<String>,
    body_truncated: bool,
}

fn read_github_event_pr_context(path: &Path, max_bytes: usize) -> Result<GitHubEventPrContext> {
    let text = fs::read_to_string(path).with_context(|| format!("read {}", path.display()))?;
    let value: serde_json::Value =
        serde_json::from_str(&text).with_context(|| format!("parse {}", path.display()))?;
    let Some(pull_request) = value.get("pull_request") else {
        return Ok(GitHubEventPrContext {
            pull_number: None,
            title: None,
            body: None,
            body_truncated: false,
        });
    };
    let body = pull_request
        .get("body")
        .and_then(serde_json::Value::as_str)
        .map(|body| bounded_string(body, max_bytes));
    Ok(GitHubEventPrContext {
        pull_number: pull_request
            .get("number")
            .and_then(serde_json::Value::as_u64),
        title: pull_request
            .get("title")
            .and_then(serde_json::Value::as_str)
            .map(str::to_owned),
        body: body.as_ref().map(|body| body.text.clone()),
        body_truncated: body.as_ref().is_some_and(|body| body.truncated),
    })
}

fn render_pr_thread_context(context: &PrThreadContext) -> String {
    let mut text = String::new();
    text.push_str(&format!("- Status: `{}`\n", context.status));
    if context.sources.is_empty() {
        text.push_str("- Sources: none\n");
    } else {
        text.push_str("- Sources:\n");
        for source in &context.sources {
            text.push_str(&format!("  - `{}`\n", escape_md(source)));
        }
    }
    if !context.warnings.is_empty() {
        text.push_str("- Warnings:\n");
        for warning in &context.warnings {
            text.push_str(&format!("  - {}\n", escape_md(warning)));
        }
    }
    if let Some(number) = context.pull_number {
        text.push_str(&format!("- Pull request: `#{number}`\n"));
    }
    if let Some(title) = context.title.as_deref() {
        text.push_str(&format!("- Title: {}\n", escape_md(title)));
    }
    if let Some(guidance) = pr_thread_reuse_guidance(context) {
        text.push('\n');
        text.push_str(guidance);
    }
    if let Some(body) = context.body.as_deref() {
        text.push_str("\n### PR Body\n\n```text\n");
        text.push_str(body);
        if !body.ends_with('\n') {
            text.push('\n');
        }
        text.push_str("```\n");
    }
    if let Some(thread_context) = context.thread_context.as_deref() {
        text.push_str("\n### Prior Review Thread\n\n```text\n");
        text.push_str(thread_context);
        if !thread_context.ends_with('\n') {
            text.push('\n');
        }
        text.push_str("```\n");
    }
    if context.status == "absent" {
        text.push_str("- No PR thread context was provided for this run.\n");
    }
    text
}

fn pr_thread_reuse_guidance(context: &PrThreadContext) -> Option<&'static str> {
    if context.status != "seeded" {
        return None;
    }
    Some(
        "### Seeded Thread Reuse Rules\n\n\
- Treat PR body claims, author replies, prior ub-review comments, resolved/dismissed discussion notes, and proof receipts in this context as lane evidence.\n\
- Before emitting a verification question or proof request, compare it with the seeded thread. If the same concern is already answered and the current diff does not reopen it, emit a `resolved-check` observation or `failed_objection` instead of a fresh candidate.\n\
- If the current diff reopens an answered concern, cite the changed file/line or proof receipt that makes the prior answer stale.\n",
    )
}

fn render_ledger_context(root: &Path, config: &Config, args: &RunArgs) -> Result<String> {
    let ledger = effective_ledger_path(config, args);
    let ledger = ledger.trim();
    if ledger.is_empty() {
        return Ok("- No UB ledger configured for this run.\n".to_owned());
    }
    let configured_path = PathBuf::from(ledger);
    let path = if configured_path.is_absolute() {
        configured_path
    } else {
        root.join(configured_path)
    };
    if !path.exists() {
        return Ok(format!(
            "- UB ledger configured but unavailable at `{}`.\n",
            path.display()
        ));
    }
    if path.is_file() {
        let text = read_bounded_text(&path, args.ledger_max_bytes)?;
        return Ok(format!(
            "Source: `{}`\n\n```text\n{}\n```\n",
            path.display(),
            text
        ));
    }
    if path.is_dir() {
        let mut entries = fs::read_dir(&path)?
            .filter_map(std::result::Result::ok)
            .filter(|entry| entry.path().is_file())
            .map(|entry| entry.path())
            .filter(|path| is_ledger_excerpt_candidate(path))
            .collect::<Vec<_>>();
        entries.sort();
        entries.truncate(8);
        if entries.is_empty() {
            return Ok(format!(
                "- UB ledger directory `{}` has no supported excerpt files.\n",
                path.display()
            ));
        }
        let mut text = format!("Source directory: `{}`\n\n", path.display());
        let per_entry_limit = args.ledger_max_bytes.saturating_div(entries.len().max(1));
        let per_entry_limit = per_entry_limit.max(1024);
        let mut remaining = args.ledger_max_bytes;
        for entry in entries {
            if remaining == 0 {
                text.push_str("[ledger byte budget exhausted]\n");
                break;
            }
            let limit = per_entry_limit.min(remaining);
            text.push_str(&format!("### `{}`\n\n```text\n", entry.display()));
            let excerpt = read_bounded_text(&entry, limit)?;
            remaining = remaining.saturating_sub(excerpt.len());
            text.push_str(&excerpt);
            text.push_str("\n```\n\n");
        }
        return Ok(text);
    }
    Ok(format!(
        "- UB ledger path `{}` is not a regular file or directory.\n",
        path.display()
    ))
}

fn effective_ledger_path(config: &Config, args: &RunArgs) -> String {
    let cli_path = args.ledger_path.trim();
    if cli_path.is_empty() {
        config.repo.ledger.clone()
    } else {
        cli_path.to_owned()
    }
}

struct BoundedText {
    text: String,
    truncated: bool,
}

fn read_bounded_text(path: &Path, max_bytes: usize) -> Result<String> {
    read_bounded_text_with_status(path, max_bytes).map(|bounded| bounded.text)
}

fn read_bounded_text_with_status(path: &Path, max_bytes: usize) -> Result<BoundedText> {
    let mut file = File::open(path).with_context(|| format!("open {}", path.display()))?;
    let mut buffer = vec![0; max_bytes.saturating_add(1)];
    use std::io::Read as _;
    let count = file
        .read(&mut buffer)
        .with_context(|| format!("read {}", path.display()))?;
    buffer.truncate(count.min(max_bytes));
    let mut text = String::from_utf8_lossy(&buffer).to_string();
    if count > max_bytes {
        text.push_str("\n[truncated]\n");
    }
    Ok(BoundedText {
        text,
        truncated: count > max_bytes,
    })
}

fn bounded_string(value: &str, max_bytes: usize) -> BoundedText {
    if value.len() <= max_bytes {
        return BoundedText {
            text: value.to_owned(),
            truncated: false,
        };
    }
    let mut end = 0;
    for (index, ch) in value.char_indices() {
        let next = index + ch.len_utf8();
        if next > max_bytes {
            break;
        }
        end = next;
    }
    let mut text = value[..end].to_owned();
    text.push_str("\n[truncated]\n");
    BoundedText {
        text,
        truncated: true,
    }
}

fn is_ledger_excerpt_candidate(path: &Path) -> bool {
    matches!(
        path.extension().and_then(|extension| extension.to_str()),
        Some("md" | "txt" | "toml" | "json")
    )
}

fn review_lanes_for_args(plan: &Plan, args: &RunArgs) -> Vec<LanePlan> {
    let mut lanes = match (args.lane_width, args.provider_policy) {
        (20, ModelProviderPolicy::OpencodeGoWide) if plan.diff_class == DiffClass::SourceUb => {
            opencode_go_wide_lanes()
        }
        (width, _) => review_lanes_for_width(width, plan),
    };
    merge_repo_lanes_into(&mut lanes, &plan.repo_lanes);
    lanes
}

fn selected_review_lanes_for_args(plan: &Plan, args: &RunArgs) -> Result<Vec<LanePlan>> {
    let include = parse_selector_set(&args.selectors.lanes, "--lanes")?;
    let exclude = parse_selector_set(&args.selectors.except_lanes, "--except-lanes")?;
    filter_lane_plans(review_lanes_for_args(plan, args), &include, &exclude)
}

fn review_lanes_for_width(width: usize, plan: &Plan) -> Vec<LanePlan> {
    match plan.diff_class {
        DiffClass::SourceUb => match width {
            6 => plan.lanes.clone(),
            10 => standard_minimax_lanes(),
            20 => deep_minimax_lanes(),
            _ => plan.lanes.clone(),
        },
        DiffClass::SourceGeneral => source_general_lanes(),
        DiffClass::TestsOnly => tests_only_lanes(),
        DiffClass::WorkflowTooling => workflow_tooling_lanes(),
        DiffClass::DocsOnly | DiffClass::ArtifactOnlySmoke => Vec::new(),
    }
}

